/**
 * Onboarding Flow Integration Test
 * 
 * This test validates the complete 5-step onboarding process:
 * 1. Role Selection (Frontend only)
 * 2. Account Creation - POST /auth/register
 * 3. Contact Update - PUT /users/:id
 * 4. Profile Update - PUT /users/:id
 * 5. Complete Onboarding - POST /users/:id/complete-onboarding
 */

const API_BASE = 'http://localhost:3000/api/v1';

async function testOnboardingFlow() {
    console.log('🚀 Starting Onboarding Flow Test\n');

    const testUser = {
        // Step 1: Role (selected in frontend)
        role: 'WORKER', // or 'CLIENT'

        // Step 2: Account
        name: 'Test Worker',
        email: `test.worker.${Date.now()}@example.com`,
        password: 'password123',

        // Step 3: Contact
        phone: '+919876543210',
        countryCode: '+91',
        address: '123 Test Street, Test City, 12345',

        // Step 4: Profile
        bio: 'Experienced worker with multiple skills',
        skills: 'JavaScript, React, Node.js, Python',
        // For employers: companyName instead of skills
    };

    let userId, token;

    try {
        // STEP 2: Create Account
        console.log('📝 Step 2: Creating account...');
        const registerResponse = await fetch(`${API_BASE}/auth/register`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                name: testUser.name,
                email: testUser.email,
                password: testUser.password,
                role: testUser.role
            })
        });

        if (!registerResponse.ok) {
            throw new Error(`Registration failed: ${await registerResponse.text()}`);
        }

        const registerData = await registerResponse.json();
        userId = registerData.user.id;
        token = registerData.token;

        console.log(`✅ Account created successfully`);
        console.log(`   User ID: ${userId}`);
        console.log(`   Onboarding Status: ${registerData.user.onboardingStatus}`);

        if (registerData.user.onboardingStatus !== 'PENDING') {
            throw new Error('Expected onboardingStatus to be PENDING after registration');
        }

        // STEP 3: Update Contact Information
        console.log('\n📞 Step 3: Updating contact information...');
        const contactResponse = await fetch(`${API_BASE}/users/${userId}`, {
            method: 'PUT',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${token}`
            },
            body: JSON.stringify({
                phone: testUser.phone,
                address: testUser.address
            })
        });

        if (!contactResponse.ok) {
            throw new Error(`Contact update failed: ${await contactResponse.text()}`);
        }

        const contactData = await contactResponse.json();
        console.log(`✅ Contact information updated`);
        console.log(`   Phone: ${contactData.phone}`);

        // STEP 4: Update Profile Information
        console.log('\n👤 Step 4: Updating profile...');
        const profileResponse = await fetch(`${API_BASE}/users/${userId}`, {
            method: 'PUT',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${token}`
            },
            body: JSON.stringify({
                bio: testUser.bio,
                // Note: skills would be added to Worker profile, not User directly
            })
        });

        if (!profileResponse.ok) {
            throw new Error(`Profile update failed: ${await profileResponse.text()}`);
        }

        const profileData = await profileResponse.json();
        console.log(`✅ Profile updated`);
        console.log(`   Bio: ${profileData.bio}`);

        // STEP 5: Complete Onboarding
        console.log('\n🎉 Step 5: Completing onboarding...');
        const completeResponse = await fetch(`${API_BASE}/users/${userId}/complete-onboarding`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${token}`
            }
        });

        if (!completeResponse.ok) {
            throw new Error(`Complete onboarding failed: ${await completeResponse.text()}`);
        }

        const completeData = await completeResponse.json();
        console.log(`✅ Onboarding completed successfully!`);
        console.log(`   Onboarding Status: ${completeData.onboardingStatus}`);

        if (completeData.onboardingStatus !== 'COMPLETED') {
            throw new Error('Expected onboardingStatus to be COMPLETED');
        }

        // Verify by fetching user again
        console.log('\n🔍 Verifying final user state...');
        const verifyResponse = await fetch(`${API_BASE}/users/${userId}`, {
            headers: { 'Authorization': `Bearer ${token}` }
        });

        const finalUser = await verifyResponse.json();
        console.log(`✅ User verification successful`);
        console.log(`   Name: ${finalUser.name}`);
        console.log(`   Email: ${finalUser.email}`);
        console.log(`   Phone: ${finalUser.phone}`);
        console.log(`   Role: ${finalUser.role}`);
        console.log(`   Onboarding Status: ${finalUser.onboardingStatus}`);
        console.log(`   Bio: ${finalUser.bio}`);

        console.log('\n✅ ✅ ✅ ALL TESTS PASSED ✅ ✅ ✅\n');
        return true;

    } catch (error) {
        console.error('\n❌ TEST FAILED:', error.message);
        console.error(error);
        return false;
    }
}

// Run the test
if (require.main === module) {
    console.log('Make sure the backend server is running on http://localhost:3000\n');
    testOnboardingFlow()
        .then(success => process.exit(success ? 0 : 1))
        .catch(err => {
            console.error(err);
            process.exit(1);
        });
}

module.exports = { testOnboardingFlow };

/**
 * Integration Test Script for GigGuard Platform
 * Tests all API endpoints and frontend-backend connections
 */

const BASE_URL = 'http://localhost:3000/api/v1';
const FRONTEND_URL = 'http://localhost:5173';

// Test results storage
const results = {
    passed: [],
    failed: [],
    summary: {}
};

// Helper function to make API calls
async function apiCall(method, endpoint, body = null, token = null) {
    const headers = {
        'Content-Type': 'application/json',
    };
    if (token) {
        headers['Authorization'] = `Bearer ${token}`;
    }

    const options = {
        method,
        headers,
    };

    if (body) {
        options.body = JSON.stringify(body);
    }

    try {
        const response = await fetch(`${BASE_URL}${endpoint}`, options);
        const data = await response.json();
        return { status: response.status, data, ok: response.ok };
    } catch (error) {
        return { status: 0, error: error.message, ok: false };
    }
}

// Test functions
async function testHealthCheck() {
    console.log('\n🔍 Testing Health Check...');
    try {
        const response = await fetch('http://localhost:3000/health');
        const data = await response.json();
        if (response.ok && data.status === 'ok') {
            results.passed.push('Health Check');
            console.log('✅ Health Check: PASSED');
            return true;
        } else {
            results.failed.push('Health Check');
            console.log('❌ Health Check: FAILED');
            return false;
        }
    } catch (error) {
        results.failed.push('Health Check');
        console.log('❌ Health Check: FAILED -', error.message);
        return false;
    }
}

async function testFrontendServer() {
    console.log('\n🔍 Testing Frontend Server...');
    try {
        const response = await fetch(FRONTEND_URL);
        if (response.ok) {
            results.passed.push('Frontend Server');
            console.log('✅ Frontend Server: RUNNING');
            return true;
        } else {
            results.failed.push('Frontend Server');
            console.log('❌ Frontend Server: NOT RESPONDING');
            return false;
        }
    } catch (error) {
        results.failed.push('Frontend Server');
