    if (result.ok && result.data.token && result.data.user) {
        results.passed.push('User Registration');
        console.log('✅ User Registration: PASSED');
        return { success: true, token: result.data.token, user: result.data.user };
    } else {
        results.failed.push('User Registration');
        console.log('❌ User Registration: FAILED -', result.data.error || result.error);
        return { success: false };
    }
}

