import * as anchor from "@coral-xyz/anchor";
import { Program } from "@coral-xyz/anchor";
import { Escrow } from "../target/types/escrow";
import { PublicKey, Keypair, SystemProgram, LAMPORTS_PER_SOL } from "@solana/web3.js";
import { expect } from "chai";

describe("escrow", () => {
  const provider = anchor.AnchorProvider.env();
  anchor.setProvider(provider);

  const program = anchor.workspace.Escrow as Program<Escrow>;
  const employer = (provider.wallet as anchor.Wallet).payer;
  const worker = Keypair.generate();

  // PDA Derivation
  const [gigAccount] = PublicKey.findProgramAddressSync(
    [Buffer.from("gig"), employer.publicKey.toBuffer(), worker.publicKey.toBuffer()],
    program.programId
  );

  const totalBudget = new anchor.BN(2 * LAMPORTS_PER_SOL); // 2 SOL budget

  before(async () => {
    // Airdrop SOL to worker for potential gas/rent fees
    const signature = await provider.connection.requestAirdrop(worker.publicKey, 1 * LAMPORTS_PER_SOL);
    await provider.connection.confirmTransaction(signature);
  });

  it("1. Creates a Gig and pays 50% Upfront", async () => {
    const workerInitialBalance = await provider.connection.getBalance(worker.publicKey);

    await program.methods
      .createGig(totalBudget)
      .accounts({
        gigAccount,
        employer: employer.publicKey,
        worker: worker.publicKey,
        systemProgram: SystemProgram.programId,
      } as any)
      .rpc();

    const gigData = await program.account.gigData.fetch(gigAccount);
    const workerFinalBalance = await provider.connection.getBalance(worker.publicKey);
    const pdaBalance = await provider.connection.getBalance(gigAccount);

    // Assertions
    expect(gigData.totalBudget.toString()).to.equal(totalBudget.toString());
    expect(gigData.amountInEscrow.toString()).to.equal(new anchor.BN(1 * LAMPORTS_PER_SOL).toString());

    // Check worker received roughly 1 SOL (minus tiny gas)
    const diff = workerFinalBalance - workerInitialBalance;
    expect(diff).to.be.closeTo(1 * LAMPORTS_PER_SOL, 10000); 

    // Check PDA holds the remaining 1 SOL
    expect(pdaBalance).to.be.at.least(1 * LAMPORTS_PER_SOL);
  });

  it("2. Logs a worker delay (Penalty Logic)", async () => {
    await program.methods
      .logDelay(true) // is_worker_fault = true
      .accounts({
        gigAccount,
        employer: employer.publicKey,
        worker: worker.publicKey,
      } as any)
      .rpc();

    const gigData = await program.account.gigData.fetch(gigAccount);
    expect(gigData.workerDelayPoints).to.equal(1);
  });

  it("3. Mutual Emergency Release (Requires 2 Signers)", async () => {
    const releaseAmount = new anchor.BN(0.2 * LAMPORTS_PER_SOL);

    await program.methods
      .emergencyRelease(releaseAmount)
      .accounts({
        gigAccount,
        employer: employer.publicKey,
        worker: worker.publicKey,
      } as any)
      .signers([employer, worker])
      .rpc();

    const gigData = await program.account.gigData.fetch(gigAccount);
    // Escrow should now have 0.8 SOL left
    expect(gigData.amountInEscrow.toNumber()).to.be.lessThan(1 * LAMPORTS_PER_SOL);
  });

  it("4. Blocks early release (15-day lock)", async () => {
    try {
      await program.methods
        .releasePayment()
        .accounts({
          gigAccount,
          employer: employer.publicKey,
          worker: worker.publicKey,
        } as any)
        .rpc();
      expect.fail("Should have failed due to lock period");
    } catch (err) {
      expect(err.message).to.contain("LockPeriodActive");
    }
  });
});

use anchor_lang::prelude::*;
use anchor_lang::solana_program::clock::Clock;

declare_id!("6Ncm64zUBrUkwbtn6eks8DTRWN5p5WjYpiSm7bJxhnrt"); // Replace with your actual Program ID after first build

#[program]
pub mod escrow {
    use super::*;

    /// 1. Create Gig & Pay 50% Upfront
    /// This locks the remaining 50% in a Program Derived Address (PDA)
    pub fn create_gig(ctx: Context<CreateGig>, total_budget: u64) -> Result<()> {
        let gig = &mut ctx.accounts.gig_account;
        let upfront_amount = total_budget / 2;
        let escrow_amount = total_budget - upfront_amount;

        gig.employer = ctx.accounts.employer.key();
        gig.worker = ctx.accounts.worker.key();
        gig.total_budget = total_budget;
        gig.amount_in_escrow = escrow_amount;
        gig.created_at = Clock::get()?.unix_timestamp;
        gig.status = GigStatus::Active;
        gig.worker_delay_points = 0;

        // CPI: Immediate 50% Transfer from Employer to Worker
        let cpi_context = CpiContext::new(
            ctx.accounts.system_program.to_account_info(),
            anchor_lang::system_program::Transfer {
                from: ctx.accounts.employer.to_account_info(),
                to: ctx.accounts.worker.to_account_info(),
            },
        );
        anchor_lang::system_program::transfer(cpi_context, upfront_amount)?;

        // CPI: Transfer remaining 50% to the Gig PDA (Vault)
        let cpi_escrow = CpiContext::new(
            ctx.accounts.system_program.to_account_info(),
            anchor_lang::system_program::Transfer {
                from: ctx.accounts.employer.to_account_info(),
                to: ctx.accounts.gig_account.to_account_info(),
            },
        );
        anchor_lang::system_program::transfer(cpi_escrow, escrow_amount)?;

        Ok(())
    }

    /// 2. Delay-Based Fair Payment Logic
    /// Employer can flag delays. Points reduce the final payout during release.
    pub fn log_delay(ctx: Context<ManageGig>, is_worker_fault: bool) -> Result<()> {
        let gig = &mut ctx.accounts.gig_account;
        require!(gig.status == GigStatus::Active, GigError::GigNotActive);

        if is_worker_fault {
            gig.worker_delay_points = gig.worker_delay_points.saturating_add(1);
        }
        Ok(())
    }

    /// 3. Emergency Partial Withdrawal
    /// Requires BOTH Employer and Worker to be signers (In-app agreement logged)
    pub fn emergency_release(ctx: Context<EmergencyWithdrawal>, amount: u64) -> Result<()> {
        let gig = &mut ctx.accounts.gig_account;
        require!(amount <= gig.amount_in_escrow, GigError::InsufficientFunds);

        **gig.to_account_info().try_borrow_mut_lamports()? -= amount;
        **ctx.accounts.worker.try_borrow_mut_lamports()? += amount;

        gig.amount_in_escrow -= amount;
        Ok(())
    }

    /// 4. Final Release (The 15-Day Lock)
    /// Calculates final payment minus delay penalties. Change goes back to Employer.
    pub fn release_payment(ctx: Context<ManageGig>) -> Result<()> {
        let gig = &mut ctx.accounts.gig_account;
        let now = Clock::get()?.unix_timestamp;

        // Hard 15-day lock (15 days * 24h * 60m * 60s = 1,296,000 seconds)
        require!(now >= gig.created_at + 1296000, GigError::LockPeriodActive);

        // Penalty Logic: Each delay point = 5% of total budget deducted from escrow
        let penalty_per_point = gig.total_budget / 20; 
        let total_penalty = (gig.worker_delay_points as u64) * penalty_per_point;

        let final_payout = gig.amount_in_escrow.saturating_sub(total_penalty);
        let refund_to_employer = gig.amount_in_escrow - final_payout;

        // Pay Worker
        **gig.to_account_info().try_borrow_mut_lamports()? -= final_payout;
        **ctx.accounts.worker.try_borrow_mut_lamports()? += final_payout;

        // Refund Penalty to Employer
        **gig.to_account_info().try_borrow_mut_lamports()? -= refund_to_employer;
        **ctx.accounts.employer.try_borrow_mut_lamports()? += refund_to_employer;

        gig.status = GigStatus::Completed;
        gig.amount_in_escrow = 0;

        Ok(())
    }
}

#[derive(Accounts)]
pub struct CreateGig<'info> {
    #[account(
        init, 
        payer = employer, 
        space = 8 + 32 + 32 + 8 + 8 + 8 + 1 + 1, 
        seeds = [b"gig", employer.key().as_ref(), worker.key().as_ref()], 
        bump
    )]
    pub gig_account: Account<'info, GigData>,
    #[account(mut)]
    pub employer: Signer<'info>,
    /// CHECK: Worker account receiving funds
    #[account(mut)]
    pub worker: AccountInfo<'info>,
    pub system_program: Program<'info, System>,
}

#[derive(Accounts)]
pub struct ManageGig<'info> {
    #[account(
        mut,
        seeds = [b"gig", employer.key().as_ref(), worker.key().as_ref()],
        bump,
        has_one = employer,
        has_one = worker,
    )]
    pub gig_account: Account<'info, GigData>,
    #[account(mut)]
    pub employer: Signer<'info>,
    /// CHECK: Recipient
    #[account(mut)]
    pub worker: AccountInfo<'info>,
}

#[derive(Accounts)]
pub struct EmergencyWithdrawal<'info> {
    #[account(
        mut,
        seeds = [b"gig", employer.key().as_ref(), worker.key().as_ref()],
        bump,
        has_one = employer,
        has_one = worker,
    )]
    pub gig_account: Account<'info, GigData>,
    #[account(mut)]
    pub employer: Signer<'info>, // Both must sign for emergency
    #[account(mut)]
    pub worker: Signer<'info>,   // Both must sign for emergency
}

#[account]
pub struct GigData {
    pub employer: Pubkey,
    pub worker: Pubkey,
    pub total_budget: u64,
    pub amount_in_escrow: u64,
    pub created_at: i64,
    pub status: GigStatus,
    pub worker_delay_points: u8,
}

#[derive(AnchorSerialize, AnchorDeserialize, Clone, PartialEq, Eq)]
pub enum GigStatus {
    Active,
    Completed,
}

#[error_code]
pub enum GigError {
    #[msg("The 15-day lock period is still active.")]
    LockPeriodActive,
    #[msg("Gig is not in active state.")]
    GigNotActive,
    #[msg("Escrow has insufficient funds.")]
    InsufficientFunds,
}

