const request = require('supertest');
const app = require('./src/app');

async function testBackend() {
    console.log('🧪 Testing Backend Functionalities...\n');

    // Test 1: Health Check
    console.log('1️⃣  Testing Health Endpoint...');
    try {
        const healthRes = await request(app).get('/health');
        console.log(`   ✅ Health check: ${healthRes.body.status}`);
    } catch (err) {
        console.log(`   ❌ Health check failed: ${err.message}`);
    }

    // Test 2: Auth Registration
    console.log('\n2️⃣  Testing Auth Registration...');
    try {
        const randomEmail = `test${Date.now()}@example.com`;
        const randomPhone = `+9199999${Math.floor(10000 + Math.random() * 90000)}`;
        const authRes = await request(app)
            .post('/api/v1/auth/register')
            .send({
                email: randomEmail,
                phone: randomPhone,
                password: 'password123',
                name: 'Test User',
                role: 'WORKER'
            });
        if (authRes.statusCode === 201) {
            console.log('   ✅ User registration successful');
            console.log(`   📧 Email: ${randomEmail}`);
        } else {
            console.log(`   ⚠️  Registration returned ${authRes.statusCode}: ${JSON.stringify(authRes.body)}`);
        }
    } catch (err) {
        console.log(`   ❌ Registration failed: ${err.message}`);
    }

    // Test 3: IVR Incoming Call
    console.log('\n3️⃣  Testing IVR Incoming Call...');
    try {
        const ivrRes = await request(app)
            .post('/api/v1/ivr/incoming')
            .send({});
        console.log(`   ✅ IVR endpoint responded with status ${ivrRes.statusCode}`);
    } catch (err) {
        console.log(`   ❌ IVR test failed: ${err.message}`);
    }

    // Test 4: Job Search
    console.log('\n4️⃣  Testing Job Search...');
    try {
        const searchRes = await request(app)
            .get('/api/v1/jobs/search?query=plumber');
        console.log(`   ✅ Job search responded with status ${searchRes.statusCode}`);
    } catch (err) {
        console.log(`   ❌ Job search failed: ${err.message}`);
    }

    // Test 5: SMS Notification
    console.log('\n5️⃣  Testing SMS Notification...');
    try {
        const notificationService = require('./src/services/notification.service');
        await notificationService.sendSMS('+917628919275', 'Test notification from GigGuard backend test suite!');
        console.log('   ✅ SMS notification sent successfully');
    } catch (err) {
        console.log(`   ❌ SMS notification failed: ${err.message}`);
    }

    console.log('\n✨ Backend functionality test complete!');
    process.exit(0);
}

testBackend();

require('dotenv').config();
const twilio = require('twilio');

const client = twilio(
    process.env.TWILIO_ACCOUNT_SID,
    process.env.TWILIO_AUTH_TOKEN
);

async function sendTestSMS() {
    try {
        console.log('📱 Sending SMS to +917628919275...');

        const message = await client.messages.create({
            body: 'Hello from GigGuard! This is a test SMS notification. Your account is ready.',
            from: process.env.TWILIO_PHONE_NUMBER,
            to: '+917628919275'
        });

        console.log('✅ SMS sent successfully!');
        console.log('Message SID:', message.sid);
        console.log('Status:', message.status);

    } catch (error) {
        console.error('❌ Failed to send SMS:', error.message);
        if (error.code) {
            console.error('Error Code:', error.code);
        }
    }
}

sendTestSMS();

