    createdAt: string;
    onboardingStatus?: 'PENDING' | 'COMPLETED';
    kycVerified?: boolean;
}

export interface Gig {
    id: string;
    title: string;
    description: string;
    budget: { min: number; max: number };
    type: 'fixed' | 'hourly';
    status: 'open' | 'closed' | 'in-progress' | 'completed';
    employerId: string;
    employerName: string;
    skills: string[];
