import React, { useEffect, useState } from 'react';
import { View, ActivityIndicator, StyleSheet, Text, Platform } from 'react-native';
import Constants from 'expo-constants';
import { setApiBaseUrl } from './src/services/api';
import { SafeAreaProvider } from 'react-native-safe-area-context';
import { NavigationContainer } from '@react-navigation/native';
import RootNavigator from './src/navigation/RootNavigator';
import { useAppStore } from './src/store/appStore';
import { logger } from './src/utils/logger';

export default function App() {
    const { loadUser, isLoading } = useAppStore();
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        // Configure API base URL at runtime for development devices/emulators
        try {
            const expoExtra = (Constants as any)?.expoConfig?.extra;
            const override = expoExtra?.API_BASE_URL || process.env?.API_BASE_URL;
            if (override) {
                setApiBaseUrl(override);
            } else if (__DEV__) {
                // try to derive host from Expo manifest (new) or legacy manifest.debuggerHost
                const hostUri = (Constants as any)?.expoConfig?.hostUri || (Constants as any)?.manifest?.debuggerHost || '';
                let host = 'localhost';
                if (typeof hostUri === 'string' && hostUri.includes(':')) host = hostUri.split(':')[0];
                if (Platform.OS === 'android' && host === 'localhost') host = '10.0.2.2';
                setApiBaseUrl(`http://${host}:3000/api/v1`);
            }
        } catch (e) {
            // ignore
        }

        logger.info('App mounted, loading user...');
        loadUser().catch(e => {
            logger.error('App load error:', e);
            setError(e.message);
        });
    }, []);

    logger.debug('App render - isLoading:', isLoading, 'error:', error);

    if (error) {
        return (
            <View style={styles.loading}>
                <Text style={styles.errorText}>Error: {error}</Text>
            </View>
        );
    }

    if (isLoading) {
        return (
            <View style={styles.loading}>
                <ActivityIndicator size="large" color="#6366F1" />
            </View>
        );
    }

    return (
        <SafeAreaProvider>
            <NavigationContainer>
                <RootNavigator />
            </NavigationContainer>
        </SafeAreaProvider>
    );
}

const styles = StyleSheet.create({
    loading: {
        flex: 1,
        justifyContent: 'center',
        alignItems: 'center',
        backgroundColor: '#1a1a1a',
    },
    errorText: {
        color: '#EF4444',
        fontSize: 16,
        padding: 20,
        textAlign: 'center',
    },
});

import { registerRootComponent } from 'expo';
import App from './App';

registerRootComponent(App);

