import AsyncStorage from '@react-native-async-storage/async-storage';
import Constants from 'expo-constants';
import { Platform } from 'react-native';
import { logger } from '../utils/logger';

// Resolve API base URL for development on physical devices: use the bundler host IP instead of localhost
function getDevHost(): string {
    try {
        // Classic manifest exposes debuggerHost like "192.168.1.5:8081"
        const debuggerHost = (Constants?.manifest && (Constants.manifest as any).debuggerHost)
            || (Constants?.expoConfig && (Constants.expoConfig as any).hostUri)
            || (Constants as any).manifest2?.debuggerHost
            || '';
        if (typeof debuggerHost === 'string' && debuggerHost.includes(':')) {
            return debuggerHost.split(':')[0];
        }
    } catch (e) {
        // ignore
    }
    // Android emulators (older) must use 10.0.2.2 to reach host machine
    if (Platform.OS === 'android') return '10.0.2.2';
    return 'localhost';
}

// Allow overriding via Expo config (useful for tunnels/ngrok):
const EXPO_OVERRIDE = (Constants?.expoConfig?.extra && (Constants.expoConfig as any).extra?.API_BASE_URL) || (process.env?.API_BASE_URL as string | undefined);

// Detect a sensible default for API base URL. Priority:
// 1. Expo override via app config / env
// 2. In dev: host derived from debugger manifest (physical device) or emulator fallback
// 3. Production: configured production URL
const DEV_HOST = getDevHost();
// allow runtime override for debugging
let API_BASE_URL = EXPO_OVERRIDE || (__DEV__ ? `http://${DEV_HOST}:3000/api/v1` : 'https://your-production-api.com/api/v1');

export function setApiBaseUrl(url: string) {
    API_BASE_URL = url;
}

export function getApiBaseUrl() {
    return API_BASE_URL;
}

if (__DEV__) {
    // Helpful debug log so you can see what host the app is trying to reach
    // This will appear in Metro/Expo logs when the app starts
    logger.debug('[api] Using API_BASE_URL:', API_BASE_URL);
}

// Get stored JWT token
async function getToken(): Promise<string | null> {
    try {
        return await AsyncStorage.getItem('jwt_token');
    } catch (error) {
        console.error('Failed to get token:', error);
        return null;
    }
}

// Store JWT token
export async function storeToken(token: string): Promise<void> {
    try {
        await AsyncStorage.setItem('jwt_token', token);
    } catch (error) {
        console.error('Failed to store token:', error);
    }
}

// Clear JWT token
export async function clearToken(): Promise<void> {
    try {
        await AsyncStorage.removeItem('jwt_token');
    } catch (error) {
        console.error('Failed to clear token:', error);
    }
}

// Generic API request handler
async function apiRequest<T>(
    endpoint: string,
    options: RequestInit = {}
): Promise<T> {
    const token = await getToken();
    let response: Response;
    // Add an AbortController so requests have a timeout
    const controller = new AbortController();
    const timeout = (options as any)?.timeout ?? 15000; // 15s default
    const timeoutId = setTimeout(() => controller.abort(), timeout);
    try {
        response = await fetch(`${API_BASE_URL}${endpoint}`, {
            ...options,
            signal: controller.signal,
            headers: {
                'Content-Type': 'application/json',
                ...(token && { Authorization: `Bearer ${token}` }),
                ...options.headers,
            },
        });
    } catch (err: any) {
        // Network or CORS error (e.g., device cannot reach host). Provide actionable message.
        // eslint-disable-next-line no-console
        console.error('[api] Network request failed:', err?.message || err);
        // Provide hints for common issues
        const hint = Platform.OS === 'android' ? 'If running on Android emulator try http://10.0.2.2:3000' : 'Ensure Metro/Backend running and device can reach host';
        clearTimeout(timeoutId);
        // On AbortError, give clearer message
        if (err?.name === 'AbortError') {
            throw new Error(`Request timed out after ${timeout}ms (url: ${API_BASE_URL}${endpoint}). Hint: ${hint}`);
        }
        throw new Error(`Network request failed: ${err?.message || 'unknown error'} (url: ${API_BASE_URL}${endpoint}). Hint: ${hint}`);
    }
    clearTimeout(timeoutId);

    if (!response.ok) {
        // If unauthorized, clear stored token so app can redirect to login
        if (response.status === 401) {
            try {
                await clearToken();
            } catch (e) {
                // ignore
            }
            // Trigger app-level logout so UI updates (use zustand store getter)
            try {
                // Importing dynamically to avoid circular import issues in module load
                // eslint-disable-next-line @typescript-eslint/no-var-requires
                const { useAppStore } = require('../store/appStore');
                const logout = useAppStore.getState().logout;
                if (logout) {
                    logout();
                }
            } catch (e) {
                // ignore
            }
            throw new Error('Unauthorized. Please log in again.');
        }
        // Try to parse JSON error body for better message
        let body: any = null;
        try {
            body = await response.json();
        } catch (e) {
            try {
                body = await response.text();
            } catch (e2) {
                body = response.statusText;
            }
        }
        const message = body && body.error ? body.error : (body && body.message) ? body.message : JSON.stringify(body);
        throw new Error(`API Error: ${response.status} ${message}`);
    }

    // Return parsed JSON (some endpoints may return empty body)
    try {
        return await response.json();
    } catch (e) {
        return {} as T;
    }
}

// Jobs API (backend uses 'jobs' not 'gigs')
export const gigsApi = {
    search: async (query?: string) => {
        const queryString = query ? `?q=${encodeURIComponent(query)}` : '';
        return apiRequest(`/jobs/search${queryString}`);
    },

    getAll: async () => {
        return apiRequest('/jobs');
    },

    getById: async (id: string) => {
        return apiRequest(`/jobs/${id}`);
    },

    create: async (data: any) => {
        return apiRequest('/jobs', {
            method: 'POST',
            body: JSON.stringify(data),
        });
    },
};

