        // Use contracts as chats since there is no dedicated chat endpoint
        try {
            const contracts = await contractsApi.getAll();
            return (contracts as any[]).map(c => ({
                id: c.id,
                participantIds: [c.workerId || 'worker', c.clientId || c.employerId || 'client'],
                participantNames: [c.workerName || 'Worker', c.employerName || 'Client'],
                lastMessage: `Contract: ${c.gigTitle}`,
                lastMessageTime: c.updatedAt || c.startDate || new Date().toISOString(),
                unreadCount: 0,
                contractId: c.id
            }));
        } catch (error) {
            console.error('Failed to fetch chats from contracts:', error);
            return [];
        }
    },

    getMessages: async (chatId: string) => {
        // Try to fetch messages from contract endpoint
        return apiRequest(`/contracts/${chatId}/messages`);
    },

    sendMessage: async (chatId: string, content: string, attachments?: any[]) => {
        return apiRequest(`/contracts/${chatId}/messages`, {
            method: 'POST',
            body: JSON.stringify({ content, attachments }),
        });
    },

    createDispute: async (contractId: string, reason: string) => {
        return apiRequest(`/contracts/${contractId}/disputes`, {
            method: 'POST',
            body: JSON.stringify({ reason }),
        });
    },
};

