interface StatusPillProps {
    status: 'open' | 'in-progress' | 'completed' | 'cancelled' | 'pending' | 'active' | 'closed';
    size?: 'small' | 'medium';
}

const statusConfig = {
    open: { color: theme.colors.status.success, label: 'Open' },
    pending: { color: theme.colors.status.warning, label: 'Pending' },
    'in-progress': { color: theme.colors.primary[500], label: 'In Progress' },
    active: { color: theme.colors.primary[500], label: 'Active' },
    completed: { color: theme.colors.status.success, label: 'Completed' },
    closed: { color: theme.colors.textSecondary, label: 'Closed' },
    cancelled: { color: theme.colors.status.error, label: 'Cancelled' },
};

export default function StatusPill({ status, size = 'medium' }: StatusPillProps) {
    const config = statusConfig[status] || statusConfig.open;
    const isSmall = size === 'small';

    return (
        <View style={[styles.pill, { backgroundColor: config.color + '20' }]}>
            <View style={[styles.dot, { backgroundColor: config.color }]} />
            <Text style={[styles.text, { color: config.color }, isSmall && styles.textSmall]}>
                {config.label}
            </Text>
        </View>
    );
}

