import { getTrustScoreLevel } from '@hackapp/shared';

interface TrustBadgeProps {
    score: number;
    size?: 'small' | 'medium' | 'large';
    showLabel?: boolean;
}

export default function TrustBadge({ score, size = 'medium', showLabel = true }: TrustBadgeProps) {
    const level = getTrustScoreLevel(score);

    const sizeMap = {
        small: { outer: 50, inner: 42, fontSize: theme.fontSize.sm },
        medium: { outer: 80, inner: 68, fontSize: theme.fontSize.xl },
        large: { outer: 120, inner: 104, fontSize: theme.fontSize.xxxl },
    };

    const colorMap = {
        low: theme.colors.status.error,
        medium: theme.colors.status.warning,
        high: theme.colors.primary[500],
        excellent: theme.colors.status.success,
    };

    const dimensions = sizeMap[size];
    const color = colorMap[level];

    return (
        <View style={styles.container}>
            <View
                style={[
                    styles.badge,
                    {
                        width: dimensions.outer,
                        height: dimensions.outer,
                        borderRadius: dimensions.outer / 2,
                        borderColor: color,
                    },
                ]}
            >
                <View
                    style={[
                        styles.inner,
                        {
                            width: dimensions.inner,
                            height: dimensions.inner,
                            borderRadius: dimensions.inner / 2,
                            backgroundColor: color + '20',
                        },
                    ]}
                >
                    <Text style={[styles.score, { fontSize: dimensions.fontSize, color }]}>
                        {score}
                    </Text>
                </View>
            </View>
            {showLabel && (
                <Text style={[styles.label, { color }]}>
                    {level.charAt(0).toUpperCase() + level.slice(1)}
                </Text>
            )}
        </View>
    );
}

