import { create } from 'zustand';
import AsyncStorage from '@react-native-async-storage/async-storage';
import type { User } from '@hackapp/shared';
import { hasCompletedOnboarding } from '@hackapp/shared';
import { storeToken, clearToken } from '../services/api';
import { logger } from '../utils/logger';

interface AppState {
    user: User | null;
    token: string | null;
    isAuthenticated: boolean;
    isOnboarded: boolean;
    isLoading: boolean;
    setUser: (user: User | null, token?: string) => void;
    logout: () => void;
    loadUser: () => Promise<void>;
}

export const useAppStore = create<AppState>((set) => ({
    user: null,
    token: null,
    isAuthenticated: false,
    isOnboarded: false,
    isLoading: true,

    setUser: async (user, token) => {
        set({
            user,
            token: token || null,
            isAuthenticated: user !== null,
            isOnboarded: user ? hasCompletedOnboarding(user) : false,
            isLoading: false,
        });
        if (user) {
            await AsyncStorage.setItem('user', JSON.stringify(user));
        }
        if (token) {
            await storeToken(token);
        }
    },

    logout: async () => {
        set({ user: null, token: null, isAuthenticated: false, isOnboarded: false });
        await AsyncStorage.removeItem('user');
        await clearToken();
    },

    loadUser: async () => {
        logger.debug('[Store] loadUser started');
        try {
            const savedUser = await AsyncStorage.getItem('user');
            logger.debug('[Store] savedUser:', savedUser);
            if (savedUser) {
                const user = JSON.parse(savedUser);
                logger.debug('[Store] parsed user:', user);
                set({
                    user,
                    isAuthenticated: true,
                    isOnboarded: hasCompletedOnboarding(user),
                });
            }
        } catch (error) {
            logger.error('[Store] Failed to load user:', error);
        } finally {
            logger.debug('[Store] loadUser finished, setting isLoading to false');
            set({ isLoading: false });
        }
    },
}));

const isDev = typeof __DEV__ !== 'undefined' && __DEV__;

export const logger = {
    debug: (...args: any[]) => {
        if (isDev) {
            // eslint-disable-next-line no-console
            console.debug('[DEBUG]', ...args);
        }
    },
    info: (...args: any[]) => {
        if (isDev) {
            // eslint-disable-next-line no-console
            console.info('[INFO]', ...args);
        }
    },
    warn: (...args: any[]) => {
        // eslint-disable-next-line no-console
        console.warn('[WARN]', ...args);
    },
    error: (...args: any[]) => {
        // eslint-disable-next-line no-console
        console.error('[ERROR]', ...args);
    },
};

export default logger;

import React, { useState, useEffect } from 'react';
import {
    View,
    Text,
    FlatList,
    StyleSheet,
    SafeAreaView,
    KeyboardAvoidingView,
    Platform,
    ActivityIndicator,
} from 'react-native';
import { StatusBar } from 'expo-status-bar';
import { Ionicons } from '@expo/vector-icons';
import { useAppStore } from '../../store/appStore';
import { ChatListItem, ChatHeader, MessageBubble, MessageInput } from './components';
import type { Chat, Message } from '@hackapp/shared';
import { messagesApi } from '../../services/api';
import { logger } from '../../utils/logger';

// Messages are now fetched from the backend API. Mock/demo data removed per migration.
// UI will show a placeholder when there are no chats/messages.

export default function MessagesScreen({ navigation }: any) {
    const { user } = useAppStore();
    const [selectedChat, setSelectedChat] = useState<Chat | null>(null);
    const [messages, setMessages] = useState<Message[]>([]);
    const [chats, setChats] = useState<Chat[]>([]);
    const [isChatsLoading, setIsChatsLoading] = useState<boolean>(false);
    const [isMessagesLoading, setIsMessagesLoading] = useState<boolean>(false);

    useEffect(() => {
        loadChats();
    }, [user?.id]);

    const loadChats = async () => {
        if (!user?.id) return;
        setIsChatsLoading(true);
        try {
            const res = await messagesApi.getChats(user.id);
            setChats((res as Chat[]) || []);
        } catch (err) {
            logger.error('Failed to load chats:', err);
            setChats([]);
        } finally {
            setIsChatsLoading(false);
        }
    };

    const openChat = async (chat: Chat) => {
        setSelectedChat(chat);
        setIsMessagesLoading(true);
        try {
            const msgs = await messagesApi.getMessages(chat.id);
            setMessages((msgs as Message[]) || []);
        } catch (err) {
            logger.error('Failed to load messages for chat', chat.id, err);
            setMessages([]);
        } finally {
            setIsMessagesLoading(false);
        }
    };

    const handleSendMessage = async (content: string) => {
        if (!selectedChat || !user) return;

        const newMessage: Message = {
            id: Date.now().toString(),
            chatId: selectedChat.id,
            senderId: user.id,
            senderName: user.name,
            content,
            createdAt: new Date().toISOString(),
        };

        // Optimistic UI update
        setMessages(prev => [...prev, newMessage]);
        setChats(prev => prev.map(chat =>
            chat.id === selectedChat.id
                ? { ...chat, lastMessage: content, lastMessageTime: newMessage.createdAt, unreadCount: 0 }
                : chat
        ));

        try {
            await messagesApi.sendMessage(selectedChat.id, content);
        } catch (err) {
            logger.error('Failed to send message:', err);
            // Optionally show an error or mark message as failed
        }
    };

    const renderChatListItem = ({ item }: { item: Chat }) => (
        <ChatListItem
            chat={item}
            onPress={() => openChat(item)}
        />
    );

    const renderMessage = ({ item }: { item: Message }) => (
        <MessageBubble
            message={item}
            isOwnMessage={item.senderId === user?.id}
        />
    );

    if (selectedChat) {
        const chatMessages = messages.filter(m => m.chatId === selectedChat.id);

        return (
            <SafeAreaView style={styles.container}>
                <StatusBar style="dark" />
                <KeyboardAvoidingView 
                    style={styles.chatContainer}
                    behavior={Platform.OS === 'ios' ? 'padding' : undefined}
                    keyboardVerticalOffset={Platform.OS === 'ios' ? 0 : 0}
                >
                    <ChatHeader
                        title={selectedChat.participantNames[0]}
                        subtitle="Active now"
                        onBack={() => setSelectedChat(null)}
                        onCall={() => logger.info('Call')}
                        onVideoCall={() => logger.info('Video call')}
                    />

                    {isMessagesLoading ? (
                        <View style={styles.loadingContainer}>
                            <ActivityIndicator size="large" color="#6366F1" />
                        </View>
                    ) : (
                        <FlatList
                            data={chatMessages}
                            renderItem={renderMessage}
                            keyExtractor={item => item.id}
                            contentContainerStyle={styles.messagesList}
                            showsVerticalScrollIndicator={false}
                            inverted={false}
                        />
                    )}

                    <MessageInput onSend={handleSendMessage} />
                </KeyboardAvoidingView>
            </SafeAreaView>
        );
    }

    return (
        <SafeAreaView style={styles.container}>
            <StatusBar style="dark" />

            <View style={styles.header}>
                <View>
                    <Text style={styles.headerTitle}>Messages</Text>
                    <Text style={styles.headerSubtitle}>
                        {chats.filter(c => c.unreadCount > 0).length} unread
                    </Text>
                </View>
            </View>

            {/* Demo Data Banner */}
            {isChatsLoading ? (
                <View style={styles.loadingContainer}>
                    <ActivityIndicator size="large" color="#6366F1" />
                </View>
            ) : chats.length === 0 ? (
                <View style={styles.demoBanner}>
                    <Ionicons name="information-circle-outline" size={16} color="#F59E0B" />
                    <Text style={styles.demoText}>
                        No messages yet — start a conversation!
                    </Text>
                </View>
            ) : null}

            <FlatList
                data={chats}
                renderItem={renderChatListItem}
                keyExtractor={item => item.id}
                contentContainerStyle={styles.listContent}
                showsVerticalScrollIndicator={false}
            />
        </SafeAreaView>
    );
}

