export default function WelcomeScreen() {
    const navigation = useNavigation();
    const [currentIndex, setCurrentIndex] = useState(0);
    const flatListRef = useRef<FlatList>(null);

    const handleScroll = (event: NativeSyntheticEvent<NativeScrollEvent>) => {
        const offsetX = event.nativeEvent.contentOffset.x;
        const index = Math.round(offsetX / width);
        setCurrentIndex(index);
    };

    const handleNext = () => {
        if (currentIndex < steps.length - 1) {
            flatListRef.current?.scrollToIndex({
                index: currentIndex + 1,
                animated: true,
            });
        } else {
            handleComplete();
        }
    };

    const handleComplete = () => {
        navigation.navigate('Auth' as never);
    };

    const handleSkip = () => {
        navigation.navigate('Auth' as never);
    };

    const renderItem = ({ item }: { item: OnboardingStep }) => (
        <View style={styles.slide}>
            <LinearGradient colors={item.gradientColors} style={styles.gradientTop}>
                {/* Brand Header */}
                <View style={styles.brandHeader}>
                    <Text style={styles.brandText}>
                        MIDDLE<Text style={styles.brandTextLight}>MAN</Text>
                    </Text>
                </View>

                {/* Icon Container */}
                <View style={styles.iconSection}>
                    <View style={styles.iconBox}>
                        <Ionicons name={item.iconName} size={48} color="#fff" />
                    </View>
                    <View style={styles.badge}>
                        <Text style={styles.badgeText}>{item.badgeText}</Text>
                    </View>
                </View>

                {/* Background Logo */}
                <View style={styles.bgLogo}>
                    <Text style={styles.bgLogoText}>MM</Text>
                </View>
            </LinearGradient>

            {/* Content Card */}
            <View style={styles.contentCard}>
                <View style={styles.content}>
                    <Text style={styles.subtitle}>{item.subtitle}</Text>
                    <Text style={styles.title}>{item.title}</Text>
                    <Text style={styles.description}>{item.description}</Text>
                </View>
            </View>
        </View>
    );

    return (
        <View style={styles.container}>
            {/* Skip Button */}
            <TouchableOpacity style={styles.skipButton} onPress={handleSkip}>
                <Text style={styles.skipText}>Skip</Text>
            </TouchableOpacity>

            {/* Slides */}
            <FlatList
                ref={flatListRef}
                data={steps}
                renderItem={renderItem}
                horizontal
                pagingEnabled
                showsHorizontalScrollIndicator={false}
                onScroll={handleScroll}
                scrollEventThrottle={16}
                keyExtractor={(item) => item.id}
            />

            {/* Bottom Navigation */}
            <View style={styles.bottomContainer}>
                {/* Pagination Dots */}
                <View style={styles.pagination}>
                    {steps.map((_, index) => (
                        <View
                            key={index}
                            style={[
                                styles.dot,
                                index === currentIndex && styles.activeDot,
                            ]}
                        />
                    ))}
                </View>

                {/* Buttons */}
                <View style={styles.buttonRow}>
                    {currentIndex > 0 && (
                        <TouchableOpacity
                            style={styles.backButton}
                            onPress={() =>
                                flatListRef.current?.scrollToIndex({
                                    index: currentIndex - 1,
                                    animated: true,
                                })
                            }
                        >
                            <Ionicons name="chevron-back" size={24} color="#64748B" />
                        </TouchableOpacity>
                    )}
                    <TouchableOpacity
                        style={[styles.nextButton, currentIndex === 0 && styles.nextButtonFull]}
                        onPress={handleNext}
                        activeOpacity={0.9}
                    >
                        <Text style={styles.nextButtonText}>
                            {currentIndex === steps.length - 1 ? 'GET STARTED' : 'CONTINUE'}
                        </Text>
                        <Ionicons name="arrow-forward" size={20} color="#fff" />
                    </TouchableOpacity>
                </View>
            </View>
        </View>
    );
}

