export default function ContactDetailsScreen({ navigation, route }: any) {
    const { user, setUser } = useAppStore();
    const { role, name, email } = route.params;
    const [phone, setPhone] = useState(user?.phone || '');
    const [location, setLocation] = useState(user?.location || '');

    const handleContinue = () => {
        if (user) {
            setUser({ ...user, phone, location });
        }
        navigation.navigate('ProfileSetup', { role, name, email, phone, location });
    };

    return (
        <ScrollView style={styles.container} contentContainerStyle={styles.content}>
            <TouchableOpacity
                style={styles.backButton}
                onPress={() => navigation.goBack()}
            >
                <Text style={styles.backText}>← Back</Text>
            </TouchableOpacity>

            <Text style={styles.title}>Contact Details</Text>
            <Text style={styles.subtitle}>How can clients reach you?</Text>

            <View style={styles.form}>
                <Text style={styles.label}>Phone Number</Text>
                <TextInput
                    style={styles.input}
                    value={phone}
                    onChangeText={setPhone}
                    placeholder="+1 234 567 8900"
                    placeholderTextColor="#6B7280"
                    keyboardType="phone-pad"
                />

                <Text style={styles.label}>Location</Text>
                <TextInput
                    style={styles.input}
                    value={location}
                    onChangeText={setLocation}
                    placeholder="New York, USA"
                    placeholderTextColor="#6B7280"
                />
            </View>

            <TouchableOpacity
                style={[styles.button, (!phone || !location) && styles.buttonDisabled]}
                onPress={handleContinue}
                disabled={!phone || !location}
            >
                <Text style={styles.buttonText}>Continue</Text>
            </TouchableOpacity>
        </ScrollView>
    );
}

