import React, { useState } from 'react';
import { View, Text, StyleSheet, TextInput, TouchableOpacity, Alert, ScrollView } from 'react-native';
import { useNavigation } from '@react-navigation/native';

export default function PostGigScreen() {
    const [title, setTitle] = useState('');
    const [description, setDescription] = useState('');
    const [budget, setBudget] = useState('');
    const [skills, setSkills] = useState('');
    const [isSubmitting, setIsSubmitting] = useState(false);

    const nav = useNavigation();

    const handleSubmit = async () => {
        if (!title || !description) {
            Alert.alert('Validation', 'Please provide title and description');
            return;
        }
        setIsSubmitting(true);
        try {
            const body = {
                title,
                description,
                budget: Number(budget) || 0,
                skills: skills.split(',').map(s => s.trim()).filter(Boolean),
            };
            // eslint-disable-next-line @typescript-eslint/no-var-requires
            const { gigsApi } = require('../../services/api');
            await gigsApi.create(body);
            Alert.alert('Success', 'Gig posted');
            // Navigate back to list
            try {
                // @ts-ignore
                nav.goBack();
            } catch (e) {
                // ignore
            }
        } catch (err: any) {
            console.error('Post gig failed', err);
            Alert.alert('Error', err.message || 'Failed to post gig');
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <ScrollView contentContainerStyle={styles.container}>
            <Text style={styles.title}>Post a Gig</Text>

            <TextInput
                style={styles.input}
                placeholder="Title"
                value={title}
                onChangeText={setTitle}
            />

            <TextInput
                style={[styles.input, { height: 120 }]}
                placeholder="Description"
                value={description}
                onChangeText={setDescription}
                multiline
            />

            <TextInput
                style={styles.input}
                placeholder="Budget"
                value={budget}
                onChangeText={setBudget}
                keyboardType="numeric"
            />

            <TextInput
                style={styles.input}
                placeholder="Skills (comma separated)"
                value={skills}
                onChangeText={setSkills}
            />

            <TouchableOpacity style={styles.button} onPress={handleSubmit} disabled={isSubmitting}>
                <Text style={styles.buttonText}>{isSubmitting ? 'Posting...' : 'Post Gig'}</Text>
            </TouchableOpacity>
        </ScrollView>
    );
}

