interface Props {
    role: UserRole;
}

export default function HomeScreen({ role }: Props) {
    const { user } = useAppStore();
    const isWorker = role === 'worker';
    const [showNotifications, setShowNotifications] = useState(false);
    const [showMenu, setShowMenu] = useState(false);
    const [activeGigs, setActiveGigs] = useState<any[]>([]);
    const [userProfile, setUserProfile] = useState<any>(null);
    const [isLoading, setIsLoading] = useState(true);

    // Fetch user profile and active gigs
    useEffect(() => {
        fetchHomeData();
    }, [user?.id]);

    const fetchHomeData = async () => {
        if (!user?.id) return;

        try {
            setIsLoading(true);

            // Fetch user profile for wallet balance
            const profile = await profileApi.get(user.id);
            setUserProfile(profile);

            // Fetch active jobs
            const jobs = await gigsApi.getAll() as any[];

            // Filter to show relevant jobs
            const relevantJobs = isWorker 
                ? (jobs || []).filter((job: any) => job.status === 'IN_PROGRESS' && job.workerId === user.id).slice(0, 2)
                : (jobs || []).filter((job: any) => job.clientId === user.id).slice(0, 2);

            // Map to display format
            const mappedGigs = relevantJobs.map((job: any) => isWorker ? {
                title: job.title,
                client: 'Client',
                status: job.status === 'IN_PROGRESS' ? 'In Progress' : 'Open',
                icon: 'briefcase',
                time: 'Active'
            } : {
                title: job.title,
                applicants: '0 New',
                status: job.status === 'OPEN' ? 'Hiring' : 'Active',
                icon: 'people',
                time: 'Active'
            });

            setActiveGigs(mappedGigs);
        } catch (error) {
            console.error('Failed to fetch home data:', error);
            // Set empty defaults on error
            setActiveGigs([]);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <View style={styles.container}>
            {/* Fixed Header */}
            <View style={styles.header}>
                <View style={styles.headerLeft}>
                    <LinearGradient colors={['#6366F1', '#7C3AED']} style={styles.logoGradient}>
                        <Ionicons name="people" size={20} color="#fff" />
