import React from 'react';
import { View, Text, StyleSheet, TouchableOpacity, Alert, ScrollView, ActivityIndicator } from 'react-native';
import { useRoute, useNavigation } from '@react-navigation/native';
import { useAppStore } from '../../store/appStore';
import { logger } from '../../utils/logger';

export default function GigDetailsScreen() {
    const route = useRoute();
    const navigation = useNavigation();
    const { user, setUser } = useAppStore();
    // route.params?.id expected
    // @ts-ignore
    const { id } = route.params || {};

    const [gig, setGig] = React.useState<any | null>(null);
    const [loading, setLoading] = React.useState(true);
    const [error, setError] = React.useState<string | null>(null);
    const [creatingContract, setCreatingContract] = React.useState(false);

    React.useEffect(() => {
        let mounted = true;
        async function load() {
            try {
                setLoading(true);
                setError(null);
                if (!id) {
                    setError('No gig id provided');
                    return;
                }
                // eslint-disable-next-line @typescript-eslint/no-var-requires
                const { gigsApi } = require('../../services/api');
                const data = await gigsApi.getById(id);
                if (!mounted) return;
                setGig(data);
            } catch (err: any) {
                console.error('Failed to load gig:', err);
                if (mounted) setError(err.message || 'Failed to load gig');
            } finally {
                if (mounted) setLoading(false);
            }
        }
        load();
        return () => { mounted = false; };
    }, [id]);

    const handleGenerateContract = async () => {
        if (!gig) return;
        setCreatingContract(true);
        try {
            // eslint-disable-next-line @typescript-eslint/no-var-requires
            const { contractsApi } = require('../../services/api');
            await contractsApi.generateAI({
                description: gig.description,
                amount: gig.budget,
                jobId: gig.id
            });
            Alert.alert('Success', 'Contract generated successfully! Check your email or contracts dashboard.');
        } catch (err: any) {
            Alert.alert('Error', 'Failed to generate contract: ' + err.message);
        } finally {
            setCreatingContract(false);
        }
    };

    const handleApply = async () => {
        if (!gig || !user) return;
        setCreatingContract(true);
        try {
            // eslint-disable-next-line @typescript-eslint/no-var-requires
            const { contractsApi, profileApi } = require('../../services/api');

            // Auto-update profile to include required skills if missing
            const userSkills = user.profile?.skills || [];
            const requiredSkills = gig.skills || [];
            const missingSkills = requiredSkills.filter((skill: string) => 
                !userSkills.some((us: string) => us.toLowerCase() === skill.toLowerCase())
            );

            if (missingSkills.length > 0) {
                logger.info('Auto-adding missing skills:', missingSkills);
                const newSkills = [...userSkills, ...missingSkills];

                // Update backend
                await profileApi.update(user.id, {
                    workerProfile: {
                        update: {
                            languages: newSkills
                        }
                    }
                });

                // Update local store
                const updatedUser = {
                    ...user,
                    profile: {
                        ...user.profile,
                        skills: newSkills
                    }
                };
                setUser(updatedUser, undefined);
            }

            await contractsApi.create({
                jobId: gig.id,
                employerId: gig.employerId || gig.clientId,
                workerId: user.id,
                gigTitle: gig.title,
                amount: typeof gig.budget === 'object' ? gig.budget.min : gig.budget || 0,
                status: 'pending'
            });
            Alert.alert('Success', 'Application sent successfully!');
            navigation.goBack();
        } catch (err: any) {
            Alert.alert('Error', 'Failed to apply: ' + err.message);
        } finally {
            setCreatingContract(false);
        }
    };

    return (
        <ScrollView contentContainerStyle={styles.container}>
            {loading ? (
                <ActivityIndicator size="large" color="#6366F1" />
            ) : error ? (
                <Text style={styles.error}>{error}</Text>
            ) : gig ? (
                <>
                    <Text style={styles.title}>{gig.title || 'Untitled'}</Text>
                    <View style={styles.tagContainer}>
                        <Text style={styles.tag}>{gig.type || 'Fixed Price'}</Text>
                        <Text style={styles.tag}>{gig.status || 'Open'}</Text>
                    </View>

                    <Text style={styles.sectionTitle}>Description</Text>
                    <Text style={styles.subtitle}>{gig.description || 'No description provided.'}</Text>

                    <Text style={styles.sectionTitle}>Budget</Text>
                    <Text style={styles.note}>${gig.budget || gig.price || '0'}</Text>

                    <Text style={styles.sectionTitle}>Skills</Text>
                    <View style={styles.skillsContainer}>
                        {(gig.skills || []).map((skill: string, index: number) => (
                            <View key={index} style={styles.skillChip}>
                                <Text style={styles.skillText}>{skill}</Text>
                            </View>
                        ))}
                    </View>

                    {user?.role === 'employer' ? (
                        <TouchableOpacity 
                            style={styles.button}
                            onPress={handleGenerateContract}
                            disabled={creatingContract}
                        >
                            {creatingContract ? (
                                <ActivityIndicator color="#fff" />
                            ) : (
                                <Text style={styles.buttonText}>Generate Contract with AI</Text>
                            )}
                        </TouchableOpacity>
                    ) : (
                        <TouchableOpacity 
                            style={styles.button}
                            onPress={handleApply}
                            disabled={creatingContract}
                        >
                            {creatingContract ? (
                                <ActivityIndicator color="#fff" />
                            ) : (
                                <Text style={styles.buttonText}>Apply Now</Text>
                            )}
                        </TouchableOpacity>
                    )}
                </>
            ) : (
                <Text style={styles.subtitle}>No data found</Text>
            )}
        </ScrollView>
    );
}

