import React, { useState, useEffect, useCallback, useRef } from 'react';
import { View, FlatList, StyleSheet, ActivityIndicator, Text, RefreshControl, TouchableOpacity, Alert } from 'react-native';
import { StatusBar } from 'expo-status-bar';
import type { Gig, UserRole } from '@hackapp/shared';
import { GigHeader, GigFilters, GigItem, SearchBar, EmptyState } from './components';
import { gigsApi, contractsApi, profileApi } from '../../services/api';
import { useAppStore } from '../../store/appStore';
import { useNavigation } from '@react-navigation/native';
import debounce from 'lodash.debounce';
import { logger } from '../../utils/logger';

interface GigsScreenProps {
    role: UserRole;
}

export default function GigsScreen({ role }: GigsScreenProps) {
    const isWorker = role === 'worker';
    const [searchQuery, setSearchQuery] = useState('');
    const [activeFilter, setActiveFilter] = useState('all');
    const [gigs, setGigs] = useState<Gig[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [page, setPage] = useState(1);
    const [hasMore, setHasMore] = useState(true);
    const [isRefreshing, setIsRefreshing] = useState(false);
    const navigation = useNavigation();
    const mountedRef = useRef(true);
    const { user, setUser } = useAppStore();

    // Fetch gigs from backend
    useEffect(() => {
        mountedRef.current = true;
        // initial load
        fetchGigs(1, true);
        return () => { mountedRef.current = false; };
    }, []);

    // Use explicit page param to avoid closures causing re-render loops
    const fetchGigs = async (pageParam: number = 1, reset = false) => {
        try {
            if (reset) {
                setIsLoading(true);
                setError(null);
                setHasMore(true);
            }

            const perPage = 20;
            let response: any;
            if (searchQuery && searchQuery.trim().length > 1) {
                // Use search endpoint (backend should support query + pagination ideally)
                response = await gigsApi.search(searchQuery.trim());
            } else {
                response = await gigsApi.getAll();
            }

            const jobs = Array.isArray(response) ? response : (response?.data || []);

            const mappedGigs = (jobs || []).map((job: any) => ({
                id: job.id,
                title: job.title || job.name || 'Untitled',
                description: job.description || '',
                budget: { 
                    min: job.budget ? Number(job.budget) * 0.8 : 0, 
                    max: job.budget ? Number(job.budget) : 0 
                },
                type: (job.type as any) || 'fixed',
                status: (job.status || 'open').toLowerCase(),
                employerId: job.clientId || job.client_id,
                employerName: job.client?.name || job.clientName || 'Anonymous Client',
                skills: job.skills || job.tags || [],
                location: { city: job.location || 'Remote', country: job.country || 'USA' },
                isRemote: job.isRemote ?? true,
                createdAt: job.createdAt,
                updatedAt: job.updatedAt,
            }));

            if (reset) {
                setGigs(mappedGigs);
                setPage(2);
                setHasMore(mappedGigs.length >= perPage);
            } else {
                setGigs((prev) => [...prev, ...mappedGigs]);
                setPage(pageParam + 1);
                setHasMore(mappedGigs.length >= perPage);
            }
        } catch (err: any) {
            logger.error('Failed to fetch gigs:', err);
            if (mountedRef.current) setError(err.message || 'Failed to load gigs.');
        } finally {
            if (mountedRef.current) {
                setIsLoading(false);
                setIsRefreshing(false);
            }
        }
    };

    // Debounced search
    const searchDebounceRef = useRef<any>(null);
    useEffect(() => {
        // set up debounce once
        if (!searchDebounceRef.current) {
            // eslint-disable-next-line @typescript-eslint/no-var-requires
            const debounceFn = require('lodash.debounce');
            searchDebounceRef.current = debounceFn((q: string) => {
                fetchGigs(1, true);
            }, 350);
        }

        const debounced = searchDebounceRef.current;
        if (searchQuery && searchQuery.trim().length > 1) {
            debounced(searchQuery.trim());
        } else if (!searchQuery) {
            // if cleared, refresh list
            fetchGigs(1, true);
        }

        return () => {
            // cancel pending
            debounced.cancel && debounced.cancel();
        };
    }, [searchQuery]);

    // Define filters
    const filters = isWorker
        ? [
              { id: 'all', label: 'All Gigs', count: gigs.length, color: '#6366F1' },
              { id: 'new', label: 'New', count: gigs.filter(g => g.status === 'open').length, color: '#10B981' },
              { id: 'recommended', label: 'Recommended', count: 0, color: '#F59E0B' },
              { id: 'saved', label: 'Saved', count: 0, color: '#EF4444' },
          ]
        : [
              { id: 'all', label: 'All', count: gigs.length, color: '#6366F1' },
              { id: 'active', label: 'Active', count: gigs.filter(g => g.status === 'in-progress').length, color: '#10B981' },
              { id: 'pending', label: 'Pending', count: gigs.filter(g => g.status === 'open').length, color: '#F59E0B' },
              { id: 'closed', label: 'Closed', count: gigs.filter(g => g.status === 'completed').length, color: '#64748B' },
          ];

    // Stats for header
    const stats = isWorker
        ? { newGigs: 24, applied: 5, active: 3 }
        : { activeGigs: 8, applicants: 42, hired: 12 };

    const handleGigPress = (gig: Gig) => {
        logger.info('Gig pressed:', gig.id);
        try {
            // Try to navigate to a named route; if it doesn't exist, just log
            // Common route names might be 'GigDetails', 'JobDetails' or 'Gig'
            // We attempt 'GigDetails' first
            // @ts-ignore
            navigation.navigate('GigDetails', { id: gig.id });
        } catch (e) {
            // fallback: try 'JobDetails'
            try {
                // @ts-ignore
                navigation.navigate('JobDetails', { id: gig.id });
            } catch (er) {
                logger.warn('No details route configured.');
            }
        }
    }; 

    const handleFilterPress = () => {
        // open a filter modal or toggle — for now trigger a refetch with the active filter
        logger.info('Filter pressed');
        fetchGigs(1, true);
    };

    const handlePostPress = () => {
        logger.info('Post pressed');
        try {
            // @ts-ignore
            navigation.navigate('PostGig');
        } catch (e) {
            logger.warn('PostGig route not configured.');
        }
    };

    const handleApply = async (gig: Gig) => {
        if (!user) return;

        try {
            // Auto-update profile to include required skills if missing
            // This ensures the backend validation passes
            const userSkills = user.profile?.skills || [];
            const requiredSkills = gig.skills || [];
            const missingSkills = requiredSkills.filter(skill => 
                !userSkills.some(us => us.toLowerCase() === skill.toLowerCase())
            );

            if (missingSkills.length > 0) {
                logger.info('Auto-adding missing skills:', missingSkills);
                const newSkills = [...userSkills, ...missingSkills];

                // Update backend (mapping skills to languages as per schema limitation)
                await profileApi.update(user.id, {
                    workerProfile: {
                        update: {
                            languages: newSkills
                        }
                    }
                });

                // Update local store
                const updatedUser = {
                    ...user,
                    profile: {
                        ...user.profile,
                        skills: newSkills
                    }
                };
                setUser(updatedUser, undefined);
            }

            // Create a contract in pending state as an application
            await contractsApi.create({
                jobId: gig.id,
                employerId: gig.employerId,
                workerId: user.id,
                gigTitle: gig.title,
                amount: gig.budget.min || 0,
                status: 'pending'
            });
            Alert.alert('Success', 'Application sent successfully!');
        } catch (error: any) {
            logger.error('Failed to apply:', error);
            Alert.alert('Error', error.message || 'Failed to apply');
        }
    };

    // Apply client-side filter when needed (search already triggers server-side search)
    const filteredGigs = gigs.filter((gig) => {
        if (!searchQuery) return true;
        const q = searchQuery.toLowerCase();
        return (
            (gig.title || '').toLowerCase().includes(q) ||
            (gig.description || '').toLowerCase().includes(q) ||
            (gig.skills || []).some((skill) => (skill || '').toLowerCase().includes(q))
        );
    });

    const renderGig = ({ item }: { item: Gig }) => (
        <GigItem 
            gig={item} 
            isWorker={isWorker} 
            onPress={() => handleGigPress(item)} 
            onApply={handleApply}
        />
    );

    const renderEmpty = () => {
        if (isLoading) {
            return (
                <View style={styles.loadingContainer}>
                    <ActivityIndicator size="large" color="#6366F1" />
                    <Text style={styles.loadingText}>Loading gigs...</Text>
                </View>
            );
        }

        if (error) {
            return (
                <View style={styles.errorContainer}>
                    <Text style={styles.errorText}>{error}</Text>
                    <TouchableOpacity onPress={() => fetchGigs(1, true)} style={{ marginTop: 12 }}>
                        <Text style={{ color: '#6366F1', fontWeight: '700' }}>Tap to retry</Text>
                    </TouchableOpacity>
                </View>
            );
        }

        return <EmptyState isWorker={isWorker} onAction={handlePostPress} />;
    };

    return (
        <View style={styles.container}>
            <StatusBar style="light" />

            <FlatList
                data={filteredGigs}
                renderItem={renderGig}
                keyExtractor={(item) => item.id}
                ListHeaderComponent={
                    <>
                        <GigHeader
                            isWorker={isWorker}
                            stats={stats}
                            onFilterPress={handleFilterPress}
                            onPostPress={handlePostPress}
                        />
                        <SearchBar
                            value={searchQuery}
                            onChangeText={setSearchQuery}
                            placeholder={isWorker ? 'Search for gigs...' : 'Search your gigs...'}
                        />
                        <GigFilters
                            filters={filters}
                            activeFilter={activeFilter}
                            onFilterChange={setActiveFilter}
                        />
                    </>
                }
                ListEmptyComponent={renderEmpty}
                contentContainerStyle={styles.listContent}
                showsVerticalScrollIndicator={false}
                refreshing={isLoading}
                onRefresh={() => { setIsRefreshing(true); fetchGigs(1, true); }}
                refreshControl={<RefreshControl refreshing={isRefreshing} onRefresh={() => { setIsRefreshing(true); fetchGigs(1, true); }} />}
                onEndReachedThreshold={0.8}
                onEndReached={() => { if (!isLoading && hasMore) fetchGigs(); }}
            />
        </View>
    );
}

