import React, { useState, useEffect } from 'react';
import {
    View,
    Text,
    ScrollView,
    StyleSheet,
    SafeAreaView,
    ActivityIndicator,
} from 'react-native';
import { StatusBar } from 'expo-status-bar';
import { useAppStore } from '../../store/appStore';
import { WalletHeader, QuickStats, TransactionItem } from './components';
import { profileApi, contractsApi } from '../../services/api';
import { logger } from '../../utils/logger';

export default function WalletScreen() {
    const { user } = useAppStore();
    const [userProfile, setUserProfile] = useState<any>(null);
    const [transactions, setTransactions] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        fetchWalletData();
    }, [user?.id]);

    const fetchWalletData = async () => {
        if (!user?.id) return;

        try {
            setIsLoading(true);
            const [profile, contracts] = await Promise.all([
                profileApi.get(user.id),
                contractsApi.getAll()
            ]);
            setUserProfile(profile);

            // Map contracts to transactions for display
            const mappedTransactions = (contracts as any[] || []).map((c: any) => ({
                id: c.id,
                type: user.role === 'worker' ? 'credit' : 'debit',
                title: c.gigTitle || 'Contract Payment',
                description: c.status,
                amount: c.amount || 0,
                date: c.createdAt || new Date().toISOString(),
                status: c.status === 'completed' ? 'completed' : 'pending',
            }));
            setTransactions(mappedTransactions);

        } catch (error) {
            logger.error('Failed to fetch wallet data:', error);
        } finally {
            setIsLoading(false);
        }
    };

    const workerStats = [
        { label: 'Earned this month', value: '$4,300', change: '+12%', isPositive: true },
        { label: 'Active gigs', value: '3', change: '+1', isPositive: true },
        { label: 'Avg. payment', value: '$850', change: '-5%', isPositive: false },
    ];

    const employerStats = [
        { label: 'Spent this month', value: '$8,500', change: '+23%', isPositive: false },
        { label: 'Active contracts', value: '5', change: '+2', isPositive: true },
        { label: 'Avg. project cost', value: '$1,700', change: '+8%', isPositive: false },
    ];

    const renderTransaction = ({ item }: { item: any }) => (
        <TransactionItem transaction={item} />
    );

    return (
        <SafeAreaView style={styles.container}>
            <StatusBar style="dark" />

            <ScrollView 
                showsVerticalScrollIndicator={false}
                contentContainerStyle={styles.scrollContent}
            >
                <View style={styles.header}>
                    <Text style={styles.headerTitle}>Wallet</Text>
                    <Text style={styles.headerSubtitle}>
                        {user?.role === 'worker' ? 'Your earnings' : 'Your spending'}
                    </Text>
                </View>

                {isLoading ? (
                    <View style={styles.loadingContainer}>
                        <ActivityIndicator size="large" color="#6366F1" />
                    </View>
                ) : (
                    <>
                        <WalletHeader
                            role={user?.role || 'worker'}
                            balance={parseFloat(userProfile?.walletBalance || '0')}
                            pendingBalance={0}
                        />

                        <QuickStats stats={user?.role === 'worker' ? workerStats : employerStats} />
                    </>
                )}

                <View style={styles.transactionsHeader}>
                    <Text style={styles.transactionsTitle}>Recent Transactions</Text>
                </View>

                {transactions.length > 0 ? (
                    transactions.map((item) => (
                        <TransactionItem key={item.id} transaction={item} />
                    ))
                ) : (
                    <View style={{ padding: 24, alignItems: 'center' }}>
                        <Text style={{ color: '#64748B' }}>No transactions yet</Text>
                    </View>
                )}
            </ScrollView>
        </SafeAreaView>
    );
}

