import React, { useState } from 'react';
import {
    View,
    Text,
    StyleSheet,
    TouchableOpacity,
    ScrollView,
    KeyboardAvoidingView,
    Platform,
    Alert,
    ActivityIndicator,
} from 'react-native';
import { useNavigation } from '@react-navigation/native';
import { Ionicons } from '@expo/vector-icons';
import { LinearGradient } from 'expo-linear-gradient';
import { Mail, Lock, User } from 'lucide-react-native';
import { useAppStore } from '../../store/appStore';
import { Input } from '../../components/ui/Input';
import { authApi } from '../../services/api';
import type { AuthScreenNavigationProp } from '../../navigation/types';

export default function AuthScreen() {
    const navigation = useNavigation<AuthScreenNavigationProp>();
    const { setUser } = useAppStore();
    const [isLogin, setIsLogin] = useState(true);
    const [showPassword, setShowPassword] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [userRole, setUserRole] = useState<'worker' | 'employer'>('worker');
    const [formData, setFormData] = useState({
        email: '',
        password: '',
        name: '',
    });

    const handleAuth = async () => {
        // Validation
        if (!formData.email || !formData.password) {
            Alert.alert('Error', 'Please fill in all required fields');
            return;
        }

        if (!isLogin && !formData.name) {
            Alert.alert('Error', 'Please provide your name');
            return;
        }

        setIsLoading(true);

        try {
            if (isLogin) {
                // Login with backend API
                const response = await authApi.login(formData.email, formData.password, true) as any;

                if (response.user && response.token) {
                    // Map backend user to frontend format
                    const mappedUser = {
                        id: response.user.id,
                        name: response.user.name || 'User',
                        email: response.user.email || formData.email,
                        role: (response.user.role === 'CLIENT' ? 'employer' : 'worker') as any,
                        trustScore: response.user.trustScore || 100,
                        isVerified: response.user.kycVerified || false,
                        profileComplete: response.user.onboardingStatus === 'COMPLETED',
                        createdAt: response.user.createdAt,
                    };

                    await setUser(mappedUser, response.token);
                    // Navigation will happen automatically via RootNavigator
                } else {
                    Alert.alert('Error', 'Invalid response from server');
                }
            } else {
                // Register with backend API
                const backendRole = userRole === 'employer' ? 'CLIENT' : 'WORKER';
                const response = await authApi.register({
                    email: formData.email,
                    password: formData.password,
                    name: formData.name,
                    role: backendRole,
                }) as any;

                if (response.user && response.token) {
                    // Map backend user to frontend format
                    const mappedUser = {
                        id: response.user.id,
                        name: response.user.name || formData.name,
                        email: response.user.email || formData.email,
                        role: userRole,
                        trustScore: response.user.trustScore || 100,
                        isVerified: false,
                        profileComplete: false,
                        createdAt: response.user.createdAt,
                    };

                    await setUser(mappedUser, response.token);
                    // Go through onboarding flow
                    navigation.navigate('RoleSelection');
                } else {
                    Alert.alert('Error', 'Registration failed');
                }
            }
        } catch (error: any) {
            console.error('Auth error:', error);
            Alert.alert(
                'Authentication Error',
                error.message || 'Failed to authenticate. Please try again.'
            );
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <KeyboardAvoidingView
            style={styles.container}
            behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
        >
            <ScrollView
                contentContainerStyle={styles.scrollContent}
                showsVerticalScrollIndicator={false}
            >
                {/* Header */}
                <View style={styles.header}>
                    <View style={styles.logoContainer}>
                        <LinearGradient
                            colors={['#6366F1', '#7C3AED']}
                            style={styles.logoGradient}
                        >
                            <Ionicons name="people" size={20} color="#fff" />
                        </LinearGradient>
                        <Text style={styles.logo}>
                            MIDDLE<Text style={styles.logoLight}>MAN</Text>
                        </Text>
                    </View>
                </View>

                {/* Title */}
                <View style={styles.titleSection}>
                    <View style={[styles.modeBadge, isLogin ? styles.modeBadgeLogin : styles.modeBadgeSignup]}>
                        <Ionicons
                            name={isLogin ? 'log-in-outline' : 'person-add-outline'}
                            size={16}
                            color="#fff"
                        />
                        <Text style={styles.modeBadgeText}>
                            {isLogin ? 'LOGIN MODE' : 'SIGNUP MODE'}
                        </Text>
                    </View>
                    <Text style={styles.title}>
                        {isLogin ? 'Welcome Back' : 'Create Account'}
                    </Text>
                    <Text style={styles.subtitle}>
                        {isLogin
                            ? 'Sign in to access your dashboard.'
                            : 'Complete your profile to get started.'}
                    </Text>
                </View>

                {/* Role Selector */}
                <View style={styles.roleSelector}>
                    <TouchableOpacity
                        style={[
                            styles.roleButton,
                            userRole === 'worker' && styles.roleButtonActive,
                        ]}
                        onPress={() => setUserRole('worker')}
                    >
                        <Ionicons
                            name="person-outline"
                            size={16}
                            color={userRole === 'worker' ? '#6366F1' : '#64748B'}
                        />
                        <Text
                            style={[
                                styles.roleText,
                                userRole === 'worker' && styles.roleTextActive,
                            ]}
                        >
                            WORKER
                        </Text>
                    </TouchableOpacity>
                    <TouchableOpacity
                        style={[
                            styles.roleButton,
                            userRole === 'employer' && styles.roleButtonActive,
                        ]}
                        onPress={() => setUserRole('employer')}
                    >
                        <Ionicons
                            name="business-outline"
                            size={16}
                            color={userRole === 'employer' ? '#6366F1' : '#64748B'}
                        />
                        <Text
                            style={[
                                styles.roleText,
                                userRole === 'employer' && styles.roleTextActive,
                            ]}
                        >
                            EMPLOYER
                        </Text>
                    </TouchableOpacity>
                </View>

                {/* Form */}
                <View style={styles.form}>
                    {!isLogin && (
                        <Input
                            label="Full Name"
                            placeholder="Enter your full name"
                            icon={User}
                            value={formData.name}
                            onChangeText={(text) => setFormData({ ...formData, name: text })}
                            error={formData.name && formData.name.length < 2 ? 'Name must be at least 2 characters' : ''}
                        />
                    )}

                    <Input
                        label="Email"
                        placeholder={userRole === 'worker' ? 'Enter your personal email' : 'Enter your corporate email'}
                        icon={Mail}
                        value={formData.email}
                        onChangeText={(text) => setFormData({ ...formData, email: text })}
                        error={formData.email && !formData.email.includes('@') ? 'Please enter a valid email address' : ''}
                        keyboardType="email-address"
                        autoCapitalize="none"
                    />

                    <Input
                        label="Password"
                        placeholder="Enter your password"
                        icon={Lock}
                        value={formData.password}
                        onChangeText={(text) => setFormData({ ...formData, password: text })}
                        error={formData.password && formData.password.length < 6 ? 'Password must be at least 6 characters' : ''}
                        secureTextEntry
                    />

                    {isLogin && (
                        <TouchableOpacity style={styles.forgotButton}>
                            <Text style={styles.forgotText}>Forgot Password?</Text>
                        </TouchableOpacity>
                    )}

                    {/* Auth Button */}
                    <TouchableOpacity
                        style={[styles.authButton, !isLogin && styles.authButtonSignup]}
                        onPress={handleAuth}
                        activeOpacity={0.9}
                        disabled={isLoading}
                    >
                        {isLoading ? (
                            <ActivityIndicator color="#fff" />
                        ) : (
                            <>
                                <Ionicons
                                    name={isLogin ? 'log-in' : 'arrow-forward'}
                                    size={20}
                                    color="#fff"
                                />
                                <Text style={styles.authButtonText}>
                                    {isLogin ? 'LOGIN TO DASHBOARD' : 'START ONBOARDING'}
                                </Text>
                            </>
                        )}
                    </TouchableOpacity>

                    {/* Divider */}
                    <View style={styles.divider}>
                        <View style={styles.dividerLine} />
                        <Text style={styles.dividerText}>
                            {isLogin ? 'NEW HERE?' : 'HAVE AN ACCOUNT?'}
                        </Text>
                        <View style={styles.dividerLine} />
                    </View>

                    {/* Toggle Auth Mode */}
                    <TouchableOpacity
                        style={styles.toggleButton}
                        onPress={() => setIsLogin(!isLogin)}
                        activeOpacity={0.9}
                    >
                        <Text style={styles.toggleButtonText}>
                            {isLogin ? 'CREATE NEW ACCOUNT' : 'LOGIN TO EXISTING ACCOUNT'}
                        </Text>
                    </TouchableOpacity>

                    {/* Social Auth (Optional) */}
                    {isLogin && (
                        <>
                            <View style={styles.divider}>
                                <View style={styles.dividerLine} />
                                <Text style={styles.dividerText}>OR CONTINUE WITH</Text>
                                <View style={styles.dividerLine} />
                            </View>

                            <View style={styles.socialButtons}>
                                <TouchableOpacity style={styles.socialButton}>
                                    <Ionicons name="logo-google" size={20} color="#0F172A" />
                                </TouchableOpacity>
                                <TouchableOpacity style={styles.socialButton}>
                                    <Ionicons name="logo-apple" size={20} color="#0F172A" />
                                </TouchableOpacity>
                                <TouchableOpacity style={styles.socialButton}>
                                    <Ionicons name="logo-github" size={20} color="#0F172A" />
                                </TouchableOpacity>
                            </View>
                        </>
                    )}
                </View>
            </ScrollView>
        </KeyboardAvoidingView>
    );
}

