import React, { useState, useEffect } from 'react';
import {
    View,
    Text,
    ScrollView,
    StyleSheet,
    SafeAreaView,
    Alert,
    ActivityIndicator,
} from 'react-native';
import { StatusBar } from 'expo-status-bar';
import { useAppStore } from '../../store/appStore';
import { ProfileHeader, ProfileStats, MenuItem } from './components';
import { gamificationApi, profileApi } from '../../services/api';
import { logger } from '../../utils/logger';

export default function ProfileScreen({ navigation }: any) {
    const { user, logout } = useAppStore();
    const [stats, setStats] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        fetchProfileStats();
    }, [user?.id]);

    const fetchProfileStats = async () => {
        if (!user?.id) return;

        try {
            setIsLoading(true);

            if (user.role === 'worker') {
                // Fetch gamification stats for workers
                const gamificationStats = await gamificationApi.getMyStats() as any;

                setStats([
                    { icon: 'briefcase' as const, label: 'Completed Gigs', value: gamificationStats?.completedJobs?.toString() || '0', color: '#6366F1' },
                    { icon: 'star' as const, label: 'Rating', value: gamificationStats?.rating?.toFixed(1) || '0.0', color: '#F59E0B' },
                    { icon: 'cash' as const, label: 'Total Earned', value: `$${gamificationStats?.totalEarnings?.toFixed(0) || '0'}`, color: '#10B981' },
                ]);
            } else {
                // For employers, use profile data
                const profile = await profileApi.get(user.id) as any;

                setStats([
                    { icon: 'people' as const, label: 'Jobs Posted', value: profile?.jobsAsClient?.length?.toString() || '0', color: '#6366F1' },
                    { icon: 'checkmark-circle' as const, label: 'Active', value: '0', color: '#10B981' },
                    { icon: 'trending-up' as const, label: 'Success Rate', value: '0%', color: '#F59E0B' },
                ]);
            }
        } catch (error) {
            logger.error('Failed to fetch profile stats:', error);
            // Set default stats on error
            const defaultStats = user?.role === 'worker'
                ? [
                    { icon: 'briefcase' as const, label: 'Completed Gigs', value: '0', color: '#6366F1' },
                    { icon: 'star' as const, label: 'Rating', value: '0.0', color: '#F59E0B' },
                    { icon: 'cash' as const, label: 'Total Earned', value: '$0', color: '#10B981' },
                ]
                : [
                    { icon: 'people' as const, label: 'Workers Hired', value: '0', color: '#6366F1' },
                    { icon: 'checkmark-circle' as const, label: 'Projects', value: '0', color: '#10B981' },
                    { icon: 'trending-up' as const, label: 'Success Rate', value: '0%', color: '#F59E0B' },
                ];
            setStats(defaultStats);
        } finally {
            setIsLoading(false);
        }
    };

    if (!user) {
        return null;
    }

    const handleLogout = () => {
        Alert.alert(
            'Logout',
            'Are you sure you want to logout?',
            [
                { text: 'Cancel', style: 'cancel' },
                {
                    text: 'Logout',
                    style: 'destructive',
                    onPress: async () => {
                        await logout();
                        navigation.reset({
                            index: 0,
                            routes: [{ name: 'Auth' }],
                        });
                    },
                },
            ]
        );
    };

    const accountMenuItems = [
        {
            icon: 'person-outline' as const,
            title: 'Personal Information',
            subtitle: 'Update your details',
            onPress: () => navigation.navigate('EditProfile'),
        },
        {
            icon: 'shield-checkmark-outline' as const,
            title: 'Security',
            subtitle: 'Password & authentication',
            onPress: () => logger.info('Security'),
        },
        {
            icon: 'notifications-outline' as const,
            title: 'Notifications',
            subtitle: 'Manage your preferences',
            onPress: () => logger.info('Notifications'),
        },
        {
            icon: 'card-outline' as const,
            title: 'Payment Methods',
            subtitle: 'Manage cards & bank accounts',
            onPress: () => logger.info('Payment Methods'),
        },
    ];

    const appMenuItems = [
        {
            icon: 'help-circle-outline' as const,
            title: 'Help & Support',
            onPress: () => logger.info('Help'),
            color: '#6366F1',
        },
        {
            icon: 'document-text-outline' as const,
            title: 'Terms & Policies',
            onPress: () => logger.info('Terms'),
            color: '#6366F1',
        },
        {
            icon: 'information-circle-outline' as const,
            title: 'About',
            subtitle: 'Version 1.0.0',
            onPress: () => logger.info('About'),
            color: '#6366F1',
        },
    ];

    const logoutMenuItem = {
        icon: 'log-out-outline' as const,
        title: 'Logout',
        onPress: handleLogout,
        color: '#EF4444',
    };

    return (
        <SafeAreaView style={styles.container}>
            <StatusBar style="dark" />
            <ScrollView showsVerticalScrollIndicator={false}>
                <ProfileHeader
                    user={user}
                    onEditPress={() => navigation.navigate('EditProfile')}
                />
                {isLoading ? (
                    <View style={styles.loadingContainer}>
                        <ActivityIndicator size="large" color="#6366F1" />
                    </View>
                ) : (
                    <ProfileStats stats={stats} />
                )}

                <View style={styles.section}>
                    <Text style={styles.sectionTitle}>Account Settings</Text>
                    {accountMenuItems.map((item, index) => (
                        <MenuItem key={index} item={item} />
                    ))}
                </View>

                <View style={styles.section}>
                    <Text style={styles.sectionTitle}>App</Text>
                    {appMenuItems.map((item, index) => (
                        <MenuItem key={index} item={item} />
                    ))}
                </View>

                <View style={styles.section}>
                    <MenuItem item={logoutMenuItem} />
                </View>

                <View style={styles.footer}>
                    <Text style={styles.footerText}>Made with ❤️ by HackApp</Text>
                </View>
            </ScrollView>
        </SafeAreaView>
    );
}

