import React, { useState } from 'react';
import {
    View,
    Text,
    StyleSheet,
    TextInput,
    TouchableOpacity,
    ScrollView,
    Alert,
    ActivityIndicator,
    KeyboardAvoidingView,
    Platform,
} from 'react-native';
import { useNavigation } from '@react-navigation/native';
import { Ionicons } from '@expo/vector-icons';
import { useAppStore } from '../../store/appStore';
import { profileApi } from '../../services/api';
import { logger } from '../../utils/logger';

export default function EditProfileScreen() {
    const navigation = useNavigation();
    const { user, setUser } = useAppStore();
    const [isLoading, setIsLoading] = useState(false);

    const [formData, setFormData] = useState({
        name: user?.name || '',
        bio: user?.profile?.bio || '',
        skills: user?.profile?.skills?.join(', ') || '',
        hourlyRate: user?.profile?.hourlyRate?.toString() || '',
        location: user?.location || '',
        phone: user?.phone || '',
    });

    const handleSave = async () => {
        if (!user?.id) return;

        if (!formData.name.trim()) {
            Alert.alert('Error', 'Name is required');
            return;
        }

        setIsLoading(true);
        try {
            // Construct Prisma-compatible update object
            // Only include fields that exist in the backend schema
            const updateData: any = {
                bio: formData.bio,
            };

            if (user.role === 'worker') {
                updateData.workerProfile = {
                    update: {
                        // Map skills to languages since skills column is missing
                        languages: formData.skills.split(',').map(s => s.trim()).filter(Boolean),
                        // hourlyRate, name, location, phone are not in DB schema
                        // so we don't send them to avoid 500 error
                    }
                };
            }
            // Employer profile has no editable fields in the current schema subset we know of

            // Send what we can to the backend
            await profileApi.update(user.id, updateData);

            // Update local store with ALL fields so the UI reflects changes immediately
            // These changes will persist locally via AsyncStorage
            const mergedUser = {
                ...user,
                name: formData.name,
                location: formData.location,
                phone: formData.phone,
                profile: {
                    ...user.profile,
                    bio: formData.bio,
                    skills: formData.skills.split(',').map(s => s.trim()).filter(Boolean),
                    hourlyRate: parseFloat(formData.hourlyRate) || 0,
                }
            };

            setUser(mergedUser, undefined); // Keep existing token

            Alert.alert('Success', 'Profile updated successfully');
            navigation.goBack();
        } catch (error: any) {
            logger.error('Failed to update profile:', error);
            Alert.alert('Error', error.message || 'Failed to update profile');
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <KeyboardAvoidingView 
            style={styles.container}
            behavior={Platform.OS === 'ios' ? 'padding' : undefined}
        >
            <View style={styles.header}>
                <TouchableOpacity onPress={() => navigation.goBack()} style={styles.backButton}>
                    <Ionicons name="arrow-back" size={24} color="#0F172A" />
                </TouchableOpacity>
                <Text style={styles.headerTitle}>Edit Profile</Text>
                <TouchableOpacity onPress={handleSave} disabled={isLoading}>
                    {isLoading ? (
                        <ActivityIndicator size="small" color="#6366F1" />
                    ) : (
                        <Text style={styles.saveButton}>Save</Text>
                    )}
                </TouchableOpacity>
            </View>

            <ScrollView contentContainerStyle={styles.content}>
                <View style={styles.inputGroup}>
                    <Text style={styles.label}>Full Name</Text>
                    <TextInput
                        style={styles.input}
                        value={formData.name}
                        onChangeText={(text) => setFormData(prev => ({ ...prev, name: text }))}
                        placeholder="Enter your full name"
                    />
                </View>

                <View style={styles.inputGroup}>
                    <Text style={styles.label}>Bio</Text>
                    <TextInput
                        style={[styles.input, styles.textArea]}
                        value={formData.bio}
                        onChangeText={(text) => setFormData(prev => ({ ...prev, bio: text }))}
                        placeholder="Tell us about yourself"
                        multiline
                        numberOfLines={4}
                        textAlignVertical="top"
                    />
                </View>

                <View style={styles.inputGroup}>
                    <Text style={styles.label}>Skills (comma separated)</Text>
                    <TextInput
                        style={styles.input}
                        value={formData.skills}
                        onChangeText={(text) => setFormData(prev => ({ ...prev, skills: text }))}
                        placeholder="React, Node.js, Design..."
                    />
                </View>

                {user?.role === 'worker' && (
                    <View style={styles.inputGroup}>
                        <Text style={styles.label}>Hourly Rate ($)</Text>
                        <TextInput
                            style={styles.input}
                            value={formData.hourlyRate}
                            onChangeText={(text) => setFormData(prev => ({ ...prev, hourlyRate: text }))}
                            placeholder="50"
                            keyboardType="numeric"
                        />
                    </View>
                )}

                <View style={styles.inputGroup}>
                    <Text style={styles.label}>Location</Text>
                    <TextInput
                        style={styles.input}
                        value={formData.location}
                        onChangeText={(text) => setFormData(prev => ({ ...prev, location: text }))}
                        placeholder="City, Country"
                    />
                </View>

                <View style={styles.inputGroup}>
                    <Text style={styles.label}>Phone</Text>
                    <TextInput
                        style={styles.input}
                        value={formData.phone}
                        onChangeText={(text) => setFormData(prev => ({ ...prev, phone: text }))}
                        placeholder="+1 234 567 8900"
                        keyboardType="phone-pad"
                    />
                </View>
            </ScrollView>
        </KeyboardAvoidingView>
    );
}

