import React from 'react';
import { View, Text, StyleSheet, TouchableOpacity } from 'react-native';
import { Ionicons } from '@expo/vector-icons';

interface Transaction {
    id: string;
    type: 'credit' | 'debit';
    title: string;
    description: string;
    amount: number;
    date: string;
    status: 'completed' | 'pending' | 'failed';
}

interface TransactionItemProps {
    transaction: Transaction;
}

export function TransactionItem({ transaction }: TransactionItemProps) {
    const formatCurrency = (amount: number) => {
        return `$${Math.abs(amount).toFixed(2)}`;
    };

    const getIcon = () => {
        if (transaction.type === 'credit') {
            return <Ionicons name="arrow-down" size={20} color="#10B981" />;
        }
        return <Ionicons name="arrow-up" size={20} color="#EF4444" />;
    };

    const getStatusColor = () => {
        switch (transaction.status) {
            case 'completed':
                return '#10B981';
            case 'pending':
                return '#F59E0B';
            case 'failed':
                return '#EF4444';
        }
    };

    const formatDate = (dateString: string) => {
        const date = new Date(dateString);
        return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
    };

    return (
        <TouchableOpacity style={styles.container} activeOpacity={0.7}>
            <View style={[styles.iconContainer, { backgroundColor: transaction.type === 'credit' ? '#D1FAE5' : '#FEE2E2' }]}>
                {getIcon()}
            </View>

            <View style={styles.content}>
                <View style={styles.header}>
                    <Text style={styles.title} numberOfLines={1}>
                        {transaction.title}
                    </Text>
                    <View style={[styles.statusDot, { backgroundColor: getStatusColor() }]} />
                </View>
                <View style={styles.footer}>
                    <Text style={styles.description} numberOfLines={1}>
                        {transaction.description}
                    </Text>
                    <Text style={styles.date}>{formatDate(transaction.date)}</Text>
                </View>
            </View>

            <Text style={[styles.amount, transaction.type === 'credit' ? styles.credit : styles.debit]}>
                {transaction.type === 'credit' ? '+' : '-'}{formatCurrency(transaction.amount)}
            </Text>
        </TouchableOpacity>
    );
}

