    isWorker: boolean;
    onPress: () => void;
    onApply?: (gig: Gig) => void;
}

export function GigItem({ gig, isWorker, onPress, onApply }: GigItemProps) {
    const formatBudget = () => {
        if (gig.type === 'hourly') {
            return `$${gig.budget.min}-${gig.budget.max}/hr`;
        }
        return `$${gig.budget.min}-${gig.budget.max}`;
    };

    return (
        <TouchableOpacity style={styles.container} onPress={onPress} activeOpacity={0.7}>
            {/* Header */}
            <View style={styles.header}>
                <View style={styles.headerLeft}>
                    <View style={styles.employerIcon}>
                        <Ionicons name="business" size={20} color="#6366F1" />
                    </View>
                    <View>
                        <Text style={styles.employerName}>{gig.employerName}</Text>
                        <Text style={styles.location}>
                            {gig.isRemote ? 'Remote' : `${gig.location.city}, ${gig.location.country}`}
                        </Text>
                    </View>
                </View>
                <View style={[styles.typeBadge, gig.type === 'hourly' ? styles.hourlyBadge : styles.fixedBadge]}>
                    <Text style={styles.typeBadgeText}>
                        {gig.type === 'hourly' ? 'HOURLY' : 'FIXED'}
                    </Text>
                </View>
            </View>

            {/* Title & Description */}
            <Text style={styles.title}>{gig.title}</Text>
            <Text style={styles.description} numberOfLines={2}>
                {gig.description}
            </Text>

            {/* Skills */}
            <View style={styles.skillsRow}>
                {gig.skills.slice(0, 3).map((skill, index) => (
                    <View key={index} style={styles.skillChip}>
