import React from 'react';
import { View, Text, StyleSheet, TouchableOpacity, Modal, ScrollView } from 'react-native';
import { Ionicons } from '@expo/vector-icons';

interface Notification {
    id: string;
    type: 'message' | 'gig' | 'payment' | 'system';
    title: string;
    description: string;
    timestamp: string;
    read: boolean;
}

interface NotificationModalProps {
    visible: boolean;
    onClose: () => void;
}

const mockNotifications: Notification[] = [
    {
        id: '1',
        type: 'message',
        title: 'New Message',
        description: 'Jane Smith sent you a message about the project',
        timestamp: new Date(Date.now() - 300000).toISOString(),
        read: false,
    },
    {
        id: '2',
        type: 'gig',
        title: 'Gig Application',
        description: 'Your application for Web Development was accepted',
        timestamp: new Date(Date.now() - 3600000).toISOString(),
        read: false,
    },
    {
        id: '3',
        type: 'payment',
        title: 'Payment Received',
        description: 'You received $2,500 for Website Development',
        timestamp: new Date(Date.now() - 86400000).toISOString(),
        read: true,
    },
    {
        id: '4',
        type: 'system',
        title: 'Profile Updated',
        description: 'Your profile information has been updated successfully',
        timestamp: new Date(Date.now() - 172800000).toISOString(),
        read: true,
    },
];

export function NotificationModal({ visible, onClose }: NotificationModalProps) {
    const getIcon = (type: Notification['type']) => {
        switch (type) {
            case 'message':
                return { name: 'chatbubble' as const, color: '#6366F1' };
            case 'gig':
                return { name: 'briefcase' as const, color: '#10B981' };
            case 'payment':
                return { name: 'cash' as const, color: '#F59E0B' };
            case 'system':
                return { name: 'information-circle' as const, color: '#64748B' };
        }
    };

    const formatTime = (timestamp: string) => {
        const date = new Date(timestamp);
        const now = new Date();
        const diffMs = now.getTime() - date.getTime();
        const diffMins = Math.floor(diffMs / 60000);
        const diffHours = Math.floor(diffMins / 60);
        const diffDays = Math.floor(diffHours / 24);

        if (diffMins < 60) return `${diffMins}m ago`;
        if (diffHours < 24) return `${diffHours}h ago`;
        if (diffDays < 7) return `${diffDays}d ago`;
        return date.toLocaleDateString();
    };

    return (
        <Modal
            visible={visible}
            animationType="slide"
            transparent={true}
            onRequestClose={onClose}
        >
            <View style={styles.modalOverlay}>
                <View style={styles.modalContent}>
                    <View style={styles.header}>
                        <View>
                            <Text style={styles.headerTitle}>Notifications</Text>
                            <Text style={styles.headerSubtitle}>
                                {mockNotifications.filter(n => !n.read).length} unread
                            </Text>
                        </View>
                        <TouchableOpacity style={styles.closeButton} onPress={onClose}>
                            <Ionicons name="close" size={24} color="#64748B" />
                        </TouchableOpacity>
                    </View>

                    <ScrollView 
                        style={styles.scrollView}
                        showsVerticalScrollIndicator={false}
                        contentContainerStyle={styles.scrollContent}
                    >
                        {mockNotifications.map((notification) => {
                            const icon = getIcon(notification.type);
                            return (
                                <TouchableOpacity 
                                    key={notification.id}
                                    style={[
                                        styles.notificationItem,
                                        !notification.read && styles.unreadItem
                                    ]}
                                    activeOpacity={0.7}
                                >
                                    <View style={[styles.iconContainer, { backgroundColor: `${icon.color}15` }]}>
                                        <Ionicons name={icon.name} size={20} color={icon.color} />
                                    </View>
                                    <View style={styles.notificationContent}>
                                        <View style={styles.notificationHeader}>
                                            <Text style={styles.notificationTitle}>{notification.title}</Text>
                                            {!notification.read && <View style={styles.unreadDot} />}
                                        </View>
                                        <Text style={styles.notificationDescription} numberOfLines={2}>
                                            {notification.description}
                                        </Text>
                                        <Text style={styles.notificationTime}>
                                            {formatTime(notification.timestamp)}
                                        </Text>
                                    </View>
                                </TouchableOpacity>
                            );
                        })}
                    </ScrollView>

                    <View style={styles.footer}>
                        <TouchableOpacity style={styles.footerButton}>
                            <Text style={styles.footerButtonText}>Mark all as read</Text>
                        </TouchableOpacity>
                    </View>
                </View>
            </View>
        </Modal>
    );
}

