import React from 'react';
import { View, Text, StyleSheet } from 'react-native';
import { LinearGradient } from 'expo-linear-gradient';
import Svg, { Path, Circle, Line, Text as SvgText, Defs, LinearGradient as SvgLinearGradient, Stop } from 'react-native-svg';

interface LineChartData {
    x: string;
    y: number;
    label: string;
}

interface DataSeries {
    name: string;
    data: LineChartData[];
    color: string;
}

interface LineChartProps {
    data?: LineChartData[];
    series?: DataSeries[];
    config?: {
        height?: number;
        animated?: boolean;
        showGrid?: boolean;
        showLabels?: boolean;
    };
}

export function LineChart({ data, series, config = {} }: LineChartProps) {
    const {
        height = 200,
        showGrid = true,
        showLabels = true,
    } = config;

    const width = 320;
    const padding = { top: 20, right: 20, bottom: 30, left: 40 };
    const chartWidth = width - padding.left - padding.right;
    const chartHeight = height - padding.top - padding.bottom;

    // Support both single data array and multiple series
    const allSeries: DataSeries[] = series || (data ? [{ name: 'Data', data, color: '#6366F1' }] : []);
    const allDataPoints = allSeries.flatMap(s => s.data.map(d => d.y));

    const maxY = Math.max(...allDataPoints);
    const minY = Math.min(...allDataPoints);
    const yRange = maxY - minY;

    const getX = (index: number, dataLength: number) => {
        return padding.left + (index / (dataLength - 1)) * chartWidth;
    };

    const getY = (value: number) => {
        return padding.top + chartHeight - ((value - minY) / yRange) * chartHeight;
    };

    // Get x-axis labels from first series
    const xLabels = allSeries[0]?.data.map(d => d.x) || [];

    return (
        <View style={styles.container}>
            <Svg width={width} height={height}>
                {/* Grid Lines */}
                {showGrid && (
                    <>
                        {[0, 0.25, 0.5, 0.75, 1].map((percent, index) => (
                            <Line
                                key={`grid-${index}`}
                                x1={padding.left}
                                y1={padding.top + chartHeight * percent}
                                x2={padding.left + chartWidth}
                                y2={padding.top + chartHeight * percent}
                                stroke="#E2E8F0"
                                strokeWidth="1"
                                strokeDasharray="4,4"
                            />
                        ))}
                    </>
                )}

                {/* Y-axis labels */}
                {[0, 0.5, 1].map((percent, index) => {
                    const value = Math.round(maxY - (maxY - minY) * percent);
                    return (
                        <SvgText
                            key={`y-label-${index}`}
                            x={padding.left - 10}
                            y={padding.top + chartHeight * percent + 5}
                            fontSize="10"
                            fill="#64748B"
                            textAnchor="end"
                        >
                            ${value}
                        </SvgText>
                    );
                })}

                {/* Render each series */}
                {allSeries.map((s, seriesIndex) => {
                    const pathData = s.data
                        .map((point, index) => {
                            const x = getX(index, s.data.length);
                            const y = getY(point.y);
                            return index === 0 ? `M ${x} ${y}` : `L ${x} ${y}`;
                        })
                        .join(' ');

                    const areaPath = pathData +
                        ` L ${getX(s.data.length - 1, s.data.length)} ${padding.top + chartHeight}` +
                        ` L ${getX(0, s.data.length)} ${padding.top + chartHeight} Z`;

                    return (
                        <React.Fragment key={`series-${seriesIndex}`}>
                            {/* Gradient Area */}
                            <Path
                                d={areaPath}
                                fill={`url(#gradient-${seriesIndex})`}
                                opacity={0.15}
                            />

                            {/* Line */}
                            <Path
                                d={pathData}
                                stroke={s.color}
                                strokeWidth="3"
                                fill="none"
                                strokeLinecap="round"
                                strokeLinejoin="round"
                            />

                            {/* Data Points */}
                            {s.data.map((point, index) => (
                                <Circle
                                    key={`point-${seriesIndex}-${index}`}
                                    cx={getX(index, s.data.length)}
                                    cy={getY(point.y)}
                                    r="4"
                                    fill="#fff"
                                    stroke={s.color}
                                    strokeWidth="2.5"
                                />
                            ))}
                        </React.Fragment>
                    );
                })}

                {/* Define gradients for each series */}
                <Defs>
                    {allSeries.map((s, index) => (
                        <SvgLinearGradient
                            key={`gradient-${index}`}
                            id={`gradient-${index}`}
                            x1="0"
                            y1="0"
                            x2="0"
                            y2="1"
                        >
                            <Stop offset="0%" stopColor={s.color} stopOpacity="0.3" />
                            <Stop offset="100%" stopColor={s.color} stopOpacity="0" />
                        </SvgLinearGradient>
                    ))}
                </Defs>
            </Svg>

            {/* X-axis Labels */}
            {showLabels && (
                <View style={styles.xLabels}>
                    {xLabels.map((label, index) => (
                        <Text key={`label-${index}`} style={styles.xLabel}>
                            {label}
                        </Text>
                    ))}
                </View>
            )}

            {/* Legend */}
            {series && series.length > 1 && (
                <View style={styles.legend}>
                    {series.map((s, index) => (
                        <View key={`legend-${index}`} style={styles.legendItem}>
                            <View style={[styles.legendDot, { backgroundColor: s.color }]} />
                            <Text style={styles.legendText}>{s.name}</Text>
                        </View>
                    ))}
                </View>
            )}
        </View>
    );
}

