import React from 'react';
import { View, Text, StyleSheet, Dimensions } from 'react-native';
import { LinearGradient } from 'expo-linear-gradient';

interface CandlestickData {
    date: string;
    open: number;
    high: number;
    low: number;
    close: number;
}

interface CandlestickChartProps {
    data: CandlestickData[];
    config?: {
        height?: number;
        showGrid?: boolean;
        showLabels?: boolean;
        animated?: boolean;
        duration?: number;
    };
}

export function CandlestickChart({ data, config = {} }: CandlestickChartProps) {
    const {
        height = 220,
        showGrid = true,
        showLabels = true,
    } = config;

    const screenWidth = Dimensions.get('window').width - 80;
    const maxValue = Math.max(...data.map(d => d.high));
    const minValue = Math.min(...data.map(d => d.low));
    const range = maxValue - minValue;
    const candleWidth = (screenWidth / data.length) * 0.6;
    const candleSpacing = screenWidth / data.length;

    const getY = (value: number) => {
        return height - ((value - minValue) / range) * height;
    };

    return (
        <View style={styles.container}>
            <View style={[styles.chartArea, { height }]}>
                {/* Grid Lines */}
                {showGrid && (
                    <>
                        {[0, 0.25, 0.5, 0.75, 1].map((percent, index) => (
                            <View
                                key={index}
                                style={[
                                    styles.gridLine,
                                    { top: height * percent },
                                ]}
                            />
                        ))}
                    </>
                )}

                {/* Candlesticks */}
                {data.map((item, index) => {
                    const isGreen = item.close >= item.open;
                    const bodyTop = Math.min(item.open, item.close);
                    const bodyBottom = Math.max(item.open, item.close);
                    const bodyHeight = Math.abs(item.close - item.open);

                    return (
                        <View
                            key={index}
                            style={[
                                styles.candleContainer,
                                {
                                    left: index * candleSpacing + (candleSpacing - candleWidth) / 2,
                                    width: candleWidth,
                                },
                            ]}
                        >
                            {/* Wick (High to Low) */}
                            <View
                                style={[
                                    styles.wick,
                                    {
                                        top: getY(item.high),
                                        height: getY(item.low) - getY(item.high),
                                        backgroundColor: isGreen ? '#10B981' : '#EF4444',
                                    },
                                ]}
                            />

                            {/* Body (Open to Close) */}
                            <LinearGradient
                                colors={isGreen ? ['#10B981', '#059669'] : ['#EF4444', '#DC2626']}
                                style={[
                                    styles.body,
                                    {
                                        top: getY(bodyBottom),
                                        height: Math.max(bodyHeight === 0 ? 2 : (getY(bodyTop) - getY(bodyBottom)), 2),
                                    },
                                ]}
                            />
                        </View>
                    );
                })}
            </View>

            {/* Labels */}
            {showLabels && (
                <View style={styles.labelsContainer}>
                    {data.filter((_, i) => i % 2 === 0).map((item, index) => (
                        <Text key={index} style={styles.label}>
                            {item.date.split(' ')[1]}
                        </Text>
                    ))}
                </View>
            )}

            {/* Legend */}
            <View style={styles.legend}>
                <View style={styles.legendItem}>
                    <View style={[styles.legendDot, { backgroundColor: '#10B981' }]} />
                    <Text style={styles.legendText}>Increase</Text>
                </View>
                <View style={styles.legendItem}>
                    <View style={[styles.legendDot, { backgroundColor: '#EF4444' }]} />
                    <Text style={styles.legendText}>Decrease</Text>
                </View>
            </View>
        </View>
    );
}

