import { BrowserRouter } from 'react-router-dom'
import App from './App.jsx'
import './index.css'
import { SolanaProvider } from './components/SolanaProvider'
import ErrorBoundary from './components/ErrorBoundary.jsx'
// Buffer polyfill for browser runtime (must run before other libs that expect Buffer)
import { Buffer } from 'buffer';
if (!globalThis.Buffer) {
  globalThis.Buffer = Buffer;
}

// Global runtime error overlay to avoid blank white pages and surface errors
function showRuntimeErrorOverlay(message) {
  try {
    const existing = document.getElementById('__runtime_error_overlay');
    if (existing) {
      existing.style.display = 'block';
      existing.querySelector('pre') && (existing.querySelector('pre').textContent = message);
      return;
    }

    const div = document.createElement('div');
    div.id = '__runtime_error_overlay';
    div.style.position = 'fixed';
    div.style.left = '0';
    div.style.top = '0';
    div.style.width = '100%';
    div.style.height = '100%';
    div.style.background = 'rgba(0,0,0,0.85)';
    div.style.color = 'white';
    div.style.zIndex = '999999';
    div.style.padding = '32px';
    div.style.overflow = 'auto';
    div.innerHTML = `<div style="max-width:1200px;margin:40px auto;background:#111;padding:20px;border-radius:8px;box-shadow:0 10px 40px rgba(0,0,0,0.6);"><h2 style="margin:0 0 12px;font-size:20px;">Runtime Error</h2><pre style="white-space:pre-wrap;overflow-wrap:break-word;color:#ffb86b;">${message}</pre><p style="opacity:.8;margin-top:12px">Open the browser console for full stack trace.</p></div>`;
    document.body.appendChild(div);
  } catch (e) {
    // ignore overlay failures
    console.error('Failed to show error overlay', e);
  }
}

window.addEventListener('error', (ev) => {
  console.error('Uncaught error', ev.error || ev.message || ev);
  showRuntimeErrorOverlay(String(ev.error ? (ev.error.stack || ev.error.message) : (ev.message || ev)));
});
window.addEventListener('unhandledrejection', (ev) => {
  console.error('Unhandled rejection', ev.reason || ev);
  showRuntimeErrorOverlay(String(ev.reason ? (ev.reason.stack || ev.reason.message || ev.reason) : ev));
});

createRoot(document.getElementById('root')).render(

    <ErrorBoundary>
      <SolanaProvider>
        <BrowserRouter>
          <App />
        </BrowserRouter>
      </SolanaProvider>
    </ErrorBoundary>

)

import { Navigate, Route, Routes, useLocation } from 'react-router-dom';
import { useEffect, useState } from 'react';
import AuthenticatedLayout from './layouts/AuthenticatedLayout.jsx';
import PublicLayout from './layouts/PublicLayout.jsx';
import Contrast from './pages/Contrast.jsx';
import Dashboard from './pages/Dashboard.jsx';
import EmployerDashboard from './pages/EmployeHome.jsx';
import WorkerDashboard from './pages/home.jsx';
import Login from './pages/Login.jsx';
import Onboarding from './pages/Onboarding.jsx';
import MyGigs from './pages/MyGigs.jsx';
import Payment from './pages/Payment.jsx';
import PaymentEmployee from './pages/PaymentEmployee.jsx';
import PostJob from './pages/PostJob.jsx';
import Profile from './pages/Profile.jsx';
import SearchGigs from './pages/SearchGigs.jsx';
import WorkerContrast from './pages/WorkerContrast.jsx';
import Gamification from './pages/Gamification.jsx';
import Disputes from './pages/Disputes.jsx';
import Verification from './pages/Verification.jsx';
import CVGenerator from './pages/CVGenerator.jsx';
import SolanaHome from './pages/SolanaHome.jsx';

function App() {
  const location = useLocation();
  const [authState, setAuthState] = useState(() => {
    const token = localStorage.getItem('token');
    const savedUser = localStorage.getItem('user');
    let user = null;

    if (savedUser) {
      try {
        user = JSON.parse(savedUser);
        // Map backend role to frontend role if needed
        if (user.role === 'CLIENT') user.role = 'EMPLOYEE';
        if (user.role === 'WORKER') user.role = 'USER';
      } catch (e) {
        console.error("Failed to parse saved user", e);
      }
    }

    return {
      isAuthenticated: !!token && !!user,
      user
    };
  });

  // Re-check authentication on every route change
  useEffect(() => {
    const token = localStorage.getItem('token');
    const savedUser = localStorage.getItem('user');
    let user = null;

    if (savedUser) {
      try {
        user = JSON.parse(savedUser);
        // Map backend role to frontend role if needed
        if (user.role === 'CLIENT') user.role = 'EMPLOYEE';
        if (user.role === 'WORKER') user.role = 'USER';
      } catch (e) {
        console.error("Failed to parse saved user", e);
      }
    }

    setAuthState({
      isAuthenticated: !!token && !!user,
      user
    });
  }, [location.pathname]);

  const { isAuthenticated, user } = authState;

  return (
    <Routes>
      {/* Public Routes */}
      <Route element={<PublicLayout />}>
        <Route path="/" element={!isAuthenticated ? <Login /> : <Navigate to={user?.role === 'EMPLOYEE' ? '/employer-home' : '/home'} replace />} />
        <Route path="/login" element={!isAuthenticated ? <Login /> : <Navigate to={user?.role === 'EMPLOYEE' ? '/employer-home' : '/home'} replace />} />
        <Route path="/onboarding" element={<Onboarding />} />
      </Route>

      {/* Authenticated Routes */}
      <Route element={isAuthenticated ? <AuthenticatedLayout /> : <Navigate to="/login" replace />}>
        {/* Worker Routes */}
        <Route path="/home" element={<WorkerDashboard />} />
        <Route path="/solana" element={<SolanaHome />} />

        {/* Employer Routes */}
        <Route path="/employer-home" element={<EmployerDashboard />} />
        <Route path="/post-job" element={<PostJob />} />

        {/* Shared Routes */}
        <Route path="/my-gigs" element={<MyGigs />} />
        <Route path="/search-gigs" element={<SearchGigs />} />
        <Route path="/dashboard" element={<Dashboard />} />
        <Route path="/profile" element={<Profile />} />
        <Route path="/cv-generator" element={<CVGenerator />} />
        <Route path="/gamification" element={<Gamification />} />
        <Route path="/disputes" element={<Disputes />} />
        <Route path="/verification" element={<Verification />} />

        {/* Contracts - Role-specific */}
        <Route path="/contrast" element={user?.role === 'EMPLOYEE' ? <Contrast /> : <WorkerContrast />} />

        {/* Payments - Role-specific */}
        <Route path="/payment" element={user?.role === 'EMPLOYEE' ? <Payment /> : <PaymentEmployee />} />
      </Route>

      {/* Catch all */}
      <Route path="*" element={<Navigate to={isAuthenticated ? (user?.role === 'EMPLOYEE' ? '/employer-home' : '/home') : '/'} replace />} />
    </Routes>
  );
}

export default App;

