        phone: '',
        linkedin: '',
        skills: [],
        education: [{ degree: '', institution: '', year: '' }],
        projects: [{ title: '', description: '' }],
        experience: [{ role: '', company: '', duration: '', description: '' }]
    });

    const [skillInput, setSkillInput] = useState('');

    const handleInputChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const addSkill = () => {
        if (skillInput.trim() && formData.skills.length < 15) {
            setFormData({ ...formData, skills: [...formData.skills, skillInput.trim()] });
            setSkillInput('');
        }
    };

    const removeSkill = (index) => {
        setFormData({ ...formData, skills: formData.skills.filter((_, i) => i !== index) });
    };

    const updateEducation = (index, field, value) => {
        const newEducation = [...formData.education];
        newEducation[index][field] = value;
        setFormData({ ...formData, education: newEducation });
    };

    const addEducation = () => {
        if (formData.education.length < 3) {
            setFormData({ ...formData, education: [...formData.education, { degree: '', institution: '', year: '' }] });
        }
    };

    const removeEducation = (index) => {
        if (formData.education.length > 1) {
            setFormData({ ...formData, education: formData.education.filter((_, i) => i !== index) });
        }
    };

    const updateProject = (index, field, value) => {
        const newProjects = [...formData.projects];
        newProjects[index][field] = value;
        setFormData({ ...formData, projects: newProjects });
    };

    const addProject = () => {
        if (formData.projects.length < 5) {
            setFormData({ ...formData, projects: [...formData.projects, { title: '', description: '' }] });
        }
    };

    const removeProject = (index) => {
        if (formData.projects.length > 1) {
            setFormData({ ...formData, projects: formData.projects.filter((_, i) => i !== index) });
        }
    };

    const updateExperience = (index, field, value) => {
        const newExperience = [...formData.experience];
        newExperience[index][field] = value;
        setFormData({ ...formData, experience: newExperience });
    };

    const addExperience = () => {
        if (formData.experience.length < 5) {
            setFormData({ ...formData, experience: [...formData.experience, { role: '', company: '', duration: '', description: '' }] });
        }
    };

    const removeExperience = (index) => {
        setFormData({ ...formData, experience: formData.experience.filter((_, i) => i !== index) });
    };

    const validateForm = () => {
        if (!formData.name || !formData.email || !formData.phone) {
            setError('Please fill in all required fields (Name, Email, Phone)');
            return false;
        }
        if (formData.skills.length === 0) {
            setError('Please add at least one skill');
            return false;
        }
        if (formData.linkedin && !formData.linkedin.includes('linkedin.com')) {
            setError('Please enter a valid LinkedIn URL');
            return false;
        }
        setError('');
        return true;
    };

    const handleGenerateCV = async () => {
        if (!validateForm()) return;

        setLoading(true);
        setError('');

        try {
            const response = await api.post('/cv/generate', {
                ...formData,
                useAI
            }, { responseType: 'blob' });

            // Create download link
            const url = window.URL.createObjectURL(new Blob([response.data]));
            const link = document.createElement('a');
            link.href = url;
            link.setAttribute('download', `${formData.name.replace(/\s+/g, '_')}_CV.pdf`);
            document.body.appendChild(link);
            link.click();
            link.remove();
            window.URL.revokeObjectURL(url);

            setCurrentStep(4); // Success step
        } catch (err) {
            console.error('CV Generation Error:', err);
            setError(err.message || 'Failed to generate CV. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    const steps = [
        { number: 1, title: 'Personal Info', icon: User },
        { number: 2, title: 'Skills & Education', icon: GraduationCap },
        { number: 3, title: 'Projects & Experience', icon: Briefcase },
        { number: 4, title: 'Generate', icon: Sparkles }
    ];

    return (
        <div className="min-h-screen bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900 text-white">
            {/* Header */}
            <header className="bg-white/5 backdrop-blur-xl border-b border-white/10 sticky top-0 z-50">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-4">
                            <button onClick={() => navigate(-1)} className="p-2 hover:bg-white/10 rounded-lg transition-colors">
                                <ArrowLeft className="w-5 h-5" />
                            </button>
                            <div>
                                <h1 className="text-2xl font-black flex items-center gap-2">
                                    <Sparkles className="w-6 h-6 text-blue-400" />
                                    AI CV Generator
                                </h1>
                                <p className="text-sm text-slate-400">Create a professional CV in minutes</p>
                            </div>
                        </div>
                        <button onClick={() => setIsMobileOpen(!isMobileOpen)} className="lg:hidden p-2 hover:bg-white/10 rounded-lg">
                            <Menu className="w-5 h-5" />
                        </button>
                    </div>
                </div>
            </header>

            {/* Progress Steps */}
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
                <div className="flex items-center justify-between mb-8">
                    {steps.map((step, index) => (
                        <div key={step.number} className="flex items-center flex-1">
                            <div className="flex flex-col items-center">
                                <div className={`w-12 h-12 rounded-full flex items-center justify-center transition-all ${
                                    currentStep >= step.number 
                                        ? 'bg-blue-500 text-white' 
                                        : 'bg-white/10 text-slate-400'
                                }`}>
                                    <step.icon className="w-6 h-6" />
                                </div>
                                <span className="text-xs mt-2 text-slate-400">{step.title}</span>
                            </div>
                            {index < steps.length - 1 && (
                                <div className={`flex-1 h-1 mx-4 rounded-full transition-all ${
                                    currentStep > step.number ? 'bg-blue-500' : 'bg-white/10'
                                }`}></div>
                            )}
                        </div>
                    ))}
                </div>

                {/* Error Message */}
                {error && (
                    <div className="mb-6 p-4 bg-red-500/10 border border-red-500/20 rounded-xl text-red-400 flex items-center gap-2">
                        <X className="w-5 h-5" />
                        {error}
                    </div>
                )}

                {/* Form Content */}
                <div className="bg-white/5 backdrop-blur-xl rounded-2xl border border-white/10 p-8">
                    {/* Step 1: Personal Info */}
                    {currentStep === 1 && (
                        <div className="space-y-6">
                            <h2 className="text-2xl font-bold mb-6">Personal Information</h2>

                            <div className="grid md:grid-cols-2 gap-6">
                                <div>
                                    <label className="block text-sm font-medium text-slate-300 mb-2">
                                        Full Name <span className="text-red-400">*</span>
                                    </label>
                                    <input
                                        type="text"
                                        name="name"
                                        value={formData.name}
                                        onChange={handleInputChange}
                                        className="w-full px-4 py-3 bg-white/5 border border-white/10 rounded-xl text-white placeholder-slate-500 focus:outline-none focus:border-blue-500 transition-colors"
                                        placeholder="John Doe"
                                    />
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-slate-300 mb-2">
                                        Email <span className="text-red-400">*</span>
                                    </label>
                                    <div className="relative">
                                        <Mail className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-500" />
                                        <input
                                            type="email"
                                            name="email"
                                            value={formData.email}
                                            onChange={handleInputChange}
                                            className="w-full pl-12 pr-4 py-3 bg-white/5 border border-white/10 rounded-xl text-white placeholder-slate-500 focus:outline-none focus:border-blue-500 transition-colors"
                                            placeholder="john@example.com"
                                        />
                                    </div>
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-slate-300 mb-2">
                                        Phone <span className="text-red-400">*</span>
                                    </label>
                                    <div className="relative">
                                        <Phone className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-500" />
                                        <input
                                            type="tel"
                                            name="phone"
                                            value={formData.phone}
                                            onChange={handleInputChange}
                                            className="w-full pl-12 pr-4 py-3 bg-white/5 border border-white/10 rounded-xl text-white placeholder-slate-500 focus:outline-none focus:border-blue-500 transition-colors"
                                            placeholder="+1 234 567 8900"
                                        />
                                    </div>
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-slate-300 mb-2">
                                        LinkedIn URL
                                    </label>
                                    <div className="relative">
                                        <Linkedin className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-500" />
                                        <input
                                            type="url"
                                            name="linkedin"
                                            value={formData.linkedin}
                                            onChange={handleInputChange}
                                            className="w-full pl-12 pr-4 py-3 bg-white/5 border border-white/10 rounded-xl text-white placeholder-slate-500 focus:outline-none focus:border-blue-500 transition-colors"
                                            placeholder="https://linkedin.com/in/johndoe"
                                        />
                                    </div>
                                </div>
                            </div>

                            <div className="flex justify-end pt-6">
                                <button
                                    onClick={() => setCurrentStep(2)}
                                    className="px-8 py-3 bg-blue-500 hover:bg-blue-600 rounded-xl font-bold transition-colors flex items-center gap-2"
                                >
                                    Next Step <ArrowLeft className="w-5 h-5 rotate-180" />
                                </button>
                            </div>
                        </div>
                    )}

                    {/* Step 2: Skills & Education */}
                    {currentStep === 2 && (
                        <div className="space-y-8">
                            <div>
                                <h2 className="text-2xl font-bold mb-6">Skills & Education</h2>

                                {/* Skills */}
                                <div className="mb-8">
                                    <label className="block text-sm font-medium text-slate-300 mb-2">
                                        Skills <span className="text-red-400">*</span> <span className="text-xs text-slate-500">(Max 15)</span>
                                    </label>
                                    <div className="flex gap-2 mb-3">
                                        <input
                                            type="text"
                                            value={skillInput}
                                            onChange={(e) => setSkillInput(e.target.value)}
                                            onKeyPress={(e) => e.key === 'Enter' && (e.preventDefault(), addSkill())}
                                            className="flex-1 px-4 py-3 bg-white/5 border border-white/10 rounded-xl text-white placeholder-slate-500 focus:outline-none focus:border-blue-500"
                                            placeholder="e.g., React, Python, Node.js"
                                        />
                                        <button
                                            onClick={addSkill}
                                            className="px-6 py-3 bg-blue-500/20 hover:bg-blue-500/30 border border-blue-500/50 rounded-xl font-bold transition-colors flex items-center gap-2"
                                        >
                                            <Plus className="w-5 h-5" /> Add
                                        </button>
                                    </div>
                                    <div className="flex flex-wrap gap-2">
                                        {formData.skills.map((skill, index) => (
                                            <span key={index} className="px-3 py-1.5 bg-blue-500/20 border border-blue-500/50 rounded-lg text-sm flex items-center gap-2">
                                                {skill}
                                                <button onClick={() => removeSkill(index)} className="hover:text-red-400">
                                                    <X className="w-4 h-4" />
                                                </button>
                                            </span>
                                        ))}
                                    </div>
                                </div>

                                {/* Education */}
                                <div>
                                    <div className="flex justify-between items-center mb-4">
                                        <label className="text-sm font-medium text-slate-300">Education</label>
                                        <button onClick={addEducation} className="text-sm text-blue-400 hover:text-blue-300 flex items-center gap-1">
                                            <Plus className="w-4 h-4" /> Add Education
                                        </button>
                                    </div>
                                    <div className="space-y-4">
                                        {formData.education.map((edu, index) => (
                                            <div key={index} className="p-4 bg-white/5 border border-white/10 rounded-xl space-y-3">
                                                <div className="flex justify-between items-start">
                                                    <span className="text-sm text-slate-400">Education #{index + 1}</span>
                                                    {formData.education.length > 1 && (
                                                        <button onClick={() => removeEducation(index)} className="text-red-400 hover:text-red-300">
                                                            <X className="w-4 h-4" />
                                                        </button>
                                                    )}
                                                </div>
                                                <input
                                                    type="text"
                                                    value={edu.degree}
                                                    onChange={(e) => updateEducation(index, 'degree', e.target.value)}
                                                    className="w-full px-4 py-2 bg-white/5 border border-white/10 rounded-lg text-white placeholder-slate-500 focus:outline-none focus:border-blue-500"
                                                    placeholder="Degree (e.g., B.Tech in Computer Science)"
                                                />
                                                <input
                                                    type="text"
                                                    value={edu.institution}
                                                    onChange={(e) => updateEducation(index, 'institution', e.target.value)}
                                                    className="w-full px-4 py-2 bg-white/5 border border-white/10 rounded-lg text-white placeholder-slate-500 focus:outline-none focus:border-blue-500"
                                                    placeholder="Institution Name"
                                                />
                                                <input
                                                    type="text"
                                                    value={edu.year}
                                                    onChange={(e) => updateEducation(index, 'year', e.target.value)}
                                                    className="w-full px-4 py-2 bg-white/5 border border-white/10 rounded-lg text-white placeholder-slate-500 focus:outline-none focus:border-blue-500"
                                                    placeholder="Year (e.g., 2020-2024)"
                                                />
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            </div>

                            <div className="flex justify-between pt-6">
                                <button
                                    onClick={() => setCurrentStep(1)}
                                    className="px-8 py-3 bg-white/10 hover:bg-white/20 rounded-xl font-bold transition-colors"
                                >
                                    Previous
                                </button>
                                <button
                                    onClick={() => setCurrentStep(3)}
                                    className="px-8 py-3 bg-blue-500 hover:bg-blue-600 rounded-xl font-bold transition-colors flex items-center gap-2"
                                >
                                    Next Step <ArrowLeft className="w-5 h-5 rotate-180" />
                                </button>
                            </div>
                        </div>
                    )}

                    {/* Step 3: Projects & Experience */}
                    {currentStep === 3 && (
                        <div className="space-y-8">
                            <h2 className="text-2xl font-bold mb-6">Projects & Experience</h2>

                            {/* Projects */}
                            <div>
                                <div className="flex justify-between items-center mb-4">
                                    <label className="text-sm font-medium text-slate-300">Projects</label>
                                    <button onClick={addProject} className="text-sm text-blue-400 hover:text-blue-300 flex items-center gap-1">
                                        <Plus className="w-4 h-4" /> Add Project
                                    </button>
                                </div>
                                <div className="space-y-4">
                                    {formData.projects.map((project, index) => (
                                        <div key={index} className="p-4 bg-white/5 border border-white/10 rounded-xl space-y-3">
                                            <div className="flex justify-between items-start">
                                                <span className="text-sm text-slate-400">Project #{index + 1}</span>
                                                {formData.projects.length > 1 && (
                                                    <button onClick={() => removeProject(index)} className="text-red-400 hover:text-red-300">
                                                        <X className="w-4 h-4" />
                                                    </button>
                                                )}
                                            </div>
                                            <input
                                                type="text"
                                                value={project.title}
                                                onChange={(e) => updateProject(index, 'title', e.target.value)}
                                                className="w-full px-4 py-2 bg-white/5 border border-white/10 rounded-lg text-white placeholder-slate-500 focus:outline-none focus:border-blue-500"
                                                placeholder="Project Title"
                                            />
                                            <textarea
                                                value={project.description}
                                                onChange={(e) => updateProject(index, 'description', e.target.value)}
                                                className="w-full px-4 py-2 bg-white/5 border border-white/10 rounded-lg text-white placeholder-slate-500 focus:outline-none focus:border-blue-500 resize-none"
                                                rows={3}
                                                placeholder="Describe the project (AI will polish this if enabled)"
                                                maxLength={500}
                                            />
                                            <p className="text-xs text-slate-500 text-right">{project.description.length}/500</p>
                                        </div>
                                    ))}
                                </div>
                            </div>

                            {/* Experience */}
                            <div>
                                <div className="flex justify-between items-center mb-4">
                                    <label className="text-sm font-medium text-slate-300">Work Experience (Optional)</label>
                                    <button onClick={addExperience} className="text-sm text-blue-400 hover:text-blue-300 flex items-center gap-1">
                                        <Plus className="w-4 h-4" /> Add Experience
                                    </button>
                                </div>
                                <div className="space-y-4">
                                    {formData.experience.map((exp, index) => (
                                        <div key={index} className="p-4 bg-white/5 border border-white/10 rounded-xl space-y-3">
                                            <div className="flex justify-between items-start">
                                                <span className="text-sm text-slate-400">Experience #{index + 1}</span>
                                                <button onClick={() => removeExperience(index)} className="text-red-400 hover:text-red-300">
                                                    <X className="w-4 h-4" />
                                                </button>
                                            </div>
                                            <input
                                                type="text"
                                                value={exp.role}
                                                onChange={(e) => updateExperience(index, 'role', e.target.value)}
                                                className="w-full px-4 py-2 bg-white/5 border border-white/10 rounded-lg text-white placeholder-slate-500 focus:outline-none focus:border-blue-500"
                                                placeholder="Job Role"
                                            />
                                            <input
                                                type="text"
                                                value={exp.company}
                                                onChange={(e) => updateExperience(index, 'company', e.target.value)}
                                                className="w-full px-4 py-2 bg-white/5 border border-white/10 rounded-lg text-white placeholder-slate-500 focus:outline-none focus:border-blue-500"
                                                placeholder="Company Name"
                                            />
                                            <input
                                                type="text"
                                                value={exp.duration}
                                                onChange={(e) => updateExperience(index, 'duration', e.target.value)}
                                                className="w-full px-4 py-2 bg-white/5 border border-white/10 rounded-lg text-white placeholder-slate-500 focus:outline-none focus:border-blue-500"
                                                placeholder="Duration (e.g., Jan 2023 - Present)"
                                            />
                                            <textarea
                                                value={exp.description}
                                                onChange={(e) => updateExperience(index, 'description', e.target.value)}
                                                className="w-full px-4 py-2 bg-white/5 border border-white/10 rounded-lg text-white placeholder-slate-500 focus:outline-none focus:border-blue-500 resize-none"
                                                rows={3}
                                                placeholder="Job description and achievements"
                                                maxLength={500}
                                            />
                                        </div>
                                    ))}
                                </div>
                            </div>

                            {/* AI Toggle */}
                            <div className="p-6 bg-gradient-to-r from-purple-500/10 to-blue-500/10 border border-purple-500/20 rounded-xl">
                                <div className="flex items-center justify-between">
                                    <div className="flex items-center gap-3">
                                        <Zap className="w-6 h-6 text-yellow-400" />
                                        <div>
                                            <h3 className="font-bold">AI Enhancement</h3>
                                            <p className="text-sm text-slate-400">Let AI polish your content professionally</p>
                                        </div>
                                    </div>
                                    <button
                                        onClick={() => setUseAI(!useAI)}
                                        className={`relative w-14 h-7 rounded-full transition-colors ${useAI ? 'bg-blue-500' : 'bg-white/20'}`}
                                    >
                                        <div className={`absolute top-1 w-5 h-5 bg-white rounded-full transition-transform ${useAI ? 'translate-x-8' : 'translate-x-1'}`}></div>
                                    </button>
                                </div>
                            </div>

                            <div className="flex justify-between pt-6">
                                <button
                                    onClick={() => setCurrentStep(2)}
                                    className="px-8 py-3 bg-white/10 hover:bg-white/20 rounded-xl font-bold transition-colors"
                                >
                                    Previous
                                </button>
                                <button
                                    onClick={handleGenerateCV}
                                    disabled={loading}
                                    className="px-8 py-3 bg-gradient-to-r from-blue-500 to-purple-600 hover:from-blue-600 hover:to-purple-700 rounded-xl font-bold transition-colors flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                                >
                                    {loading ? (
                                        <>
                                            <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                                            Generating...
                                        </>
                                    ) : (
                                        <>
                                            <Download className="w-5 h-5" /> Generate CV
                                        </>
                                    )}
                                </button>
                            </div>
                        </div>
                    )}

                    {/* Step 4: Success */}
                    {currentStep === 4 && (
                        <div className="text-center py-12">
                            <div className="w-20 h-20 bg-green-500/20 rounded-full flex items-center justify-center mx-auto mb-6">
                                <FileText className="w-10 h-10 text-green-400" />
                            </div>
                            <h2 className="text-3xl font-bold mb-4">CV Generated Successfully! 🎉</h2>
                            <p className="text-slate-400 mb-8">Your professional CV has been downloaded</p>
                            <div className="flex gap-4 justify-center">
                                <button
                                    onClick={() => { setCurrentStep(1); setFormData({ name: '', email: '', phone: '', linkedin: '', skills: [], education: [{ degree: '', institution: '', year: '' }], projects: [{ title: '', description: '' }], experience: [{ role: '', company: '', duration: '', description: '' }] }); }}
                                    className="px-6 py-3 bg-white/10 hover:bg-white/20 rounded-xl font-bold transition-colors"
                                >
                                    Create Another CV
                                </button>
                                <button
                                    onClick={() => navigate('/home')}
                                    className="px-6 py-3 bg-blue-500 hover:bg-blue-600 rounded-xl font-bold transition-colors"
                                >
                                    Back to Dashboard
                                </button>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

