import { useState, useEffect } from 'react';
import { Search, MapPin, DollarSign, Briefcase, Star, Heart, Filter } from 'lucide-react';
import { api } from '../api/client';

export default function SearchGigs() {
    const [jobs, setJobs] = useState([]);
    const [loading, setLoading] = useState(true);
    const [filters, setFilters] = useState({
        search: '',
        location: '',
        minBudget: '',
        maxBudget: ''
    });
    const [user, setUser] = useState(null);

    useEffect(() => {
        const storedUser = localStorage.getItem('user');
        if (storedUser) {
            setUser(JSON.parse(storedUser));
        }
    }, []);

    useEffect(() => {
        fetchOpenGigs();
    }, []);

    const fetchOpenGigs = async () => {
        try {
            setLoading(true);
            // Only fetch OPEN gigs for discovery
            const response = await api.get('/jobs?status=OPEN');
            const data = Array.isArray(response) ? response : response.data || [];
            setJobs(data);
        } catch (error) {
            console.error('Failed to fetch gigs:', error);
            setJobs([]);
        } finally {
            setLoading(false);
        }
    };

    const filteredJobs = jobs.filter(job => {
        const matchesSearch = !filters.search || 
            job.title?.toLowerCase().includes(filters.search.toLowerCase()) ||
