import { ArrowRight, Check } from 'lucide-react';
import { useEffect, useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import * as THREE from 'three';

/**
 * --- LIQUID ETHER BACKGROUND ---
 * WebGL Fluid Simulation adapted to run with npm dependencies.
 */
const LiquidEther = ({
    mouseForce = 20,
    cursorSize = 100,
    dt = 0.014,
    colors = ['#5227FF', '#FF9FFC', '#B19EEF'],
}) => {
    const mountRef = useRef(null);
    const webglRef = useRef(null);

    // FIX: Define rafRef so it can be used in the animation loop
    const rafRef = useRef(null);
    const [isWebglSupported, setIsWebglSupported] = useState(true);

    useEffect(() => {
        if (!mountRef.current) return;
        if (!isWebglSupported) return;

        try {
            function makePaletteTexture(stops) {
                let arr = (Array.isArray(stops) && stops.length > 0) ? (stops.length === 1 ? [stops[0], stops[0]] : stops) : ['#ffffff', '#ffffff'];
                const w = arr.length;
                const data = new Uint8Array(w * 4);
                for (let i = 0; i < w; i++) {
                    const c = new THREE.Color(arr[i]);
                    data[i * 4 + 0] = Math.round(c.r * 255);
                    data[i * 4 + 1] = Math.round(c.g * 255);
                    data[i * 4 + 2] = Math.round(c.b * 255);
                    data[i * 4 + 3] = 255;
                }
                const tex = new THREE.DataTexture(data, w, 1, THREE.RGBAFormat);
                tex.magFilter = THREE.LinearFilter;
                tex.minFilter = THREE.LinearFilter;
                tex.wrapS = THREE.ClampToEdgeWrapping;
                tex.wrapT = THREE.ClampToEdgeWrapping;
                tex.generateMipmaps = false;
                tex.needsUpdate = true;
                return tex;
            }

            const paletteTex = makePaletteTexture(colors);
            const bgVec4 = new THREE.Vector4(0, 0, 0, 0);

            class CommonClass {
                constructor() { this.width = 0; this.height = 0; this.aspect = 1; this.pixelRatio = 1; this.time = 0; this.delta = 0; }
                init(container) {
                    this.container = container;
                    this.pixelRatio = Math.min(window.devicePixelRatio || 1, 2);
                    this.resize();
                    try {
                        this.renderer = new THREE.WebGLRenderer({ antialias: false, alpha: true, powerPreference: "high-performance" });
                    } catch {
                        throw new Error("WebGL not supported");
                    }
                    this.renderer.autoClear = false;
                    this.renderer.setClearColor(new THREE.Color(0x000000), 0);
                    this.renderer.setPixelRatio(this.pixelRatio);
                    this.renderer.setSize(this.width, this.height);
                    this.renderer.domElement.style.width = '100%';
                    this.renderer.domElement.style.height = '100%';
                    this.renderer.domElement.style.display = 'block';
                    this.clock = new THREE.Clock();
                    this.clock.start();
                }
                resize() {
                    if (!this.container) return;
                    const rect = this.container.getBoundingClientRect();
                    this.width = Math.max(1, Math.floor(rect.width));
                    this.height = Math.max(1, Math.floor(rect.height));
                    this.aspect = this.width / this.height;
                    if (this.renderer) this.renderer.setSize(this.width, this.height, false);
                }
                update() { this.delta = this.clock.getDelta(); this.time += this.delta; }
                dispose() { if (this.renderer) this.renderer.dispose(); }
            }
            const Common = new CommonClass();

            class MouseClass {
                constructor() {
                    this.coords = new THREE.Vector2(-1, -1);
                    this.coords_old = new THREE.Vector2(-1, -1);
                    this.diff = new THREE.Vector2();
                }
                init() {
                    window.addEventListener('mousemove', this.onMove.bind(this));
                    window.addEventListener('touchstart', this.onTouch.bind(this), { passive: true });
                    window.addEventListener('touchmove', this.onTouch.bind(this), { passive: true });
                }
                setCoords(x, y) {
                    if (!Common.container) return;
                    const rect = Common.container.getBoundingClientRect();
                    const nx = (x - rect.left) / rect.width;
                    const ny = (y - rect.top) / rect.height;
                    this.coords.set(nx * 2 - 1, -(ny * 2 - 1));
                }
                onMove(e) { this.setCoords(e.clientX, e.clientY); }
                onTouch(e) { if (e.touches.length > 0) this.setCoords(e.touches[0].clientX, e.touches[0].clientY); }
                update() {
                    this.diff.subVectors(this.coords, this.coords_old);
                    this.coords_old.copy(this.coords);
                    if (this.coords_old.x === 0 && this.coords_old.y === 0) this.diff.set(0, 0);
                }
                dispose() {
                    window.removeEventListener('mousemove', this.onMove);
                    window.removeEventListener('touchstart', this.onTouch);
                    window.removeEventListener('touchmove', this.onTouch);
                }
            }
            const Mouse = new MouseClass();

            class ShaderPass {
                constructor(props) {
                    this.props = props || {};
                    this.uniforms = this.props.material?.uniforms;
                    this.scene = new THREE.Scene();
                    this.camera = new THREE.Camera();
                    if (this.uniforms) {
                        this.material = new THREE.RawShaderMaterial(this.props.material);
                        this.plane = new THREE.Mesh(new THREE.PlaneGeometry(2.0, 2.0), this.material);
                        this.scene.add(this.plane);
                    }
                }
                update() {
                    Common.renderer.setRenderTarget(this.props.output || null);
                    Common.renderer.render(this.scene, this.camera);
                    Common.renderer.setRenderTarget(null);
                }
            }

            const face_vert = `attribute vec3 position;uniform vec2 boundarySpace;varying vec2 uv;void main(){vec3 pos=position;pos.xy*=(1.0-boundarySpace*2.0);uv=vec2(0.5)+(pos.xy)*0.5;gl_Position=vec4(pos,1.0);}`;
            const mouse_vert = `attribute vec3 position;attribute vec2 uv;uniform vec2 center;uniform vec2 scale;uniform vec2 px;varying vec2 vUv;void main(){vec2 pos=position.xy*scale*2.0*px+center;vUv=uv;gl_Position=vec4(pos,0.0,1.0);}`;
            const advection_frag = `precision highp float;uniform sampler2D velocity;uniform float dt;uniform bool isBFECC;uniform vec2 fboSize;varying vec2 uv;void main(){vec2 ratio=max(fboSize.x,fboSize.y)/fboSize;if(!isBFECC){vec2 vel=texture2D(velocity,uv).xy;gl_FragColor=vec4(texture2D(velocity,uv-vel*dt*ratio).xy,0.0,0.0);}else{vec2 vel=texture2D(velocity,uv).xy;vec2 spot=uv-vel*dt*ratio;vec2 vel2=texture2D(velocity,spot).xy;vec2 spot2=spot+vel2*dt*ratio;vec2 error=spot2-uv;vec2 spot3=uv-error/2.0;vec2 vel3=texture2D(velocity,spot3).xy;gl_FragColor=vec4(texture2D(velocity,spot3-vel3*dt*ratio).xy,0.0,0.0);}}`;
            const color_frag = `precision highp float;uniform sampler2D velocity;uniform sampler2D palette;uniform vec4 bgColor;varying vec2 uv;void main(){vec2 vel=texture2D(velocity,uv).xy;float len=clamp(length(vel),0.0,1.0);vec3 c=texture2D(palette,vec2(len,0.5)).rgb;gl_FragColor=vec4(mix(bgColor.rgb,c,len),mix(bgColor.a,1.0,len));}`;
            const divergence_frag = `precision highp float;uniform sampler2D velocity;uniform float dt;uniform vec2 px;varying vec2 uv;void main(){float x0=texture2D(velocity,uv-vec2(px.x,0.0)).x;float x1=texture2D(velocity,uv+vec2(px.x,0.0)).x;float y0=texture2D(velocity,uv-vec2(0.0,px.y)).y;float y1=texture2D(velocity,uv+vec2(0.0,px.y)).y;gl_FragColor=vec4((x1-x0+y1-y0)/2.0/dt);}`;
            const force_frag = `precision highp float;uniform vec2 force;varying vec2 vUv;void main(){vec2 c=(vUv-0.5)*2.0;float d=1.0-min(length(c),1.0);d*=d;gl_FragColor=vec4(force*d,0.0,1.0);}`;
            const poisson_frag = `precision highp float;uniform sampler2D pressure;uniform sampler2D divergence;uniform vec2 px;varying vec2 uv;void main(){float p0=texture2D(pressure,uv+vec2(px.x*2.0,0.0)).r;float p1=texture2D(pressure,uv-vec2(px.x*2.0,0.0)).r;float p2=texture2D(pressure,uv+vec2(0.0,px.y*2.0)).r;float p3=texture2D(pressure,uv-vec2(0.0,px.y*2.0)).r;float div=texture2D(divergence,uv).r;gl_FragColor=vec4((p0+p1+p2+p3)/4.0-div);}`;
            const pressure_frag = `precision highp float;uniform sampler2D pressure;uniform sampler2D velocity;uniform vec2 px;uniform float dt;varying vec2 uv;void main(){float p0=texture2D(pressure,uv+vec2(px.x,0.0)).r;float p1=texture2D(pressure,uv-vec2(px.x,0.0)).r;float p2=texture2D(pressure,uv+vec2(0.0,px.y)).r;float p3=texture2D(pressure,uv-vec2(0.0,px.y)).r;vec2 v=texture2D(velocity,uv).xy;vec2 grad=vec2(p0-p1,p2-p3)*0.5;gl_FragColor=vec4(v-grad*dt,0.0,1.0);}`;

            class Simulation {
                constructor(opts) {
                    this.opts = opts;
                    this.fbos = {};
                    this.cellScale = new THREE.Vector2();
                    this.fboSize = new THREE.Vector2();
                    this.init();
                }
                init() {
                    const width = Math.max(1, Math.round(0.5 * Common.width));
                    const height = Math.max(1, Math.round(0.5 * Common.height));
                    this.cellScale.set(1 / width, 1 / height);
                    this.fboSize.set(width, height);
                    const type = THREE.HalfFloatType;
                    const createFbo = () => new THREE.WebGLRenderTarget(width, height, { type, minFilter: THREE.LinearFilter, magFilter: THREE.LinearFilter });
                    this.fbos = { vel_0: createFbo(), vel_1: createFbo(), div: createFbo(), pressure_0: createFbo(), pressure_1: createFbo() };

                    this.advection = new ShaderPass({ material: { vertexShader: face_vert, fragmentShader: advection_frag, uniforms: { boundarySpace: { value: this.cellScale }, px: { value: this.cellScale }, fboSize: { value: this.fboSize }, velocity: { value: this.fbos.vel_0.texture }, dt: { value: this.opts.dt }, isBFECC: { value: true } } }, output: this.fbos.vel_1 });
                    this.force = new ShaderPass({ output: this.fbos.vel_1 });
                    this.force.scene.add(new THREE.Mesh(new THREE.PlaneGeometry(1, 1), new THREE.RawShaderMaterial({ vertexShader: mouse_vert, fragmentShader: force_frag, blending: THREE.AdditiveBlending, depthWrite: false, uniforms: { px: { value: this.cellScale }, force: { value: new THREE.Vector2() }, center: { value: new THREE.Vector2() }, scale: { value: new THREE.Vector2(cursorSize, cursorSize) } } })));
                    this.divergence = new ShaderPass({ material: { vertexShader: face_vert, fragmentShader: divergence_frag, uniforms: { boundarySpace: { value: this.cellScale }, velocity: { value: this.fbos.vel_1.texture }, px: { value: this.cellScale }, dt: { value: this.opts.dt } } }, output: this.fbos.div });
                    this.poisson = new ShaderPass({ material: { vertexShader: face_vert, fragmentShader: poisson_frag, uniforms: { boundarySpace: { value: this.cellScale }, pressure: { value: this.fbos.pressure_0.texture }, divergence: { value: this.fbos.div.texture }, px: { value: this.cellScale } } }, output: this.fbos.pressure_1 });
                    this.pressure = new ShaderPass({ material: { vertexShader: face_vert, fragmentShader: pressure_frag, uniforms: { boundarySpace: { value: this.cellScale }, pressure: { value: this.fbos.pressure_0.texture }, velocity: { value: this.fbos.vel_1.texture }, px: { value: this.cellScale }, dt: { value: this.opts.dt } } }, output: this.fbos.vel_0 });
                }
                update() {
                    this.advection.uniforms.dt.value = this.opts.dt; this.advection.update();
                    const forceX = (Mouse.diff.x / 2) * mouseForce;
                    const forceY = (Mouse.diff.y / 2) * mouseForce;
                    const cX = Math.min(Math.max(Mouse.coords.x, -1), 1);
                    const cY = Math.min(Math.max(Mouse.coords.y, -1), 1);
                    this.force.scene.children[0].material.uniforms.force.value.set(forceX, forceY);
                    this.force.scene.children[0].material.uniforms.center.value.set(cX, cY);
                    this.force.update();
                    this.divergence.update();
                    for (let i = 0; i < 32; i++) {
                        const p_in = (i % 2 === 0) ? this.fbos.pressure_0 : this.fbos.pressure_1;
                        const p_out = (i % 2 === 0) ? this.fbos.pressure_1 : this.fbos.pressure_0;
                        this.poisson.uniforms.pressure.value = p_in.texture;
                        this.poisson.props.output = p_out;
                        this.poisson.update();
                    }
                    this.pressure.uniforms.pressure.value = this.fbos.pressure_1.texture;
                    this.pressure.update();
                }
                resize() { this.init(); }
            }

            Common.init(mountRef.current);
            Mouse.init();
            mountRef.current.appendChild(Common.renderer.domElement);

            const sim = new Simulation({ dt });
            const output = new ShaderPass({
                material: { vertexShader: face_vert, fragmentShader: color_frag, transparent: true, depthWrite: false, uniforms: { velocity: { value: sim.fbos.vel_0.texture }, boundarySpace: { value: new THREE.Vector2() }, palette: { value: paletteTex }, bgColor: { value: bgVec4 } } }
            });

            const loop = () => {
                Mouse.update();
                Common.update();
                sim.update();
                output.update();
                Common.renderer.setRenderTarget(null);
                Common.renderer.render(output.scene, output.camera);
                rafRef.current = requestAnimationFrame(loop);
            };
            loop();

            const handleResize = () => { Common.resize(); sim.resize(); };
            window.addEventListener('resize', handleResize);

            webglRef.current = {
                dispose: () => {
                    if (rafRef.current) cancelAnimationFrame(rafRef.current);
                    window.removeEventListener('resize', handleResize);
                    Mouse.dispose();
                    Common.dispose();
                    if (mountRef.current && mountRef.current.firstChild) mountRef.current.removeChild(mountRef.current.firstChild);
                }
            };
        } catch (e) {
            console.error("WebGL initialization failed, falling back to CSS background", e);
            setIsWebglSupported(false);
        }

        return () => {
            if (webglRef.current) webglRef.current.dispose();
        };
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [colors, isWebglSupported]);

    if (!isWebglSupported) {
        return <div className="absolute inset-0 w-full h-full z-0 bg-gradient-to-br from-[#0f172a] to-[#000000]" />;
    }

    return <div ref={mountRef} className="absolute inset-0 w-full h-full z-0" />;
};


import { api } from '../api/client';

/**
 * --- MAIN APP ---
 */
const Login = () => {
    const navigate = useNavigate();
    const [view, setView] = useState('INTRO');
    const [authMode, setAuthMode] = useState('LOGIN');
    const [userType, setUserType] = useState('USER'); // 'USER' or 'EMPLOYEE'
    const [formData, setFormData] = useState({ email: '', password: '', name: '' });
    const [loading, setLoading] = useState(false);
    const [success, setSuccess] = useState(false);
    const [error, setError] = useState('');
    const [currentSlideIndex, setCurrentSlideIndex] = useState(0);

    // --- DIVERSITY SLIDES (Cultural Themes) ---
    const SLIDES = [
        { id: 'north', greeting: 'Namaste', subtext: "Connecting the North", img: "https://picsum.photos/seed/north/1920/1080" },
        { id: 'south', greeting: 'Vanakkam', subtext: "Bridging the South", img: "https://picsum.photos/seed/south/1920/1080" },
        { id: 'east', greeting: 'Nomoshkar', subtext: "Empowering the East", img: "https://picsum.photos/seed/east/1920/1080" },
        { id: 'west', greeting: 'Sat Sri Akal', subtext: "Uniting the West", img: "https://picsum.photos/seed/west/1920/1080" }
    ];

    useEffect(() => {
        const interval = setInterval(() => {
            setCurrentSlideIndex(prev => (prev + 1) % SLIDES.length);
        }, 4000); // Change image every 4 seconds
        return () => clearInterval(interval);
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError('');

        try {
            let response;
            if (authMode === 'LOGIN') {
                response = await api.post('/auth/login', {
                    email: formData.email,
                    password: formData.password
                });
            } else {
                response = await api.post('/auth/register', {
                    name: formData.name,
                    email: formData.email,
                    password: formData.password,
                    role: userType === 'EMPLOYEE' ? 'CLIENT' : 'WORKER'
                });
            }

            // Assuming backend returns { token, user } or similar
            const { token, user } = response.data || response; 

            // Only set role during registration based on selected tab
            // For login, always use the role returned from backend
            if (authMode === 'REGISTER') {
                // During registration, set role based on UI selection
                user.role = userType === 'EMPLOYEE' ? 'CLIENT' : 'WORKER';
            }
            // For login (authMode === 'LOGIN'), user.role is already set from backend

            if (token) {
                localStorage.setItem('token', token);
                localStorage.setItem('user', JSON.stringify(user));
            }

            setLoading(false);
            setSuccess(true);

            setTimeout(() => {
                // Only check onboarding status for new registrations, not logins
                if (authMode === 'REGISTER' && user.onboarding_status !== 'COMPLETED') {
                    navigate('/onboarding');
                } else {
                    // Route based on actual user role from database
                    const homeRoute = user.role === 'CLIENT' ? '/employer-home' : '/home';
                    navigate(homeRoute);
                }
            }, 800);

        } catch (err) {
            console.error("Auth Error:", err);
            setLoading(false);
            setError(err.message || 'Authentication failed. Please try again.');
