            // Tech Theme Colors (Cyan/Blue/Purple)
            drawOrb(cx + Math.sin(time) * 300, cy + Math.cos(time * 0.8) * 200, 800, 'rgba(56, 189, 248, 0.15)'); // Sky Blue
            drawOrb(cx + Math.cos(time * 0.6 + 2) * 350, cy + Math.sin(time * 0.5 + 2) * 250, 600, 'rgba(99, 102, 241, 0.15)'); // Indigo
            drawOrb(cx + Math.cos(time * 0.4) * 400, cy + Math.sin(time * 0.3) * 300, 700, 'rgba(168, 85, 247, 0.1)'); // Purple

            animationFrameId = requestAnimationFrame(render);
        };

        render();

        return () => { window.removeEventListener('resize', handleResize); cancelAnimationFrame(animationFrameId); };
    }, []);

    return <canvas ref={canvasRef} className="absolute inset-0 w-full h-full z-0" />;
};

