/**
 * ==========================================
 * 1. LIQUID BACKGROUND (Vanilla Canvas)
 * ==========================================
 */
const LiquidBackground = () => {
    const canvasRef = useRef(null);
    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        let animationFrameId;
        let time = 0;

        const render = () => {
            time += 0.005;
            const w = canvas.width = window.innerWidth;
            const h = canvas.height = window.innerHeight;
            const cx = w / 2;
            const cy = h / 2;

            ctx.fillStyle = '#0a0a0f';
            ctx.fillRect(0, 0, w, h);

            const drawOrb = (x, y, r, color) => {
                const g = ctx.createRadialGradient(x, y, 0, x, y, r);
                g.addColorStop(0, color);
                g.addColorStop(1, 'rgba(0,0,0,0)');
                ctx.fillStyle = g;
                ctx.fillRect(0, 0, w, h);
            };

            // Different colors for Employer (Blue/Cyan/Purple theme)
            drawOrb(cx + Math.sin(time) * 300, cy + Math.cos(time * 0.8) * 200, 700, 'rgba(29, 78, 216, 0.35)'); // Blue
            drawOrb(cx + Math.cos(time * 0.6 + 2) * 350, cy + Math.sin(time * 0.5 + 2) * 250, 600, 'rgba(6, 182, 212, 0.3)'); // Cyan
            drawOrb(cx + Math.cos(time * 0.6 + 4) * 350, cy + Math.sin(time * 0.5 + 2) * 250, 650, 'rgba(124, 58, 237, 0.3)'); // Purple

            animationFrameId = requestAnimationFrame(render);
        };
        render();
        const handleResize = () => { canvas.width = window.innerWidth; canvas.height = window.innerHeight; };
        window.addEventListener('resize', handleResize);
        return () => { window.removeEventListener('resize', handleResize); cancelAnimationFrame(animationFrameId); };
    }, []);
    return <canvas ref={canvasRef} className="absolute inset-0 w-full h-full z-0" />;
};

/**
 * ==========================================
 * 2. DECRYPTED TEXT EFFECT
 * ==========================================
 */
const DecryptedText = ({ text, className = "" }) => {
    const [displayText, setDisplayText] = useState(text);
    const [isHovering, setIsHovering] = useState(false);
    const characters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ1234567890!@#$%^&*';

    useEffect(() => {
        let interval;
        if (isHovering) {
            let iteration = 0;
            interval = setInterval(() => {
                setDisplayText(prev =>
                    text.split("").map((char, index) => {
                        if (index < iteration) return text[index];
                        return characters[Math.floor(Math.random() * characters.length)];
                    }).join("")
                );
                if (iteration >= text.length) clearInterval(interval);
                iteration += 1 / 3;
            }, 30);
        } else {
            setDisplayText(text);
        }
        return () => clearInterval(interval);
    }, [isHovering, text]);

    return (
        <span
            onMouseEnter={() => setIsHovering(true)}
            className={`cursor-default ${className}`}
        >
            {displayText}
        </span>
    );
};

/**
 * ==========================================
 * 3. 3D TILT CARD
 * ==========================================
 */
const Card = ({ children, className = "", dark = false, delay = 0, noHover = false }) => {
    const [isVisible, setIsVisible] = useState(false);
    const cardRef = useRef(null);
    const rectRef = useRef(null);

    useEffect(() => {
        const timer = setTimeout(() => setIsVisible(true), delay);
        return () => clearTimeout(timer);
    }, [delay]);

    const handleMouseEnter = () => {
        if (cardRef.current) {
            rectRef.current = cardRef.current.getBoundingClientRect();
            cardRef.current.style.transition = 'transform 0.1s ease-out';
        }
    };

    const handleMouseMove = (e) => {
        if (noHover || !cardRef.current) return;

        if (!rectRef.current) {
            rectRef.current = cardRef.current.getBoundingClientRect();
        }

        const { left, top, width, height } = rectRef.current;
        const x = e.clientX - left;
        const y = e.clientY - top;
        const centerX = width / 2;
        const centerY = height / 2;
        const rotateX = ((y - centerY) / centerY) * -8;
        const rotateY = ((x - centerX) / centerX) * 8;

        cardRef.current.style.transform = `perspective(1000px) rotateX(${rotateX}deg) rotateY(${rotateY}deg) scale(1.02)`;
    };

    const handleMouseLeave = () => {
        if (cardRef.current) {
            cardRef.current.style.transform = 'perspective(1000px) rotateX(0deg) rotateY(0deg) scale(1)';
            cardRef.current.style.transition = 'transform 0.5s ease-out';
            rectRef.current = null;
        }
    };

    const baseClasses = dark
        ? 'bg-[#1c1c1e] text-white border border-slate-800 shadow-2xl'
        : 'bg-white/5 backdrop-blur-xl border border-white/10 text-slate-200 shadow-xl';

    return (
        <div className={`relative transition-all duration-1000 ease-out ${isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-12'} ${className}`}>
            <div 
                ref={cardRef} 
                onMouseEnter={handleMouseEnter}
                onMouseMove={handleMouseMove} 
                onMouseLeave={handleMouseLeave} 
                className={`h-full w-full rounded-[32px] p-6 overflow-hidden ${baseClasses}`}
            >
                {children}
            </div>
        </div>
    );
};

