/**
 * ==========================================
 * 1. LIQUID BACKGROUND ENGINE
 * ==========================================
 */
const LiquidBackground = () => {
    const canvasRef = useRef(null);
    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        let animationFrameId;
        let time = 0;

        const handleResize = () => {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
        };
        handleResize();
        window.addEventListener('resize', handleResize);

        const render = () => {
            time += 0.002;
            const w = canvas.width;
            const h = canvas.height;
            const cx = w / 2;
            const cy = h / 2;

            ctx.fillStyle = '#02040a';
            ctx.fillRect(0, 0, w, h);

            const drawOrb = (x, y, r, color) => {
                const g = ctx.createRadialGradient(x, y, 0, x, y, r);
                g.addColorStop(0, color);
                g.addColorStop(1, 'rgba(0,0,0,0)');
                ctx.fillStyle = g;
                ctx.fillRect(0, 0, w, h);
            };

            drawOrb(cx + Math.sin(time) * 300, cy + Math.cos(time * 0.8) * 200, 800, 'rgba(29, 78, 216, 0.15)');
            drawOrb(cx + Math.cos(time * 0.6 + 2) * 350, cy + Math.sin(time * 0.5 + 2) * 250, 600, 'rgba(6, 182, 212, 0.1)');
            drawOrb(cx + Math.cos(time * 0.4) * 400, cy + Math.sin(time * 0.3) * 300, 700, 'rgba(30, 58, 138, 0.1)');

            animationFrameId = requestAnimationFrame(render);
        };
        render();

        return () => { window.removeEventListener('resize', handleResize); cancelAnimationFrame(animationFrameId); };
    }, []);
    return <canvas ref={canvasRef} className="absolute inset-0 w-full h-full z-0" />;
};

/**
 * ==========================================
 * 2. UI COMPONENTS
 * ==========================================
 */
const Card = ({ children, className = "", dark = false, delay = 0, noHover = false }) => {
    const [isVisible, setIsVisible] = useState(false);
    const cardRef = useRef(null);
    const [tiltStyle, setTiltStyle] = useState({});

    useEffect(() => {
        const timer = setTimeout(() => setIsVisible(true), delay);
        return () => clearTimeout(timer);
    }, [delay]);

    const handleMouseMove = (e) => {
        if (noHover || !cardRef.current) return;
        const { left, top, width, height } = cardRef.current.getBoundingClientRect();
        const x = e.clientX - left;
        const y = e.clientY - top;
        const centerX = width / 2;
        const centerY = height / 2;
        const maxRotate = 3;
        const rotateX = ((y - centerY) / centerY) * -maxRotate;
        const rotateY = ((x - centerX) / centerX) * maxRotate;

        setTiltStyle({
            transform: `perspective(1000px) rotateX(${rotateX}deg) rotateY(${rotateY}deg) scale(1.005)`,
            transition: 'transform 0.1s ease-out'
        });
    };

    const handleMouseLeave = () => {
        setTiltStyle({
            transform: 'perspective(1000px) rotateX(0deg) rotateY(0deg) scale(1)',
            transition: 'transform 0.5s ease-out'
        });
    };

    const baseClasses = dark
        ? 'bg-[#0f172a] text-white border border-slate-800 shadow-2xl'
        : 'bg-white/5 backdrop-blur-xl border border-white/10 text-slate-200 shadow-xl';

    return (
        <div className={`relative transition-all duration-700 ease-out ${isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-12'} ${className}`}>
            <div ref={cardRef} onMouseMove={handleMouseMove} onMouseLeave={handleMouseLeave} className={`h-full w-full rounded-[32px] p-6 overflow-hidden ${baseClasses}`} style={tiltStyle}>
                {children}
            </div>
        </div>
    );
};

