// 3. INTERACTIVE GRAPH (Spending)
const InteractiveGraph = ({ delay }) => {
    const [hoveredIndex, setHoveredIndex] = useState(null);
    const [animate, setAnimate] = useState(false);

    const dataPoints = [30, 45, 35, 60, 50, 75, 65, 90, 80, 55, 70, 60];
    const labels = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
    const maxValue = 100;
    const width = 500;
    const height = 180;
    const spacing = width / (dataPoints.length - 1);

    useEffect(() => { setTimeout(() => setAnimate(true), delay + 300); }, [delay]);

    // Generate Path
    const points = dataPoints.map((val, i) => `${i * spacing},${height - (val / maxValue) * height}`).join(' ');

    return (
        <Card delay={delay} className="col-span-1 lg:col-span-1 min-h-[280px] flex flex-col overflow-visible group !p-8">
            <div className="flex justify-between items-center mb-8">
                <div>
                    <h3 className="font-bold text-xl text-white">Spending</h3>
                    <p className="text-xs text-slate-400 mt-1 font-medium">Yearly Overview</p>
                </div>
                <div className="flex bg-white/5 rounded-lg p-1 gap-1 border border-white/5">
                    <button className="px-3 py-1 text-[10px] font-bold text-slate-400 hover:text-white transition-colors">W</button>
                    <button className="px-3 py-1 text-[10px] font-bold bg-blue-600 text-white rounded shadow-sm">M</button>
                    <button className="px-3 py-1 text-[10px] font-bold text-slate-400 hover:text-white transition-colors">Y</button>
                </div>
            </div>

            <div className="flex-1 relative w-full h-full flex items-end" onMouseLeave={() => setHoveredIndex(null)}>
                {/* Tooltip */}
                {hoveredIndex !== null && (
                    <div
                        className="absolute bg-blue-600 shadow-lg shadow-blue-900/40 px-3 py-1.5 rounded-lg text-xs font-bold text-white z-20 transform -translate-x-1/2 -translate-y-full transition-all duration-75 pointer-events-none border border-blue-400/30"
                        style={{ left: `${hoveredIndex * spacing}px`, top: `${height - (dataPoints[hoveredIndex] / maxValue) * height - 15}px` }}
                    >
                        ₹{dataPoints[hoveredIndex]}k
                        <div className="absolute -bottom-1 left-1/2 -translate-x-1/2 w-2 h-2 bg-blue-600 rotate-45"></div>
                    </div>
                )}

                <svg className="w-full h-full overflow-visible" viewBox={`0 0 ${width} ${height}`} preserveAspectRatio="none">
                    <defs>
                        <linearGradient id="graphGradient" x1="0" x2="0" y1="0" y2="1">
                            <stop offset="0%" stopColor="#3b82f6" stopOpacity="0.5" />
                            <stop offset="100%" stopColor="#3b82f6" stopOpacity="0" />
                        </linearGradient>
                    </defs>

                    {/* Fill Area */}
                    <path
                        d={`M0,${height} L${points} L${width},${height} Z`}
                        fill="url(#graphGradient)"
                        className={`transition-opacity duration-1000 ${animate ? 'opacity-100' : 'opacity-0'}`}
                    />

                    {/* Stroke Line */}
                    <polyline
                        points={points}
                        fill="none"
                        stroke="#3b82f6"
                        strokeWidth="3"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                        className="drop-shadow-[0_0_15px_rgba(59,130,246,0.5)]"
                        strokeDasharray="1000"
                        strokeDashoffset={animate ? "0" : "1000"}
                        style={{ transition: 'stroke-dashoffset 2s ease-out' }}
                    />

                    {/* Interactive Points */}
                    {dataPoints.map((val, i) => (
                        <circle
                            key={i}
                            cx={i * spacing}
                            cy={height - (val / maxValue) * height}
                            r={hoveredIndex === i ? 6 : 0}
                            fill="#fff"
                            stroke="#3b82f6"
                            strokeWidth="2"
                            onMouseEnter={() => setHoveredIndex(i)}
                            className="transition-all duration-200 cursor-pointer pointer-events-auto"
                        />
                    ))}

                    {/* Hit Areas */}
                    {dataPoints.map((val, i) => (
                        <rect
                            key={i}
                            x={i * spacing - 10}
                            y="0"
                            width="20"
                            height={height}
                            fill="transparent"
                            onMouseEnter={() => setHoveredIndex(i)}
                            className="cursor-crosshair pointer-events-auto"
                        />
                    ))}
                </svg>

                {/* Labels */}
                <div className="absolute -bottom-6 left-0 w-full flex justify-between text-[9px] font-bold text-slate-500 uppercase">
                    {labels.filter((_, i) => i % 2 === 0).map((l, i) => <span key={i}>{l}</span>)}
                </div>
            </div>
        </Card>
    );
};

