import { useState, useEffect } from 'react';
import { Briefcase, Clock, CheckCircle, XCircle, DollarSign, MapPin, Calendar } from 'lucide-react';
import { api } from '../api/client';

export default function MyGigs() {
    const [gigs, setGigs] = useState([]);
    const [loading, setLoading] = useState(true);
    const [activeFilter, setActiveFilter] = useState('all'); // all, active, completed
    const [user, setUser] = useState(null);

    useEffect(() => {
        const storedUser = localStorage.getItem('user');
        if (storedUser) {
            setUser(JSON.parse(storedUser));
        }
    }, []);

    useEffect(() => {
        if (user) {
            fetchMyGigs();
        }
    }, [user]);

    const fetchMyGigs = async () => {
        try {
            setLoading(true);
            let endpoint = '';

            if (user.role === 'CLIENT' || user.role === 'EMPLOYEE') {
                // Employer: fetch jobs posted by them
                endpoint = `/jobs?client_id=${user.id}`;
            } else {
                // Worker: fetch jobs they're working on or applied to
                endpoint = `/jobs?worker_id=${user.id}`;
            }

            const response = await api.get(endpoint);
            const data = Array.isArray(response) ? response : response.data || [];
            setGigs(data);
        } catch (error) {
            console.error('Failed to fetch gigs:', error);
            setGigs([]);
        } finally {
            setLoading(false);
        }
    };

    const getStatusBadge = (status) => {
        const statusConfig = {
            'OPEN': { color: 'bg-blue-500/20 text-blue-300', icon: Clock, label: 'Open' },
            'IN_PROGRESS': { color: 'bg-yellow-500/20 text-yellow-300', icon: Clock, label: 'In Progress' },
            'COMPLETED': { color: 'bg-green-500/20 text-green-300', icon: CheckCircle, label: 'Completed' },
            'CANCELLED': { color: 'bg-red-500/20 text-red-300', icon: XCircle, label: 'Cancelled' }
        };

        const config = statusConfig[status] || statusConfig['OPEN'];
        const Icon = config.icon;

        return (
            <span className={`inline-flex items-center gap-1 px-3 py-1 rounded-full text-xs font-medium ${config.color}`}>
                <Icon className="w-3 h-3" />
                {config.label}
            </span>
        );
    };

    const filteredGigs = gigs.filter(gig => {
        if (activeFilter === 'all') return true;
        if (activeFilter === 'active') return gig.status === 'IN_PROGRESS' || gig.status === 'OPEN';
        if (activeFilter === 'completed') return gig.status === 'COMPLETED';
        return true;
    });

    const stats = {
        total: gigs.length,
        active: gigs.filter(g => g.status === 'IN_PROGRESS' || g.status === 'OPEN').length,
        completed: gigs.filter(g => g.status === 'COMPLETED').length
    };

    return (
        <div className="min-h-screen bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900 p-6">
            <div className="max-w-7xl mx-auto">
                {/* Header */}
                <div className="mb-8">
                    <h1 className="text-4xl font-black text-white mb-2">Your Gigs</h1>
                    <p className="text-gray-400">
                        {user?.role === 'CLIENT' || user?.role === 'EMPLOYEE' 
                            ? 'Track jobs you\'ve posted and manage your projects' 
                            : 'Track your work and history'}
                    </p>
                </div>

                {/* Stats Cards */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
                    <div className="bg-white/5 backdrop-blur-xl border border-white/10 rounded-2xl p-6">
                        <div className="flex items-center justify-between">
                            <div>
                                <p className="text-gray-400 text-sm mb-1">Total Gigs</p>
                                <p className="text-3xl font-bold text-white">{stats.total}</p>
                            </div>
                            <div className="w-12 h-12 bg-blue-500/20 rounded-xl flex items-center justify-center">
                                <Briefcase className="w-6 h-6 text-blue-400" />
                            </div>
                        </div>
                    </div>

                    <div className="bg-white/5 backdrop-blur-xl border border-white/10 rounded-2xl p-6">
                        <div className="flex items-center justify-between">
                            <div>
                                <p className="text-gray-400 text-sm mb-1">Active</p>
                                <p className="text-3xl font-bold text-white">{stats.active}</p>
                            </div>
                            <div className="w-12 h-12 bg-yellow-500/20 rounded-xl flex items-center justify-center">
                                <Clock className="w-6 h-6 text-yellow-400" />
                            </div>
                        </div>
                    </div>

                    <div className="bg-white/5 backdrop-blur-xl border border-white/10 rounded-2xl p-6">
                        <div className="flex items-center justify-between">
                            <div>
                                <p className="text-gray-400 text-sm mb-1">Completed</p>
                                <p className="text-3xl font-bold text-white">{stats.completed}</p>
                            </div>
                            <div className="w-12 h-12 bg-green-500/20 rounded-xl flex items-center justify-center">
                                <CheckCircle className="w-6 h-6 text-green-400" />
                            </div>
                        </div>
                    </div>
                </div>

                {/* Filters */}
                <div className="flex gap-3 mb-6">
                    <button
                        onClick={() => setActiveFilter('all')}
                        className={`px-4 py-2 rounded-lg font-medium transition-all ${
                            activeFilter === 'all'
                                ? 'bg-blue-500 text-white'
                                : 'bg-white/10 text-gray-300 hover:bg-white/20'
                        }`}
                    >
                        All ({stats.total})
                    </button>
                    <button
                        onClick={() => setActiveFilter('active')}
                        className={`px-4 py-2 rounded-lg font-medium transition-all ${
                            activeFilter === 'active'
                                ? 'bg-blue-500 text-white'
                                : 'bg-white/10 text-gray-300 hover:bg-white/20'
                        }`}
                    >
                        Active ({stats.active})
                    </button>
                    <button
                        onClick={() => setActiveFilter('completed')}
                        className={`px-4 py-2 rounded-lg font-medium transition-all ${
                            activeFilter === 'completed'
                                ? 'bg-blue-500 text-white'
                                : 'bg-white/10 text-gray-300 hover:bg-white/20'
                        }`}
                    >
                        Completed ({stats.completed})
                    </button>
                </div>

                {/* Gigs List */}
                {loading ? (
                    <div className="flex items-center justify-center py-20">
                        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500"></div>
                    </div>
                ) : filteredGigs.length === 0 ? (
                    <div className="bg-white/5 backdrop-blur-xl border border-white/10 rounded-2xl p-12 text-center">
                        <Briefcase className="w-16 h-16 text-gray-500 mx-auto mb-4" />
                        <h3 className="text-xl font-bold text-white mb-2">No gigs yet</h3>
                        <p className="text-gray-400">
                            {user?.role === 'CLIENT' || user?.role === 'EMPLOYEE'
                                ? 'Start by posting a new job'
                                : 'You haven\'t applied to any gigs yet'}
                        </p>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {filteredGigs.map((gig) => (
                            <div 
                                key={gig.id}
                                className="bg-white/5 backdrop-blur-xl border border-white/10 rounded-2xl p-6 hover:bg-white/10 transition-all hover:border-white/20"
                            >
                                <div className="flex items-start justify-between mb-4">
                                    <div className="flex-1">
                                        <div className="flex items-center gap-3 mb-2">
                                            <h3 className="text-xl font-bold text-white">
                                                {gig.title}
                                            </h3>
                                            {getStatusBadge(gig.status)}
                                        </div>
                                        <p className="text-gray-300 text-sm mb-3">{gig.description}</p>

                                        <div className="flex flex-wrap gap-4 text-sm text-gray-400">
                                            {gig.location && (
                                                <div className="flex items-center gap-1">
                                                    <MapPin className="w-4 h-4" />
                                                    <span>{gig.location}</span>
                                                </div>
                                            )}
                                            <div className="flex items-center gap-1">
                                                <Calendar className="w-4 h-4" />
                                                <span>Posted {new Date(gig.created_at).toLocaleDateString()}</span>
                                            </div>
                                            <div className="flex items-center gap-1 text-green-400 font-semibold">
                                                <DollarSign className="w-4 h-4" />
                                                <span>${parseFloat(gig.budget).toLocaleString()}</span>
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                {/* Skills */}
                                {gig.skills && gig.skills.length > 0 && (
                                    <div className="flex flex-wrap gap-2 pt-4 border-t border-white/10">
                                        {gig.skills.map((skill, idx) => (
                                            <span 
                                                key={idx}
                                                className="px-3 py-1 bg-blue-500/20 text-blue-300 rounded-full text-xs font-medium"
                                            >
                                                {skill}
                                            </span>
                                        ))}
                                    </div>
                                )}
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>
    );
}

