const SearchInterface = () => {
    const [viewMode, setViewMode] = useState('list');
    const [selectedJob, setSelectedJob] = useState(null);
    const [searchQuery, setSearchQuery] = useState('');
    const [jobs, setJobs] = useState([]);
    const [loading, setLoading] = useState(true);

    const fetchJobs = async (query = '') => {
        try {
            setLoading(true);
            const endpoint = query ? `/jobs/search?q=${encodeURIComponent(query)}` : '/jobs';
            const response = await api.get(endpoint);
            const backendJobs = response.data || response;

            // Map backend data to frontend format
            const mappedJobs = backendJobs.map(job => ({
                id: job.id,
                title: job.title,
                company: job.client?.name || 'Unknown Client', // Assuming include client
                rating: job.client?.trustScore ? (job.client.trustScore / 20).toFixed(1) : '4.5',
                location: job.location || 'Remote',
                budget: `₹${job.budget}`,
                urgent: false, // Add logic if needed
                desc: job.description,
                fullDesc: job.description,
                posted: new Date(job.createdAt).toLocaleDateString(),
                applicants: 0,
                match: job.similarity ? Math.round(job.similarity * 100) : 85, // Use similarity from vector search
                logo: '💼'
            }));
            setJobs(mappedJobs);
        } catch (err) {
            console.error("Failed to fetch jobs", err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchJobs();
    }, []);

    const handleSearch = () => {
        fetchJobs(searchQuery);
    };

    const handleKeyDown = (e) => {
        if (e.key === 'Enter') {
            handleSearch();
        }
    };

    if (selectedJob) {
        return <JobDetails job={selectedJob} onBack={() => setSelectedJob(null)} />;
