                            placeholder="Search for gigs..."
                            className="w-full bg-white/5 border border-white/10 rounded-2xl py-3.5 pl-12 pr-4 text-white placeholder:text-slate-500 focus:outline-none focus:border-blue-500/50 focus:bg-white/10 transition-all shadow-lg"
                        />
                    </div>
                    <button 
                        onClick={handleSearch}
                        className="px-6 py-3 bg-[#5227FF] hover:bg-[#4319cc] rounded-2xl text-white font-bold text-sm shadow-lg transition-colors whitespace-nowrap"
