/**
 * ==========================================
 * 1. LIQUID BACKGROUND (Vanilla Canvas)
 * ==========================================
 */
const LiquidBackground = () => {
    const canvasRef = useRef(null);
    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        let animationFrameId;
        let time = 0;

        const render = () => {
            time += 0.005;
            const w = canvas.width = window.innerWidth;
            const h = canvas.height = window.innerHeight;
            const cx = w / 2;
            const cy = h / 2;

            ctx.fillStyle = '#0a0a0f';
            ctx.fillRect(0, 0, w, h);

            const drawOrb = (x, y, r, color) => {
                const g = ctx.createRadialGradient(x, y, 0, x, y, r);
                g.addColorStop(0, color);
                g.addColorStop(1, 'rgba(0,0,0,0)');
                ctx.fillStyle = g;
                ctx.fillRect(0, 0, w, h);
            };

            drawOrb(cx + Math.sin(time) * 300, cy + Math.cos(time * 0.8) * 200, 700, 'rgba(76, 29, 149, 0.35)');
            drawOrb(cx + Math.cos(time * 0.6 + 2) * 350, cy + Math.sin(time * 0.5 + 2) * 250, 600, 'rgba(192, 38, 211, 0.3)');
            drawOrb(cx + Math.cos(time * 0.6 + 4) * 350, cy + Math.sin(time * 0.5 + 2) * 250, 650, 'rgba(67, 56, 202, 0.3)');

            animationFrameId = requestAnimationFrame(render);
        };
        render();
        const handleResize = () => { canvas.width = window.innerWidth; canvas.height = window.innerHeight; };
        window.addEventListener('resize', handleResize);
        return () => { window.removeEventListener('resize', handleResize); cancelAnimationFrame(animationFrameId); };
    }, []);
    return <canvas ref={canvasRef} className="absolute inset-0 w-full h-full z-0" />;
};

/**
 * ==========================================
 * 2. DECRYPTED TEXT EFFECT
 * ==========================================
 */
const DecryptedText = ({ text, className = "" }) => {
    const [displayText, setDisplayText] = useState(text);
    const [isHovering, setIsHovering] = useState(false);
    const characters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ1234567890!@#$%^&*';

    useEffect(() => {
        let interval;
        if (isHovering) {
            let iteration = 0;
            interval = setInterval(() => {
                setDisplayText(prev =>
                    text.split("").map((char, index) => {
                        if (index < iteration) return text[index];
                        return characters[Math.floor(Math.random() * characters.length)];
                    }).join("")
                );
                if (iteration >= text.length) clearInterval(interval);
                iteration += 1 / 3;
            }, 30);
        } else {
            setDisplayText(text);
        }
        return () => clearInterval(interval);
    }, [isHovering, text]);

    return (
        <span
            onMouseEnter={() => setIsHovering(true)}
            className={`cursor-default ${className}`}
        >
            {displayText}
        </span>
    );
};

/**
 * ==========================================
 * 3. 3D TILT CARD
 * ==========================================
 */
const Card = ({ children, className = "", dark = false, delay = 0, noHover = false }) => {
    const [isVisible, setIsVisible] = useState(false);
    const cardRef = useRef(null);
    const rectRef = useRef(null);

    useEffect(() => {
        const timer = setTimeout(() => setIsVisible(true), delay);
        return () => clearTimeout(timer);
    }, [delay]);

    const handleMouseEnter = () => {
        if (cardRef.current) {
            rectRef.current = cardRef.current.getBoundingClientRect();
            cardRef.current.style.transition = 'transform 0.1s ease-out';
        }
    };

    const handleMouseMove = (e) => {
        if (noHover || !cardRef.current) return;

        // Fallback if rect is missing
        if (!rectRef.current) {
            rectRef.current = cardRef.current.getBoundingClientRect();
        }

        const { left, top, width, height } = rectRef.current;
        const x = e.clientX - left;
        const y = e.clientY - top;
        const centerX = width / 2;
        const centerY = height / 2;
        const rotateX = ((y - centerY) / centerY) * -8;
        const rotateY = ((x - centerX) / centerX) * 8;

        cardRef.current.style.transform = `perspective(1000px) rotateX(${rotateX}deg) rotateY(${rotateY}deg) scale(1.02)`;
    };

    const handleMouseLeave = () => {
        if (cardRef.current) {
            cardRef.current.style.transform = 'perspective(1000px) rotateX(0deg) rotateY(0deg) scale(1)';
            cardRef.current.style.transition = 'transform 0.5s ease-out';
            rectRef.current = null;
        }
    };

    const baseClasses = dark
        ? 'bg-[#1c1c1e] text-white border border-slate-800 shadow-2xl'
        : 'bg-white/5 backdrop-blur-xl border border-white/10 text-slate-200 shadow-xl';

    return (
        <div className={`relative transition-all duration-1000 ease-out ${isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-12'} ${className}`}>
            <div 
                ref={cardRef} 
                onMouseEnter={handleMouseEnter}
                onMouseMove={handleMouseMove} 
                onMouseLeave={handleMouseLeave} 
                className={`h-full w-full rounded-[32px] p-6 overflow-hidden ${baseClasses}`}
            >
                {children}
            </div>
        </div>
    );
};

/**
 * ==========================================
 * 4. INTERACTIVE AVATAR WIDGET (Face Follows Cursor)
 * ==========================================
 */
const ProfileMetricWidget = () => {
    const faceRef = useRef(null);
    const imgRef = useRef(null);
    const [avatarSeed, setAvatarSeed] = useState('User');
    const rectRef = useRef(null);

    useEffect(() => {
        const userStr = localStorage.getItem('user');
        if (userStr) {
            try {
                const user = JSON.parse(userStr);
                if (user.name) setAvatarSeed(user.name);
            } catch (e) {
                console.error("Error parsing user", e);
            }
        }
    }, []);

    useEffect(() => {
        const updateRect = () => {
            if (faceRef.current) {
                rectRef.current = faceRef.current.getBoundingClientRect();
            }
        };

        updateRect();
        window.addEventListener('resize', updateRect);

        // Throttled scroll handler
        let scrollRaf;
        const handleScroll = () => {
            if (!scrollRaf) {
                scrollRaf = requestAnimationFrame(() => {
                    updateRect();
                    scrollRaf = null;
                });
            }
        };
        window.addEventListener('scroll', handleScroll, true);

        let rafId;
        const handleMove = (e) => {
            if (!rectRef.current || !imgRef.current) return;

            cancelAnimationFrame(rafId);
            rafId = requestAnimationFrame(() => {
                const rect = rectRef.current;
                const cx = rect.left + rect.width / 2;
                const cy = rect.top + rect.height / 2;

                // Calculate look direction limited to +/- 15px
                const dx = Math.max(-15, Math.min(15, (e.clientX - cx) / 15));
                const dy = Math.max(-15, Math.min(15, (e.clientY - cy) / 15));

                if (imgRef.current) {
                    imgRef.current.style.transform = `translate(${dx}px, ${dy}px) scale(1.1)`;
                }
            });
        };

        window.addEventListener('mousemove', handleMove);
        return () => {
            window.removeEventListener('resize', updateRect);
            window.removeEventListener('scroll', handleScroll, true);
            window.removeEventListener('mousemove', handleMove);
            cancelAnimationFrame(rafId);
            cancelAnimationFrame(scrollRaf);
        };
    }, []);

    return (
        <div className="mt-auto px-4 pb-6 w-full">
            <div className="bg-[#f2f2f7] rounded-[32px] p-5 relative overflow-hidden text-slate-800 shadow-xl transition-transform hover:scale-[1.02] duration-300">

                {/* Header */}
                <div className="flex justify-between items-center mb-6">
                    <div>
                        <h4 className="font-bold text-lg leading-tight">Profile Rating</h4>
                        <p className="text-xs text-slate-500 font-medium">Overall insights</p>
                    </div>
                    <div className="w-8 h-8 bg-white rounded-full flex items-center justify-center shadow-sm cursor-pointer">
                        <ChevronRight className="w-5 h-5 text-slate-400" />
                    </div>
                </div>

                {/* Center Avatar & Score */}
                <div className="flex flex-col items-center justify-center relative mb-6">
                    <div className="text-xs font-bold text-slate-800 mb-2">4.9 <span className="text-slate-400">| 5.0</span></div>

                    {/* Circular Track */}
                    <div className="w-32 h-32 rounded-full border-4 border-white relative flex items-center justify-center bg-white shadow-inner">
                        {/* Progress Arc (Simulated with SVG) */}
                        <svg className="absolute inset-0 w-full h-full -rotate-90">
                            <circle cx="64" cy="64" r="58" stroke="#e2e8f0" strokeWidth="4" fill="none" />
                            <circle cx="64" cy="64" r="58" stroke="#1c1c1e" strokeWidth="4" fill="none" strokeDasharray="365" strokeDashoffset="80" strokeLinecap="round" />
                        </svg>

                        {/* The Face (Interactive) */}
                        <div ref={faceRef} className="w-24 h-24 rounded-full overflow-hidden bg-blue-100 relative z-10">
                            <img
                                ref={imgRef}
                                src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${avatarSeed}&backgroundColor=c0aede`}
                                alt="Avatar"
                                className="w-full h-full object-cover transition-transform duration-100 ease-out"
                                style={{
                                    transform: `scale(1.1)`
                                }}
                            />
                        </div>

                        {/* Floating Dot indicator */}
                        <div className="absolute top-4 left-4 w-3 h-3 bg-[#1c1c1e] rounded-full border-2 border-white z-20"></div>
                    </div>
                </div>

                {/* Footer Stats */}
                <div className="flex justify-between items-center pt-4 border-t border-slate-200">
                    <div>
                        <p className="text-[10px] text-slate-500 font-bold uppercase">Lifetime Earnings</p>
                        <p className="text-lg font-bold text-slate-800">₹1.85L</p>
                    </div>
                    <div className="text-right">
                        <p className="text-[10px] text-slate-500 font-bold uppercase">Trust Score</p>
                        <p className="text-lg font-bold text-slate-800">85</p>
                    </div>
                </div>
            </div>
        </div>
    );
};

