export default function WorkerDashboard({ onLogout }) {
    const navigate = useNavigate();
    const [activeTab, setActiveTab] = useState('overview');
    const [isMobileOpen, setIsMobileOpen] = useState(false);
    const [userName, setUserName] = useState('User');
    const [stats, setStats] = useState(null);
    const [activeGigs, setActiveGigs] = useState([]);
    const [completedGigs, setCompletedGigs] = useState([]);
    const [availableGigs, setAvailableGigs] = useState([]);

    useEffect(() => {
        const userStr = localStorage.getItem('user');
        let userId = null;
        if (userStr) {
            try {
                const user = JSON.parse(userStr);
                if (user && user.name) {
                    setUserName(user.name.split(' ')[0]); // Use first name
                }
                if (user && user.id) {
                    userId = user.id;
                }
            } catch (e) {
                console.error("Error parsing user from local storage", e);
            }
        }

        const fetchStats = async () => {
            try {
                const response = await api.get('/gamification/my-stats');
                if (response.success) {
                    setStats(response.data);
                }
            } catch (error) {
                console.error("Failed to fetch stats", error);
            }
        };

        const fetchGigs = async () => {
            try {
                // Fetch Open Gigs (New Opportunities)
                const openRes = await api.get('/jobs?status=OPEN');
                if (Array.isArray(openRes)) {
                    setAvailableGigs(openRes);
                }

                if (!userId) return;

                // Fetch Active Gigs
                const activeRes = await api.get(`/jobs?workerId=${userId}&status=IN_PROGRESS`);
                if (Array.isArray(activeRes)) {
                    setActiveGigs(activeRes);
                }

                // Fetch Completed Gigs
                const completedRes = await api.get(`/jobs?workerId=${userId}&status=COMPLETED`);
                if (Array.isArray(completedRes)) {
                    setCompletedGigs(completedRes);
                }
            } catch (error) {
                console.error("Failed to fetch gigs", error);
            }
        };

        fetchStats();
        fetchGigs();
    }, []);

    const handleLogout = () => {
        if (onLogout) {
            onLogout();
        }
        navigate('/login');
    };

    const handleViewCV = async () => {
        try {
            const response = await api.get('/gamification/my-card', { responseType: 'blob' });
            const url = window.URL.createObjectURL(response.data);
            window.open(url, '_blank');
        } catch (error) {
            console.error("Failed to fetch CV", error);
            alert("Failed to generate CV. Please try again.");
        }
    };

    console.log('WorkerDashboard rendering');

    return (
        <div className="relative w-full h-full bg-transparent overflow-hidden font-sans text-white flex flex-col">
            <LiquidBackground />
            <div className="relative z-10 w-full h-full flex flex-col overflow-hidden">
                {/* MAIN CONTENT */}
                <main className="flex-1 flex flex-col h-full overflow-hidden bg-transparent">
                    <header className="px-8 py-6 flex items-center justify-between shrink-0">
                        <div className="flex items-center gap-4">
                            <button className="lg:hidden p-2 text-gray-300 hover:bg-white/10 rounded-lg" onClick={() => setIsMobileOpen(true)}><Menu /></button>
                            <h2 className="text-3xl font-bold text-white flex items-center gap-2">
                                <DecryptedText text={`Namaste, ${userName}!`} />
                                <span className="animate-bounce"></span>
                            </h2>
                        </div>
                        <div className="flex items-center gap-4">
                            <button 
                                onClick={handleViewCV}
                                className="hidden md:flex bg-[#1c1c1e] text-white border border-white/20 px-6 py-2.5 rounded-full text-sm font-bold shadow-lg hover:scale-105 hover:shadow-xl transition-all items-center gap-2"
                            >
                                <FileText className="w-4 h-4" /> My CV
                            </button>
                            <button 
                                onClick={() => navigate('/verification')}
                                className="hidden md:flex bg-white text-black px-6 py-2.5 rounded-full text-sm font-bold shadow-lg hover:scale-105 hover:shadow-xl transition-all items-center gap-2"
