import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { 
    User, 
    Briefcase, 
    Mail, 
    Lock, 
    Phone, 
    MapPin, 
    Upload, 
    FileText,
    Building2,
    Lightbulb,
    CheckCircle,
    ArrowRight,
    ArrowLeft,
    Shield
} from 'lucide-react';
import { Stepper, StepContent } from '../components/Stepper';
import { api } from '../api/client';

const STEPS = [
    { id: 1, label: 'Role', description: 'Choose your path' },
    { id: 2, label: 'Account', description: 'Basic info' },
    { id: 3, label: 'Contact', description: 'Reach you' },
    { id: 4, label: 'Profile', description: 'Show yourself' },
    { id: 5, label: 'Review', description: 'Complete setup' }
];

export default function Onboarding() {
    const navigate = useNavigate();
    const [currentStep, setCurrentStep] = useState(1);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    const [formData, setFormData] = useState({
        // Step 1
        role: '',
        // Step 2
        name: '',
        email: '',
        password: '',
        confirmPassword: '',
        // Step 3
        phone: '',
        countryCode: '+91',
        address: '',
        // Step 4
        profileImage: null,
        profileImagePreview: '',
        bio: '',
        skills: '', // for workers
        companyName: '', // for employers
    });

    const [userId, setUserId] = useState(null);
    const [token, setToken] = useState(null);

    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
        setError('');
    };

    const handleImageUpload = (e) => {
        const file = e.target.files[0];
        if (file) {
            setFormData(prev => ({
                ...prev,
                profileImage: file,
                profileImagePreview: URL.createObjectURL(file)
            }));
        }
    };

    const validateStep = () => {
        switch (currentStep) {
            case 1:
                if (!formData.role) {
                    setError('Please select your role');
                    return false;
                }
                break;
            case 2:
                if (!formData.name || !formData.email || !formData.password || !formData.confirmPassword) {
                    setError('All fields are required');
                    return false;
                }
                if (formData.password !== formData.confirmPassword) {
                    setError('Passwords do not match');
                    return false;
                }
                if (formData.password.length < 6) {
                    setError('Password must be at least 6 characters');
                    return false;
                }
                break;
            case 3:
                if (!formData.phone || !formData.address) {
                    setError('Phone and address are required');
                    return false;
                }
                break;
            case 4:
                if (!formData.profileImagePreview) {
                    setError('Profile picture is required');
                    return false;
                }
                if (!formData.bio) {
                    setError('Bio is required');
                    return false;
                }
                if (formData.role === 'WORKER' && !formData.skills) {
                    setError('Please enter your skills');
                    return false;
                }
                if (formData.role === 'EMPLOYER' && !formData.companyName) {
                    setError('Company name is required');
                    return false;
                }
                break;
        }
        return true;
    };

    const handleNext = async () => {
        if (!validateStep()) return;

        setLoading(true);
        setError('');

        try {
            // Step 2: Create account
            if (currentStep === 2) {
                const response = await api.post('/auth/register', {
                    name: formData.name,
                    email: formData.email,
                    password: formData.password,
                    role: formData.role === 'WORKER' ? 'WORKER' : 'CLIENT'
                });

                const { token: authToken, user } = response.data || response;
                setToken(authToken);
                setUserId(user.id);
                localStorage.setItem('token', authToken);
                localStorage.setItem('user', JSON.stringify(user));
            }

            // Step 3: Update contact info
            if (currentStep === 3 && userId) {
                await api.put(`/users/${userId}`, {
                    phone: `${formData.countryCode}${formData.phone}`,
                    address: formData.address
                });
            }

            // Step 4: Update profile
            if (currentStep === 4 && userId) {
                // Upload profile image first if needed
                let imageUrl = formData.profileImagePreview;

                // Update profile data
                await api.put(`/users/${userId}`, {
                    profile_image: imageUrl,
                    bio: formData.bio,
                    skills: formData.role === 'WORKER' ? formData.skills : undefined,
                    company_name: formData.role === 'EMPLOYER' ? formData.companyName : undefined
                });
            }

            setCurrentStep(prev => prev + 1);
        } catch (err) {
            console.error('Onboarding error:', err);
            setError(err.response?.data?.message || err.message || 'Something went wrong');
        } finally {
            setLoading(false);
        }
    };

    const handleComplete = async () => {
        setLoading(true);
        try {
            // Mark onboarding as complete
            await api.post(`/users/${userId}/complete-onboarding`);

            // Update local storage
            const user = JSON.parse(localStorage.getItem('user'));
            user.onboarding_status = 'COMPLETED';
            localStorage.setItem('user', JSON.stringify(user));

            // Navigate to appropriate dashboard
            const homeRoute = formData.role === 'EMPLOYER' ? '/employer-home' : '/home';
            navigate(homeRoute);
        } catch (err) {
            console.error('Complete onboarding error:', err);
            // Navigate anyway for demo
            const homeRoute = formData.role === 'EMPLOYER' ? '/employer-home' : '/home';
            navigate(homeRoute);
        } finally {
            setLoading(false);
        }
    };

    const handleBack = () => {
        if (currentStep > 1) {
            setCurrentStep(prev => prev - 1);
            setError('');
        }
    };

    return (
        <div className="min-h-screen bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900 flex items-center justify-center p-4">
            <div className="w-full max-w-4xl">
                {/* Header */}
                <div className="text-center mb-8">
                    <div className="flex items-center justify-center gap-3 mb-4">
                        <Shield className="w-10 h-10 text-indigo-500" />
                        <h1 className="text-4xl font-black text-white">MIDDLE MAN</h1>
                    </div>
                    <p className="text-slate-400">Complete your profile to get started</p>
                </div>

                {/* Stepper */}
                <Stepper steps={STEPS} currentStep={currentStep} />

                {/* Content Card */}
                <div className="bg-slate-800/50 backdrop-blur-xl rounded-3xl border border-slate-700 p-8 shadow-2xl">
                    <AnimatePresence mode="wait">
                        {currentStep === 1 && <Step1Role formData={formData} handleChange={handleChange} />}
                        {currentStep === 2 && <Step2Account formData={formData} handleChange={handleChange} />}
                        {currentStep === 3 && <Step3Contact formData={formData} handleChange={handleChange} />}
                        {currentStep === 4 && <Step4Profile formData={formData} handleChange={handleChange} handleImageUpload={handleImageUpload} />}
                        {currentStep === 5 && <Step5Review formData={formData} />}
                    </AnimatePresence>

                    {/* Error Message */}
                    {error && (
                        <div className="mt-4 p-4 bg-red-500/10 border border-red-500/50 rounded-xl text-red-400 text-sm">
                            {error}
                        </div>
                    )}

                    {/* Navigation */}
                    <div className="flex items-center justify-between mt-8">
                        <button
                            onClick={handleBack}
                            disabled={currentStep === 1}
                            className="flex items-center gap-2 px-6 py-3 rounded-xl font-semibold text-slate-400 hover:text-white hover:bg-slate-700 transition-all disabled:opacity-30 disabled:cursor-not-allowed"
                        >
                            <ArrowLeft className="w-4 h-4" />
                            Back
                        </button>

                        {currentStep < 5 ? (
                            <button
                                onClick={handleNext}
                                disabled={loading}
                                className="flex items-center gap-2 px-8 py-3 bg-indigo-600 hover:bg-indigo-500 rounded-xl font-bold text-white transition-all disabled:opacity-50 shadow-lg shadow-indigo-500/30"
                            >
                                {loading ? 'Processing...' : 'Next'}
                                <ArrowRight className="w-4 h-4" />
                            </button>
                        ) : (
                            <button
                                onClick={handleComplete}
                                disabled={loading}
                                className="flex items-center gap-2 px-8 py-3 bg-green-600 hover:bg-green-500 rounded-xl font-bold text-white transition-all disabled:opacity-50 shadow-lg shadow-green-500/30"
                            >
                                {loading ? 'Completing...' : 'Complete Setup'}
                                <CheckCircle className="w-5 h-5" />
                            </button>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}

