"use client";
import React, { JSX, useState } from 'react';
import { useAnchorWallet, useConnection } from '@solana/wallet-adapter-react';
import { Program, AnchorProvider, BN, web3 } from '@coral-xyz/anchor';
import idl from '../../idl/escrow.json';
import { ShieldCheck, Wallet, Zap, Lock, ArrowRight } from 'lucide-react';
// Polyfill Buffer in the browser (Vite doesn't provide Node globals by default)
import { Buffer } from 'buffer';
if (!(globalThis as any).Buffer) {
  (globalThis as any).Buffer = Buffer;
}
import { Escrow } from '../../types/escrow';

export default function GigForm(): JSX.Element {
  const { connection } = useConnection();
  const wallet = useAnchorWallet();
  const [worker, setWorker] = useState<string>("");
  const [budget, setBudget] = useState<string>("");
  const [loading, setLoading] = useState<boolean>(false);

  const hire = async () => {
    if (!wallet) return alert("Connect Wallet!");
    if (!worker || !budget) return alert('Fill worker and budget');

    // Check for SOL balance before attempting transaction
    const balance = await connection.getBalance(wallet.publicKey);
    if (balance === 0) {
        alert("You have 0 SOL on Devnet. Please get some Devnet SOL from a faucet (e.g., faucet.solana.com) to pay for transaction fees.");
        return;
    }

    setLoading(true);
    try {
      const provider = new AnchorProvider(connection, wallet as any, AnchorProvider.defaultOptions());

      // Ensure we use the correct Program ID from the IDL
      const program = new Program(idl as any, provider) as Program<Escrow>;

      console.log("Initializing Gig with Program ID:", program.programId.toString());

      let workerPubkey: web3.PublicKey;
      try {
        workerPubkey = new web3.PublicKey(worker);
      } catch (err) {
        alert("Invalid Worker Public Key. Please check the address.");
        setLoading(false);
        return;
      }

      // Derive PDA seeds matching lib.rs
      const [gigAccount] = web3.PublicKey.findProgramAddressSync(
        [Buffer.from("gig"), (wallet as any).publicKey.toBuffer(), workerPubkey.toBuffer()],
        program.programId
      );

      const amountLamports = new BN(Math.floor(parseFloat(budget) * web3.LAMPORTS_PER_SOL));

      const tx = await program.methods
        .createGig(amountLamports)
        .accounts({
          gigAccount,
          employer: (wallet as any).publicKey,
          worker: workerPubkey,
          systemProgram: web3.SystemProgram.programId,
        } as any)
        .rpc();

      alert("Hired! 50% Upfront Sent. TX: " + tx);
      setWorker("");
      setBudget("");
    } catch (e) {
      console.error('Hire transaction failed', e);

      // Try to extract simulation logs when possible (SendTransactionError)
      try {
        // Some errors (SendTransactionError) expose a getLogs() helper
        if (e && typeof (e as any).getLogs === 'function') {
          const logs = await (e as any).getLogs();
          console.error('Transaction simulation logs:', logs);
          const joined = Array.isArray(logs) ? logs.join('\n') : String(logs);

          if (joined.includes('Attempt to debit an account but found no record of a prior credit')) {
            alert('Transaction failed: Insufficient funds to perform this operation. Please top up your wallet or ensure you have enough SOL for the transaction and rent exemptions.\n\nDetails will be available in console logs.');
          } else {
            alert('Transaction simulation failed. Check console logs for details.');
          }

          return;
        }

        // Some providers return logs on the error object
        if (e && (e as any).logs) {
          const logs = (e as any).logs;
          console.error('Error logs:', logs);
          const joined = Array.isArray(logs) ? logs.join('\n') : String(logs);

          if (joined.includes('Attempt to debit an account but found no record of a prior credit')) {
            alert('Transaction failed: Insufficient funds. Please top up your wallet and try again.');
          } else {
            alert('Transaction failed: ' + ((e as any).message || joined));
          }

          return;
        }

        // Specific message pattern fallback
        const msg = (e && (e as any).message) ? (e as any).message : String(e);
        if (msg.includes('Attempt to debit an account but found no record of a prior credit')) {
          alert('Transaction failed: Insufficient funds. Please top up your wallet.');
        } else if (msg.includes('Simulation failed')) {
          alert('Transaction failed during simulation. See console for logs.');
        } else {
          alert('Transaction failed: ' + msg);
        }
      } catch (inner) {
        console.error('Error while extracting logs', inner);
        alert('Transaction failed and logs could not be extracted. See console for details.');
      }
    } finally {
      setLoading(false);
    }
  };

  return (
 <div className="max-w-md mx-auto relative group">
  {/* Soft Ambient Glow Behind Card */}
  <div className="absolute -inset-1 bg-gradient-to-r from-cyan-500/20 to-emerald-500/20 rounded-[24px] blur-xl opacity-50 group-hover:opacity-100 transition duration-1000"></div>

  <div className="relative p-8 bg-[#0D1117] border border-slate-800 rounded-[22px] shadow-2xl overflow-hidden">

    {/* Background Decorative Element */}
    <div className="absolute top-0 right-0 p-4 opacity-10">
      <ShieldCheck size={120} strokeWidth={1} className="text-cyan-400" />
    </div>

    {/* Header */}
    <div className="mb-10">
      <div className="flex items-center gap-3 mb-3">
        <div className="p-2 bg-cyan-500/10 rounded-lg">
          <Zap size={20} className="text-cyan-400" />
        </div>
        <h2 className="text-xl font-bold tracking-tight text-white">Initiate Secure Gig</h2>
      </div>
      <p className="text-sm text-slate-400 leading-relaxed">
        Deploy a smart-contract vault to lock funds until project milestones are verified.
      </p>
    </div>

    {/* Form Section */}
