          <Wallet size={12} /> Worker Public Key
        </label>
        <div className="relative">
          <input 
            className="w-full px-4 py-3.5 bg-slate-900/80 border border-slate-800 rounded-xl focus:ring-2 focus:ring-cyan-500/20 focus:border-cyan-500/40 focus:outline-none text-slate-200 placeholder-slate-700 transition-all font-mono text-xs" 
