          <input 
            className="w-full pl-4 pr-16 py-4 bg-slate-900/80 border border-slate-800 rounded-xl focus:ring-2 focus:ring-emerald-500/20 focus:border-emerald-500/40 focus:outline-none text-slate-100 text-xl font-semibold transition-all" 
            placeholder="0.00" 
            type="number" 
            value={budget} 
            onChange={e => setBudget(e.target.value)} 
          />
          <div className="absolute right-3 flex items-center gap-2 px-2 py-1 bg-slate-800 rounded-md border border-slate-700">
             <span className="text-[10px] font-bold text-emerald-400">SOL</span>
          </div>
        </div>
      </div>
    </div>

    {/* Security Note / Summary */}
    <div className="mt-8 p-4 bg-slate-950/50 rounded-xl border border-slate-900/50 space-y-3">
       <div className="flex justify-between text-[11px]">
          <span className="text-slate-500">Service Fee</span>
          <span className="text-slate-300">0.005 SOL</span>
       </div>
       <div className="flex justify-between text-[11px]">
          <span className="text-slate-500">Escrow Protection</span>
          <span className="text-emerald-500 font-bold flex items-center gap-1">
            <Lock size={10} /> Enabled
          </span>
       </div>
    </div>

    {/* Main CTA */}
    <button 
      onClick={hire} 
      disabled={loading} 
      className="group relative w-full mt-8 overflow-hidden rounded-xl bg-white p-[1px] transition-all hover:scale-[1.01] active:scale-[0.99] disabled:opacity-50"
    >
      <div className="relative bg-white group-hover:bg-cyan-50 rounded-xl py-4 transition-colors flex items-center justify-center gap-2">
        {loading ? (
          <div className="flex items-center gap-2">
             <div className="w-4 h-4 border-2 border-slate-900 border-t-transparent rounded-full animate-spin" />
             <span className="font-bold text-slate-900 uppercase tracking-tight text-sm">Deploying...</span>
          </div>
        ) : (
          <>
