    <div className="mt-6 flex justify-center gap-4 opacity-40">
       <div className="w-8 h-1 bg-slate-800 rounded-full" />
       <div className="w-8 h-1 bg-slate-800 rounded-full" />
       <div className="w-8 h-1 bg-slate-800 rounded-full" />
