"use client";
import React, { JSX, useEffect, useState } from 'react';
import { useAnchorWallet, useConnection } from '@solana/wallet-adapter-react';
import { Program, AnchorProvider } from '@coral-xyz/anchor';
import idl from '../../idl/escrow.json';

// Buffer Polyfill
import { Buffer } from 'buffer';
if (!(globalThis as any).Buffer) {
  (globalThis as any).Buffer = Buffer;
}

export default function GigDashboard(): JSX.Element {
  const { connection } = useConnection();
  const wallet = useAnchorWallet();
  const [history, setHistory] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (!wallet) return;

    const fetchUserHistory = async () => {
      setLoading(true);
      try {
        const provider = new AnchorProvider(connection, wallet as any, AnchorProvider.defaultOptions());
        const program = new Program(idl as any, provider);

        // Fetch gigs where the user is the EMPLOYER
        const employerGigs = await program.account.gigData.all([
          {
            memcmp: {
              offset: 8, // Skip 8-byte discriminator
              bytes: wallet.publicKey.toBase58(),
            },
          },
        ]);

        // Fetch gigs where the user is the WORKER
        const workerGigs = await program.account.gigData.all([
          {
            memcmp: {
              offset: 8 + 32, // Skip discriminator (8) + Employer pubkey (32)
              bytes: wallet.publicKey.toBase58(),
            },
          },
        ]);

        // Combine and sort by creation (if you have a timestamp) or just list
        setHistory([...employerGigs, ...workerGigs]);
      } catch (err) {
        console.error('History Fetch Error:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchUserHistory();
  }, [wallet, connection]);

  // Helper to parse Anchor Enum Status
  const getStatusString = (statusObj: any) => {
    if (statusObj.active) return "🟢 In Progress";
    if (statusObj.completed) return "✅ Completed & Released";
    if (statusObj.cancelled) return "❌ Cancelled";
    return "Unknown";
  };

  return (
    <div className="mt-8 space-y-6">
      <div className="flex justify-between items-end border-b border-zinc-800 pb-4">
      <div>
        <h2 className="text-2xl font-bold text-white">Your Gig History</h2>
        <p className="text-zinc-500 text-sm">Verified on-chain interactions for {wallet?.publicKey.toString().slice(0,6)}...</p>
      </div>
      {loading && <span className="text-indigo-400 animate-pulse text-xs font-mono">SYNCING_LEDGER...</span>}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
      {history.map((gig, i) => {
        const isEmployer = gig.account.employer.toString() === wallet?.publicKey.toString();
        const hasAbuse = gig.account.workerDelayPoints > 2;

        return (
        <div 
          key={i} 
          className={`p-6 bg-gradient-to-br rounded-2xl border transition-all duration-300 hover:shadow-lg ${
          hasAbuse 
            ? 'from-red-950 to-zinc-900 border-red-700/50 hover:border-red-600' 
            : 'from-zinc-800 to-zinc-900 border-zinc-700 hover:border-zinc-600'
          }`}
        >
          <div className="flex justify-between items-start mb-4">
          <span className={`text-[10px] font-bold px-3 py-1 rounded-full uppercase tracking-widest ${isEmployer ? 'bg-blue-500/20 text-blue-300' : 'bg-purple-500/20 text-purple-300'}`}>
            {isEmployer ? '💼 Hiring' : '👨‍💻 Working'}
          </span>
          <span className="text-xs font-mono text-zinc-400">{getStatusString(gig.account.status)}</span>
          </div>

          <div className="space-y-4">
          <div>
            <p className="text-xs text-zinc-400 mb-2 uppercase tracking-wider">{isEmployer ? 'Worker' : 'Employer'}</p>
            <p className="font-mono text-xs bg-zinc-800/50 px-3 py-2 rounded-lg text-zinc-300 truncate">
            {isEmployer ? gig.account.worker.toString() : gig.account.employer.toString()}
            </p>
          </div>

          <div>
            <p className="text-xs text-zinc-400 mb-2 uppercase tracking-wider">Budget</p>
            <p className="text-2xl font-bold bg-gradient-to-r from-amber-400 to-orange-400 bg-clip-text text-transparent">
            {(gig.account.totalBudget.toNumber() / 1e9).toFixed(2)} SOL
            </p>
          </div>
          </div>

          <div className="mt-5 pt-4 border-t border-zinc-700 space-y-2">
          <div className="flex justify-between items-center text-xs">
            <span className="text-zinc-400">Delay Points</span>
            <span className={`font-bold ${gig.account.workerDelayPoints > 0 ? 'text-amber-400' : 'text-emerald-400'}`}>
            {gig.account.workerDelayPoints}
            </span>
          </div>
          {hasAbuse && (
            <div className="bg-red-500/10 border border-red-500/30 rounded-lg px-3 py-2 text-red-400 text-xs font-semibold flex items-center gap-2">
            <span>🚩</span> Abuse Detected
            </div>
          )}
          </div>
        </div>
        );
      })}

      {!loading && history.length === 0 && (
        <div className="col-span-full text-center py-16 bg-zinc-900/50 border-2 border-dashed border-zinc-700 rounded-2xl">
        <p className="text-zinc-400 text-sm">No transactions found for this wallet on Localnet.</p>
        </div>
      )}
      </div>
    </div>
  );
}

import React from 'react';

export default class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }

  componentDidCatch(error, errorInfo) {
    // Log to console; could be sent to monitoring service
    console.error('Contracts route crashed:', error, errorInfo);
    // Persist last stack for easy copy/paste by the developer
    try {
      const stack = (error && (error.stack || error.message)) || String(error);
      localStorage.setItem('last_error_stack', stack);
    } catch (e) {
      // ignore storage failures
    }
  }

  copyErrorToClipboard = () => {
    const error = this.state.error;
    const stack = (error && (error.stack || error.message)) || String(error || '');
    if (navigator && navigator.clipboard && navigator.clipboard.writeText) {
      navigator.clipboard.writeText(stack).then(() => this.setState({ copied: true })).catch(() => this.fallbackCopy(stack));
    } else {
      this.fallbackCopy(stack);
    }
  }

  fallbackCopy(text) {
    try {
      const el = document.createElement('textarea');
      el.value = text;
      document.body.appendChild(el);
      el.select();
      document.execCommand('copy');
      document.body.removeChild(el);
      this.setState({ copied: true });
    } catch (e) {
      console.error('Copy failed', e);
    }
  }

  render() {
    if (this.state.hasError) {
      const error = this.state.error;
      return (
        <div className="p-6 mt-8 border-t border-gray-700 text-red-500">
          <h2 className="text-lg font-bold">Something went wrong.</h2>
          <p className="text-sm mt-2">The Contracts page hit an error. Try refreshing or navigating back.</p>
          {error && (
            <div className="mt-4 bg-black/60 p-3 rounded text-xs text-yellow-200">
              <div className="flex items-center justify-between">
                <strong className="font-mono">Error Details</strong>
                <div className="flex items-center gap-2">
                  <button onClick={this.copyErrorToClipboard} className="px-3 py-1 bg-slate-700 hover:bg-slate-600 rounded text-[11px]">{this.state.copied ? 'Copied!' : 'Copy details'}</button>
                  <button onClick={() => console.error(error)} className="px-3 py-1 bg-slate-700 hover:bg-slate-600 rounded text-[11px]">Show in console</button>
                </div>
              </div>
              <pre className="whitespace-pre-wrap mt-2 text-[11px]">{String(error && (error.stack || error.message || error))}</pre>
            </div>
          )}
        </div>
      );
    }
    return this.props.children;
  }
}

