// The URL that the TwiML App should point to (your ngrok URL + IVR endpoint)
// We'll fetch the current ngrok URL from the running tunnel or use the one in the script
// For now, let's assume the user has updated the webhook and we can reuse that URL or construct it.
// Ideally, we should query the phone number to see what its Voice URL is, and use that.

async function setupTwimlApp() {
    try {
        console.log('Checking for existing TwiML Apps...');
        const apps = await client.applications.list({ friendlyName: 'GigGuard Browser Dialer' });

        let appSid;

        // We need the current webhook URL. 
        // Let's try to find the phone number and get its Voice URL, as that's what we want to replicate.
        const phoneNumber = process.env.TWILIO_PHONE_NUMBER;
        const incomingNumbers = await client.incomingPhoneNumbers.list({ phoneNumber: phoneNumber });

        let voiceUrl = 'http://demo.twilio.com/docs/voice.xml'; // Default fallback
        let voiceMethod = 'POST';

        if (incomingNumbers.length > 0) {
            voiceUrl = incomingNumbers[0].voiceUrl;
            voiceMethod = incomingNumbers[0].voiceMethod;
            console.log(`Found existing Voice URL from phone number: ${voiceUrl}`);
        } else {
            console.warn('Could not find configured phone number to copy URL from. Please ensure ngrok is running and webhook is set.');
            // Fallback to constructing it if we know the ngrok domain? 
            // For now, let's hope the user ran the update_twilio_webhook.js script.
        }

        if (apps.length > 0) {
            appSid = apps[0].sid;
            console.log(`Found existing TwiML App: ${appSid}`);
            // Update it just in case the URL changed
            await client.applications(appSid).update({
                voiceUrl: voiceUrl,
                voiceMethod: voiceMethod
            });
            console.log(`Updated TwiML App with Voice URL: ${voiceUrl}`);
        } else {
            console.log('Creating new TwiML App...');
            const newApp = await client.applications.create({
                friendlyName: 'GigGuard Browser Dialer',
                voiceUrl: voiceUrl,
                voiceMethod: voiceMethod
            });
            appSid = newApp.sid;
            console.log(`Created new TwiML App: ${appSid}`);
        }

        console.log('\nIMPORTANT: Please add the following line to your .env file:');
        console.log(`TWILIO_TWIML_APP_SID=${appSid}`);
        console.log('\n(I will try to append it automatically if not present)');

        // Append to .env if not present
        const fs = require('fs');
        const path = require('path');
        const envPath = path.join(__dirname, '../.env');

        let envContent = fs.readFileSync(envPath, 'utf8');
        if (!envContent.includes('TWILIO_TWIML_APP_SID')) {
            fs.appendFileSync(envPath, `\nTWILIO_TWIML_APP_SID=${appSid}\n`);
            console.log('Added TWILIO_TWIML_APP_SID to .env');
        } else {
            // Replace existing
            const regex = /TWILIO_TWIML_APP_SID=.*/;
            const newContent = envContent.replace(regex, `TWILIO_TWIML_APP_SID=${appSid}`);
            fs.writeFileSync(envPath, newContent);
            console.log('Updated TWILIO_TWIML_APP_SID in .env');
        }

    } catch (error) {
        console.error('Error setting up TwiML App:', error);
    }
}

setupTwimlApp();

