async function checkTwimlApp() {
    try {
        console.log(`Checking TwiML App: ${twimlAppSid}`);
        const app = await client.applications(twimlAppSid).fetch();

        console.log('\n=== TwiML App Configuration ===');
        console.log(`Friendly Name: ${app.friendlyName}`);
        console.log(`Voice URL: ${app.voiceUrl}`);
        console.log(`Voice Method: ${app.voiceMethod}`);
        console.log(`Status URL: ${app.statusCallback}`);
        console.log(`SID: ${app.sid}`);
        console.log('================================\n');

        // Test the voice URL
        console.log(`Testing Voice URL: ${app.voiceUrl}`);
        const https = require('https');
        const http = require('http');
        const url = require('url');

        const parsedUrl = url.parse(app.voiceUrl);
        const protocol = parsedUrl.protocol === 'https:' ? https : http;

        const options = {
            hostname: parsedUrl.hostname,
            port: parsedUrl.port,
            path: parsedUrl.path,
            method: 'POST',
            headers: {
                'Content-Type': 'application/x-www-form-urlencoded',
                'Content-Length': Buffer.byteLength('From=+1234567890'),
                'ngrok-skip-browser-warning': 'true'
            }
        };

        const req = protocol.request(options, (res) => {
            let data = '';
            res.on('data', (chunk) => {
                data += chunk;
            });
            res.on('end', () => {
                console.log(`Status Code: ${res.statusCode}`);
                console.log(`Response:\n${data.substring(0, 500)}`);
            });
        });

        req.on('error', (error) => {
            console.error(`Error testing Voice URL: ${error.message}`);
        });

        req.write('From=+1234567890');
        req.end();

    } catch (error) {
        console.error('Error:', error.message);
    }
}

