const express = require('express');
const twilio = require('twilio');
const path = require('path');
const dotenv = require('dotenv');

// Load environment variables from the root .env file
dotenv.config({ path: path.join(__dirname, '../.env') });

const app = express();
const port = 3001; // Running on a separate port

app.use(express.static(path.join(__dirname, 'public')));
app.use(express.json());

// Serve Twilio SDK from node_modules to avoid CDN issues
app.get('/twilio.min.js', (req, res) => {
    res.sendFile(path.join(__dirname, 'node_modules/@twilio/voice-sdk/dist/twilio.min.js'));
});

// Endpoint to generate Access Token
app.get('/token', async(req, res) => {
    try {
        const accountSid = process.env.TWILIO_ACCOUNT_SID;
        const authToken = process.env.TWILIO_AUTH_TOKEN;
        const twimlAppSid = process.env.TWILIO_TWIML_APP_SID;

        if (!accountSid || !authToken || !twimlAppSid) {
            return res.status(500).json({ error: 'Missing Twilio credentials or TwiML App SID in .env' });
        }

        // We need an API Key and Secret for AccessToken
        // For this demo, we'll generate a temporary one or use one if provided
        // To keep it simple for the hackathon, we'll create a new key if not in env, 
        // but ideally we should have them in .env. 
        // Let's try to create a volatile one or check if we can use the main auth token (not for AccessToken).

        // NOTE: In a real app, store API_KEY and API_SECRET in .env.
        // Here, we will assume the user has set TWILIO_API_KEY and TWILIO_API_SECRET.
        // If not, we will try to create one on the fly (which is slow) or fail.

        let apiKey = process.env.TWILIO_API_KEY;
        let apiSecret = process.env.TWILIO_API_SECRET;

        if (!apiKey || !apiSecret) {
            // Fallback: Create a temporary key (Not recommended for production but works for quick demo)
            const client = twilio(accountSid, authToken);
            const newKey = await client.newKeys.create({ friendlyName: 'Browser Dialer Temp Key' });
            apiKey = newKey.sid;
            apiSecret = newKey.secret;
            console.log('Created temporary API Key for this session.');
        }

        const AccessToken = twilio.jwt.AccessToken;
        const VoiceGrant = AccessToken.VoiceGrant;

        const voiceGrant = new VoiceGrant({
            outgoingApplicationSid: twimlAppSid,
            incomingAllow: true, // Allow incoming calls to this client
        });

        const token = new AccessToken(
            accountSid,
            apiKey,
            apiSecret, { identity: 'browser_user_' + Math.floor(Math.random() * 1000) }
        );

        token.addGrant(voiceGrant);

        res.json({ token: token.toJwt() });

    } catch (error) {
        console.error('Error generating token:', error);
        res.status(500).json({ error: error.message });
    }
});

app.listen(port, () => {
    console.log(`Browser Dialer running at http://localhost:${port}`);
});

