const statusDiv = document.getElementById('status');
const btnCall = document.getElementById('btn-call');
const btnHangup = document.getElementById('btn-hangup');
const logDiv = document.getElementById('log');
const keypadDiv = document.getElementById('keypad');

let device;
let currentCall = null;

function log(message) {
    const entry = document.createElement('div');
    entry.textContent = `> ${message}`;
    logDiv.appendChild(entry);
    logDiv.scrollTop = logDiv.scrollHeight;
}

function updateStatus(status, className) {
    statusDiv.textContent = status;
    statusDiv.className = `status ${className}`;
}

async function startup() {
    log('Requesting access token...');
    try {
        const response = await fetch('/token');
        const data = await response.json();

        if (data.error) {
            log('Error: ' + data.error);
            updateStatus('Error', 'offline');
            return;
        }

        log('Token received. Initializing Twilio Device...');
        device = new Twilio.Device(data.token, {
            // Set Opus as our preferred codec. Opus generally performs better, requiring less bandwidth and providing better audio quality in restrained network conditions.
            codecPreferences: ["opus", "pcmu"],
            // Enable debug logging
            debug: true
        });

        device.on('registered', function(device) {
            log('Twilio.Device Ready!');
            updateStatus('Ready to Call', 'ready');
            btnCall.disabled = false;
        });

        device.on('error', function(error) {
            log('Twilio.Device Error: ' + error.message);
            updateStatus('Error', 'offline');
        });

        // device.connect() returns a Call object, but we can also listen for global connect events
        // Note: In v2, it's often better to handle the call object directly, but this works for simple demos
        // However, let's attach listeners to the call object returned by connect() for better control

        // Bind button events
        btnCall.onclick = async function() {
            log('Calling IVR...');
            try {
                // Connect to the TwiML App
                const call = await device.connect();
                currentCall = call;

                call.on('accept', () => {
                    log('Successfully established call!');
                    updateStatus('On Call', 'on-call');
                    btnCall.style.display = 'none';
                    btnHangup.style.display = 'block';
                    keypadDiv.classList.add('active');
                });

                call.on('disconnect', () => {
                    log('Call ended.');
                    updateStatus('Ready to Call', 'ready');
                    btnCall.style.display = 'block';
                    btnHangup.style.display = 'none';
                    keypadDiv.classList.remove('active');
                    currentCall = null;
                });

                call.on('error', (error) => {
                    log('Call Error: ' + error.message);
                });

            } catch (error) {
                log('Connection failed: ' + error.message);
            }
        };

        btnHangup.onclick = function() {
            log('Hanging up...');
            device.disconnectAll();
            currentCall = null;
        };

        // Register the device
        device.register();

    } catch (err) {
        log('Setup failed: ' + err);
        updateStatus('Setup Failed', 'offline');
    }
}

// Send DTMF digit during active call
function sendDigit(digit) {
    if (currentCall) {
        currentCall.sendDigits(digit);
        log(`Sent digit: ${digit}`);
    } else {
        log('No active call to send digits');
    }
}

// Wait for window load to ensure external scripts are loaded
window.addEventListener('load', () => {
    if (typeof Twilio === 'undefined') {
        log('Error: Twilio SDK not loaded. Check your internet connection.');
        updateStatus('SDK Error', 'offline');
    } else {
        startup();
    }
});
// Call Me Feature - Load registered workers
async function loadWorkers() {
    const workersList = document.getElementById('workers-list');
    workersList.innerHTML = '<div style="text-align: center; color: #999; padding: 20px;">Loading workers...</div>';

    try {
        const response = await fetch('http://localhost:3000/api/v1/ivr/workers');
        const data = await response.json();

        if (data.success && data.workers && data.workers.length > 0) {
            displayWorkers(data.workers);
        } else {
            workersList.innerHTML = '<div style="text-align: center; color: #999; padding: 20px;">No registered workers found. Register via IVR first!</div>';
        }
    } catch (error) {
        console.error('Error loading workers:', error);
        workersList.innerHTML = '<div style="text-align: center; color: #f44336; padding: 20px;">Error loading workers. Make sure backend is running on port 3000.</div>';
    }
}

function displayWorkers(workers) {
    const workersList = document.getElementById('workers-list');

    workersList.innerHTML = workers.map(worker => {
        const skills = worker.skills || [];
        const skillsHTML = skills.length > 0 ?
            skills.map(skill => `<span class="skill-tag">${skill}</span>`).join('') :
            '<span style="color: #999; font-size: 0.85rem;">No skills listed</span>';

        return `
            <div class="worker-card">
                <div class="worker-name">${worker.name || 'Unnamed Worker'}</div>
                <div class="worker-info">📞 ${worker.phone || 'No phone'}</div>
                <div class="worker-info">👤 ${worker.role || 'WORKER'}</div>
                <div class="worker-skills">
                     ${skillsHTML}
                </div>
                <button 
                    class="btn-call-worker" 
                    data-worker-id="${worker.id}"
                    data-worker-phone="${worker.phone || ''}"
                    data-worker-name="${worker.name || ''}"
                    id="call-btn-${worker.id}"
                >
                    📞 Call ${worker.name}
                </button>
                <div id="status-${worker.id}" style="margin-top: 5px; font-size: 0.85rem; color: #28a745;"></div>
            </div>
        `;
    }).join('');

    // Add event listeners to all call buttons
    document.querySelectorAll('.btn-call-worker').forEach(button => {
        button.addEventListener('click', function() {
            const workerId = this.dataset.workerId;
            const phone = this.dataset.workerPhone;
            const name = this.dataset.workerName;
            callWorker(workerId, phone, name);
        });
    });
}

async function callWorker(workerId, phone, name) {
    const button = document.getElementById(`call-btn-${workerId}`);
    const statusDiv = document.getElementById(`status-${workerId}`);

    if (!button || !statusDiv) {
        console.error('Button or status div not found for worker:', workerId);
        return;
    }

    button.disabled = true;
    button.textContent = '📞 Calling...';
    statusDiv.textContent = 'Initiating call...';
    statusDiv.style.color = '#ffc107';

    try {
        const response = await fetch('http://localhost:3000/api/v1/ivr/trigger-call', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({ userId: workerId })
        });

        const data = await response.json();

        if (data.success) {
            statusDiv.textContent = `✅ Call initiated to ${phone}`;
            statusDiv.style.color = '#28a745';
            button.textContent = `✅ Called ${name}`;

            setTimeout(() => {
                button.disabled = false;
                button.textContent = `📞 Call ${name}`;
                statusDiv.textContent = '';
            }, 5000);
        } else {
            throw new Error(data.error || 'Failed to initiate call');
        }
    } catch (error) {
        console.error('Error calling worker:', error);
        statusDiv.textContent = `❌ Error: ${error.message}`;
        statusDiv.style.color = '#f44336';
        button.disabled = false;
        button.textContent = `📞 Call ${name}`;
    }
}

