window.addEventListener('load', () => {
    setTimeout(loadWorkers, 1000);
});

const nodemailer = require('nodemailer');
const twilioConfig = require('../config/twilio');
const userRepository = require('../repositories/user.repository');
const jobRepository = require('../repositories/job.repository');
const logger = require('../libs/logger');

class NotificationService {
    constructor() {
        // Initialize Nodemailer Transporter
        // For Hackathon: Using Ethereal (fake SMTP) if no real creds provided
        // You can replace this with Gmail or SendGrid credentials in .env
        this.transporter = nodemailer.createTransport({
            host: process.env.SMTP_HOST || 'smtp.ethereal.email',
            port: process.env.SMTP_PORT || 587,
            auth: {
                user: process.env.SMTP_USER || 'ethereal_user',
                pass: process.env.SMTP_PASS || 'ethereal_pass'
            }
        });
    }

    async sendEmail(to, subject, body) {
        try {
            const info = await this.transporter.sendMail({
                from: '"GigGuard" <no-reply@gigguard.com>',
                to: to,
                subject: subject,
                text: body, // plain text body
                html: `<p>${body}</p>` // html body
            });
            logger.info(`Email sent: ${info.messageId}`);
            // Preview only available when sending through an Ethereal account
            if (process.env.SMTP_HOST && process.env.SMTP_HOST.includes('ethereal')) {
                logger.info(`Preview URL: ${nodemailer.getTestMessageUrl(info)}`);
            }
        } catch (error) {
            logger.error(error, 'Failed to send email');
        }
    }

    async sendSMS(to, message) {
        try {
            await twilioConfig.client.messages.create({
                body: message,
                from: twilioConfig.phoneNumber,
                to: to
            });
            logger.info(`SMS sent to ${to}`);
        } catch (error) {
            logger.error(error, `Failed to send SMS to ${to}`);
        }
    }

    async notifyWorkerByCall(workerId, jobId) {
        try {
            const worker = await userRepository.findById(workerId);
            const job = await jobRepository.findById(jobId);

            if (!worker || !job) {
                logger.error('Worker or Job not found for call notification');
                return;
            }

            const baseUrl = process.env.BASE_URL || 'http://localhost:3000';
            const call = await twilioConfig.client.calls.create({
                url: `${baseUrl}/api/v1/ivr/offer-job?jobId=${job.id}`,
                to: worker.phone,
                from: twilioConfig.phoneNumber
            });

            logger.info(`Call initiated to ${worker.phone} for job ${job.id}. Call SID: ${call.sid}`);
        } catch (error) {
            logger.error(error, `Failed to initiate call to worker ${workerId}`);
        }
    }
}

