const OpenAI = require('openai');
const config = require('../config');
const logger = require('../libs/logger');
const prisma = require('../libs/prisma');

const openai = new OpenAI({
    apiKey: config.openai.apiKey,
});

class AIService {
    async generateEmbedding(text) {
        try {
            if (!text) return null;
            // Clean text
            const cleanText = text.replace(/\n/g, ' ');
            const response = await openai.embeddings.create({
                model: 'text-embedding-ada-002',
                input: cleanText,
            });
            return response.data[0].embedding;
        } catch (error) {
            logger.error(error, 'Failed to generate embedding');
            return null;
        }
    }

    async updateEmbedding(table, id, embedding) {
        if (!embedding) return;

        try {
            const vectorString = `[${embedding.join(',')}]`;
            const tableName = table === 'user' ? 'users' : 'jobs';

            await prisma.$executeRawUnsafe(
                `UPDATE "${tableName}" SET embedding = $1::vector WHERE id = $2`,
                vectorString,
                id
            );
        } catch (error) {
            logger.error(error, `Failed to update embedding for ${table} ${id}`);
        }
    }

    async matchJobs(freelancerSkills, freelancerBio) {
        try {
            const text = `${freelancerSkills.join(' ')} ${freelancerBio || ''}`;
            const embedding = await this.generateEmbedding(text);

            if (!embedding) return [];

            const vectorString = `[${embedding.join(',')}]`;

            const jobs = await prisma.$queryRaw `
        SELECT id, title, description, budget, created_at as "createdAt",
        1 - (embedding <=> ${vectorString}::vector) as similarity
        FROM jobs
        WHERE status = 'OPEN'
        ORDER BY similarity DESC
        LIMIT 5;
      `;

            return jobs;
        } catch (error) {
            logger.error(error, 'Failed to match jobs');
            return [];
        }
    }

    async matchFreelancers(jobDescription, skillsRequired) {
        try {
            const text = `${skillsRequired.join(' ')} ${jobDescription}`;
            const embedding = await this.generateEmbedding(text);

            if (!embedding) return [];

            const vectorString = `[${embedding.join(',')}]`;

            // Updated query to match 'WORKER' role and return phone/email for notification logic
            const freelancers = await prisma.$queryRaw `
        SELECT id, name, bio, role, phone, email,
        1 - (embedding <=> ${vectorString}::vector) as similarity
        FROM users
        WHERE role = 'WORKER'
        ORDER BY similarity DESC
        LIMIT 5;
      `;

            return freelancers;
        } catch (error) {
            logger.error(error, 'Failed to match freelancers');
            return [];
        }
    }

    async searchJobs(query) {
        try {
            const embedding = await this.generateEmbedding(query);

            if (!embedding) return [];

            const vectorString = `[${embedding.join(',')}]`;

            const jobs = await prisma.$queryRaw `
        SELECT id, title, description, budget, created_at as "createdAt",
        1 - (embedding <=> ${vectorString}::vector) as similarity
        FROM jobs
        WHERE status = 'OPEN'
        ORDER BY similarity DESC
        LIMIT 10;
      `;

            return jobs;
        } catch (error) {
            logger.error(error, 'Failed to search jobs');
            return [];
        }
    }

    async generateContract(description, clientName, freelancerName, amount) {
        try {
            const prompt = `
        Generate a professional legal service contract in HTML format based on the following details:
        Client: ${clientName}
        Freelancer: ${freelancerName}
        Project Description: ${description}
        Agreed Amount: ${amount} USD

        The contract MUST follow this specific visual theme and structure:
        - Use a clean, professional font (serif for body, sans-serif for headers).
        - Background: White.
        - Header: A full-width header bar with background color #E6B8A2 (peach/light brown).
        - Title: "CLIENT AGREEMENT" centered in the header, large font, uppercase.
        - Sub-header: "MIDDLEMEN" centered below the title, slightly smaller, spaced out letters.
        - Content:
            - A table or grid section listing "The Virtual Assistant" (Freelancer) and "The Client" details side-by-side. Use a light peach background (#F5E6E0) for the table headers.
            - Section 1: DESCRIPTION OF SERVICES. Bold uppercase header.
            - A list of duties/deliverables based on the project description.
            - Section 2: PAYMENT TERMS. Include the amount (${amount} USD) and that it is Escrow backed.
            - Section 3: TIMELINE/DEADLINE.
            - Section 4: DISPUTE RESOLUTION (Arbitration via GigGuard AI).
            - Section 5: TERMINATION.
            - Signatures section at the bottom.

        Return ONLY the HTML code with inline CSS. No markdown formatting.
      `;

            const response = await openai.chat.completions.create({
                model: 'gpt-3.5-turbo',
                messages: [{ role: 'user', content: prompt }],
            });

            return response.choices[0].message.content;
        } catch (error) {
            logger.error(error, 'Failed to generate contract');
            throw error;
        }
    }

    async analyzeDispute(disputeDetails, evidence) {
        try {
            const prompt = `
        You are an AI Arbitrator for GigGuard. Analyze the following dispute and provide a fair verdict based on these scenarios:
        1. Non-Payment
        2. Partial Work
        3. Quality Dispute
        4. Scope Creep
        5. Abandonment
        6. Late Delivery

        Dispute Details: ${JSON.stringify(disputeDetails)}
        Evidence: ${JSON.stringify(evidence)}

        Provide a JSON response with:
        - verdict (string): "PAY_FREELANCER", "REFUND_CLIENT", "SPLIT"
        - confidence (number): 0-100
        - reasoning (string): Explanation of the decision
        - recommendedAction (string): Specific payment distribution
      `;

            const response = await openai.chat.completions.create({
                model: 'gpt-3.5-turbo',
                messages: [{ role: 'user', content: prompt }],
            });

            const content = response.choices[0].message.content;
            try {
                return JSON.parse(content);
            } catch (e) {
                return { verdict: 'MANUAL_REVIEW', reasoning: content };
            }
        } catch (error) {
            logger.error(error, 'Failed to analyze dispute');
            throw error;
        }
    }

    async parseVoiceRegistration(transcript) {
        try {
            const prompt = `
                Extract the user's Name and Skills from this voice transcript.
                Transcript: "${transcript}"

                Return a JSON object with:
                - name (string): The person's name. If not found, use "Unknown Worker".
                - skills (array of strings): List of skills mentioned (e.g., ["Carpenter", "Plumber"]).
            `;

            const response = await openai.chat.completions.create({
                model: 'gpt-3.5-turbo',
                messages: [{ role: 'user', content: prompt }],
            });

            const content = response.choices[0].message.content;
            try {
                return JSON.parse(content);
            } catch (e) {
                logger.error(e, 'Failed to parse JSON from AI');
                return { name: "Unknown Worker", skills: [] };
            }
        } catch (error) {
            logger.error(error, 'Failed to parse voice registration');
            return { name: "Unknown Worker", skills: [] };
        }
    }

    async checkJobWorkerCompatibility(jobId, workerId) {
        try {
            // 1. Get Job Embedding
            const job = await prisma.job.findUnique({
                where: { id: jobId },
                select: { embedding: true } // Assuming embedding is available on the model, though it might be raw
            });

            // 2. Get Worker Embedding
            const worker = await prisma.user.findUnique({
                where: { id: workerId },
                select: { embedding: true }
            });

            // If either is missing embedding, we can't check, so we might default to TRUE or FALSE.
            // For strict mode, default to FALSE.
            // However, prisma might not return the vector field directly if it's unsupported in the client type.
            // We should use $queryRaw to be safe as seen in other methods.

            const result = await prisma.$queryRaw `
                SELECT 1 - (j.embedding <=> w.embedding) as similarity
                FROM jobs j, users w
                WHERE j.id = ${jobId} AND w.id = ${workerId}
            `;

            if (result.length === 0) return false;

            const similarity = result[0].similarity;
            logger.info(`Compatibility check: Job ${jobId} vs Worker ${workerId} = ${similarity}`);

            // Threshold can be adjusted. 0.6 is a reasonable start for "relatable".
            return similarity > 0.6;

        } catch (error) {
            logger.error(error, 'Failed to check job-worker compatibility');
            // If error (e.g. embeddings not generated yet), maybe allow or deny?
            // Let's allow for now to avoid blocking if embeddings are missing, 
            // BUT the user asked "only then if...". So strictly we should return false.
            // But for demo stability, if embeddings are missing, we might want to fallback to text match?
            // Let's return false to be strict as requested.
            return false;
        }
    }
}

