class DisputeService {
    async raiseDispute(data) {
        return disputeRepository.create(data);
    }

    async getDispute(id) {
        return disputeRepository.findById(id);
    }

    async getDisputes(filter) {
        return disputeRepository.findAll(filter);
    }

    async generateVerdict(disputeId) {
        const dispute = await disputeRepository.findById(disputeId);
