const prisma = require('../libs/prisma');
const aiService = require('./ai.service');
const authService = require('./auth.service');
const jobRepository = require('../repositories/job.repository');

class VoiceService {
    // 1. Registration via Call
    async registerUserFromVoice(phoneNumber, transcript, enteredPhoneNumber) {
        // Use entered phone number if provided, otherwise use caller phone
        const actualPhone = enteredPhoneNumber || phoneNumber;

        // Check if user exists
        let user = await prisma.user.findUnique({ where: { phone: actualPhone } });
        if (user) {
            return { message: `Welcome back, ${user.name}.` };
        }

        // Parse transcript using AI
        const { name, skills } = await aiService.parseVoiceRegistration(transcript);

        // Create user (auto-generate password for voice users)
        const password = Math.random().toString(36).slice(-8);

        // Register using AuthService logic (handles hashing, etc.)
        const { user: newUser } = await authService.register({
            phone: actualPhone,
            name,
            password,
            role: 'WORKER'
        });

        // Create Worker profile with skills
        try {
            await prisma.worker.create({
                data: {
                    userId: newUser.id,
                    skills: skills
                }
            });
        } catch (error) {
            console.error("Failed to create worker profile", error);
        }

        // Generate embedding for the user based on skills
        const embedding = await aiService.generateEmbedding(skills.join(' '));
        if (embedding) {
            await aiService.updateEmbedding('user', newUser.id, embedding);
        }

        return {
            message: `Registration successful. Welcome ${name}. You are registered as a ${skills.join(', ')}.`,
            userId: newUser.id
        };
    }

    // 2. Job Alerts via Call
    async getJobAlerts(phoneNumber) {
        const user = await prisma.user.findUnique({ where: { phone: phoneNumber } });
        if (!user) return { message: "User not found. Please register first." };

        // Find matching jobs using vector search (if user has embedding)
        // Since we don't have a direct 'skills' field on User in the schema shown earlier (only on Job),
        // we rely on the embedding we hopefully created during registration.

        // For this MVP, let's just fetch open jobs. In production, use vector search.
        const jobs = await jobRepository.findAll({ status: 'OPEN' });

        if (jobs.length === 0) return { message: "No jobs available right now." };

        // Format for voice output
        const jobList = jobs.slice(0, 3).map((job, index) => {
            return `Job ${index + 1}: ${job.title} for ${job.budget} rupees.`;
        }).join(' ... ');

        return {
            message: `Here are the jobs for you: ${jobList}. Press 1, 2, or 3 to accept.`,
            jobs: jobs.slice(0, 3)
        };
    }

    // 3. Accept Job via Keypad Input
    async acceptJob(phoneNumber, jobIndex) {
        const user = await prisma.user.findUnique({ where: { phone: phoneNumber } });
        if (!user) return { message: "User not found." };

        // Re-fetch jobs to map index to ID (stateful IVR is complex, simplifying here)
        // In a real IVR, we'd pass the Job IDs in the session context.
        const jobs = await jobRepository.findAll({ status: 'OPEN' });
        const job = jobs[jobIndex - 1];

        if (!job) return { message: "Invalid selection." };

        // Assign job
        await jobRepository.update(job.id, {
            workerId: user.id,
            status: 'IN_PROGRESS'
        });

        return { message: `You have accepted the job: ${job.title}. The client will contact you shortly.` };
    }
}

