const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');
const userRepository = require('../repositories/user.repository');
const notificationService = require('./notification.service');
const config = require('../config');

class AuthService {
    async register(data) {
        const { email, phone, password, name, role } = data;

        if (email) {
            const existingEmail = await userRepository.findByEmail(email);
            if (existingEmail) {
                const error = new Error('User with this email already exists');
                error.status = 409;
                throw error;
            }
        }

        if (phone) {
            const existingPhone = await userRepository.findByPhone(phone);
            if (existingPhone) {
                const error = new Error('User with this phone already exists');
                error.status = 409;
                throw error;
            }
        }

        const hashedPassword = await bcrypt.hash(password, 10);
        const user = await userRepository.create({
            email,
            phone,
            password: hashedPassword,
            name,
            role: role || 'WORKER',
            onboardingStatus: 'PENDING',
        });

        // Send Welcome Notification (don't block registration if notification fails)
        if (phone) {
            notificationService.sendSMS(phone, `Welcome to GigGuard, ${name}! Your account has been created.`).catch(() => {
                // Silently ignore SMS errors (e.g., unverified numbers on trial account)
            });
        } else if (email) {
            notificationService.sendEmail(email, 'Welcome to GigGuard', `Hi ${name}, welcome to GigGuard!`).catch(() => {
                // Silently ignore email errors
            });
        }

        return this.generateToken(user);
    }

    async login(identifier, password) {
        // identifier can be email or phone
        let user = await userRepository.findByEmail(identifier);
        if (!user) {
            user = await userRepository.findByPhone(identifier);
        }

        if (!user) {
            const error = new Error('Invalid credentials');
            error.status = 401;
            throw error;
        }

        const isPasswordValid = await bcrypt.compare(password, user.password);
        if (!isPasswordValid) {
            const error = new Error('Invalid credentials');
            error.status = 401;
            throw error;
        }

        return this.generateToken(user);
    }

    generateToken(user) {
        const token = jwt.sign({ userId: user.id, role: user.role },
            config.jwtSecret, { expiresIn: config.jwtExpiresIn }
        );
        return { user, token };
    }
}

