const prisma = require('../libs/prisma');

class GamificationService {
    async calculateWorkerStats(workerId) {
        const worker = await prisma.user.findUnique({
            where: { id: workerId },
            include: {
                jobsAsWorker: {
                    include: {
                        escrowTransactions: {
                            include: {
                                disputes: true
                            }
                        }
                    }
                }
            }
        });

        if (!worker) throw new Error('Worker not found');

        const jobs = worker.jobsAsWorker;
        const completedJobs = jobs.filter(j => j.status === 'COMPLETED');
        const completedCount = completedJobs.length;
        const totalJobs = jobs.length;

        // 1. Calculate Level
        // Level up every 5 jobs
        const level = Math.floor(completedCount / 5) + 1;

        // 2. Calculate Stats

        // Reliability: Completion Rate
        let reliability = 100;
        if (totalJobs > 0) {
            reliability = Math.round((completedCount / totalJobs) * 100);
        }

        // Quality: Based on Trust Score (which decreases on disputes/cancellations)
        const quality = worker.trustScore;

        // Speed: Placeholder logic (in real app, compare actual vs expected time)
        // For now, we'll base it on how many jobs were completed within 3 days (arbitrary)
        // or just map it to reliability for simplicity in this MVP
        const speed = Math.max(70, Math.min(100, reliability - 5 + Math.floor(Math.random() * 10)));

        // 3. Badges
        const badges = [];

        if (completedCount >= 1) badges.push('First Job Done');
        if (completedCount >= 10) badges.push('Seasoned Pro');
        if (completedCount >= 50) badges.push('Veteran');

        if (quality >= 90) badges.push('Top Rated');
        if (quality >= 98) badges.push('5-Star Streak');

        // Check disputes
        let disputeCount = 0;
        jobs.forEach(job => {
            job.escrowTransactions.forEach(tx => {
                disputeCount += tx.disputes.length;
            });
        });

        if (completedCount > 5 && disputeCount === 0) {
            badges.push('Dispute-Free');
        }

        if (level >= 5) badges.push('Level 5 Master');

        return {
            workerId,
            name: worker.name,
            level: `Level ${level} ${this.getLevelTitle(level)}`,
            stats: {
                reliability,
                quality,
                speed
            },
            badges,
            completedJobs: completedCount
        };
    }

    getLevelTitle(level) {
        if (level === 1) return 'Novice';
        if (level <= 3) return 'Apprentice';
        if (level <= 5) return 'Journeyman';
        if (level <= 8) return 'Expert';
        return 'Master';
    }
}

