const jobRepository = require('../repositories/job.repository');
const aiService = require('./ai.service');
const notificationService = require('./notification.service');
const logger = require('../libs/logger');

class JobService {
    async createJob(data) {
        // Generate embedding from title + description
        const embedding = await aiService.generateEmbedding(`${data.title} ${data.description}`);

        // Create job
        const job = await jobRepository.create(data);

        // Update embedding
        if (embedding) {
            await aiService.updateEmbedding('job', job.id, embedding);
        }

        // Trigger proactive notification for matching workers
        this.notifyMatchingWorkers(job);

        return job;
    }

    async notifyMatchingWorkers(job) {
        try {
            // Find matching workers using AI service
            // Verified: matchFreelancers queries for users with role 'WORKER' which matches our schema.
            const matchingWorkers = await aiService.matchFreelancers(job.description, job.skills || []);

            for (const worker of matchingWorkers) {
                // Only call if they don't have an email (feature phone user) OR explicitly for high match
                // For this demo, we prioritize those without email as "call-only"
                if (!worker.email && worker.phone) {
                    // Send SMS as requested
                    const message = `You are up for the job ${job.title}... ${job.description ? job.description.substring(0, 50) + '...' : ''}`;
                    await notificationService.sendSMS(worker.phone, message);

                    await notificationService.notifyWorkerByCall(worker.id, job.id);
                }
            }
        } catch (error) {
            logger.error(error, 'Failed to notify matching workers');
        }
    }

    async getJob(id) {
        const job = await jobRepository.findById(id);
        if (!job) throw new Error('Job not found');
        return job;
    }

    async getJobs(filter) {
        return jobRepository.findAll(filter);
    }

    async updateJob(id, data) {
        return jobRepository.update(id, data);
    }

    async searchJobs(query) {
        return aiService.searchJobs(query);
    }
}

