const razorpay = require('../libs/razorpay');
const paymentRepository = require('../repositories/payment.repository');
const contractRepository = require('../repositories/contract.repository');
const walletRepository = require('../repositories/wallet.repository');
const crypto = require('crypto');

class PaymentService {
    async createOrder(jobId, amount, contractId) {
        const options = {
            amount: amount * 100, // amount in smallest currency unit
            currency: "INR",
            receipt: `receipt_${jobId.slice(0, 30)}`,
        };

        const order = await razorpay.orders.create(options);

        const transactionData = {
            jobId,
            amount,
            razorpayOrderId: order.id,
            status: 'ORDER_CREATED'
        };
        if (contractId) transactionData.contractId = contractId;

        const transaction = await paymentRepository.createTransaction(transactionData);

        return { order, transaction };
    }

    async releaseFunds(userId, contractId) {
        const contract = await contractRepository.findById(contractId);
        if (!contract) throw { status: 404, message: 'Contract not found' };

        // Check client ID from the associated Job
        if (contract.job.clientId !== userId) throw { status: 403, message: 'Unauthorized' };

        // Check escrow amount (ensure it's a number/decimal)
        if (Number(contract.escrowAmount) <= 0) throw { status: 400, message: 'No funds in escrow' };

        const platformFee = Number(contract.escrowAmount) * 0.03; // 3% Platform Fee
        const amountToFreelancer = Number(contract.escrowAmount) - platformFee;

        // Transfer to Freelancer Wallet (Worker ID from Job)
        if (!contract.job.workerId) throw { status: 400, message: 'No worker assigned to job' };

        await walletRepository.updateBalance(contract.job.workerId, amountToFreelancer);

        // Update Contract
        await contractRepository.update(contractId, {
            escrowAmount: 0,
            status: 'COMPLETED',
        });

        return {
            success: true,
            released: amountToFreelancer,
            fee: platformFee
        };
    }

    async verifyPayment(orderId, paymentId, signature) {
        const secret = process.env.RAZORPAY_KEY_SECRET || 'placeholder';
        const generated_signature = crypto
            .createHmac('sha256', secret)
            .update(orderId + "|" + paymentId)
            .digest('hex');

        if (generated_signature === signature) {
            const transaction = await paymentRepository.findByOrderId(orderId);
            if (transaction) {
                await paymentRepository.updateStatus(transaction.id, 'AUTHORIZED', paymentId);

                // If transaction is linked to a contract, update contract escrow
                if (transaction.contractId) {
                    await contractRepository.update(transaction.contractId, {
                        escrowAmount: transaction.amount,
                        status: 'ACTIVE'
                    });
                }
            }
            return true;
        }
        return false;
    }
}

module.exports = new PaymentService();

const contractRepository = require('../repositories/contract.repository');
const jobRepository = require('../repositories/job.repository');
const userRepository = require('../repositories/user.repository');
const aiService = require('./ai.service');

class ContractService {
    async generateContract(jobId, voiceTranscript, workerId) {
        const job = await jobRepository.findById(jobId);
        if (!job) throw new Error('Job not found');

        // Update job with workerId if provided
        if (workerId) {
            await jobRepository.update(jobId, { workerId });
        }

        const client = await userRepository.findById(job.clientId);

        const description = voiceTranscript || job.description;
        const amount = job.budget;

        const contractHtml = await aiService.generateContract(
            description,
            client.name || "Client",
            "Freelancer",
            amount
        );

        return contractRepository.create({
            jobId,
            voiceTranscript,
            contractHtml,
            escrowAmount: amount,
            status: 'DRAFT'
        });
    }

    async generateAIPreview(description, amount, clientName = "Client", freelancerName = "Freelancer") {
        const html = await aiService.generateContract(
            description,
            clientName,
            freelancerName,
            amount
        );
        return { html };
    }

    async createContract(data) {
        // Semantic Check: Verify if worker is compatible with the job
        if (data.jobId && (data.workerId || data.freelancerId)) {
            const workerId = data.workerId || data.freelancerId;
            // Skip check for temp IDs used in demos
            if (data.jobId !== 'temp-job-id' && workerId !== 'temp-worker-id') {
                const isCompatible = await aiService.checkJobWorkerCompatibility(data.jobId, workerId);
                if (!isCompatible) {
                    throw new Error('Contract denied: Worker profile does not match job requirements sufficiently.');
                }
            }
        }

        if (data.freelancerId) {
            await jobRepository.update(data.jobId, {
                workerId: data.freelancerId,
                status: 'IN_PROGRESS'
            });
        }

        return contractRepository.create({
            jobId: data.jobId,
            contractHtml: data.terms,
            escrowAmount: data.amount,
            status: 'DRAFT'
        });
    }

    async getContract(id) {
        return contractRepository.findById(id);
    }

    async getContracts(filter) {
        return contractRepository.findAll(filter);
    }
}

module.exports = new ContractService();

