class JobRepository {
    async create(data) {
        return prisma.job.create({ data });
    }

    async findById(id) {
        return prisma.job.findUnique({
            where: { id },
            include: { client: true, worker: true }
        });
    }

    async findAll(filter = {}) {
    // Map snake_case query params to Prisma camelCase fields
    const prismaWhere = {};

    if (filter.worker_id) {
        prismaWhere.workerId = filter.worker_id;
    }

    if (filter.client_id) {
        prismaWhere.clientId = filter.client_id;
    }

    // Add other filters as needed, or spread the rest
    // const { worker_id, client_id, ...rest } = filter;

    return prisma.job.findMany({
        where: prismaWhere,
        orderBy: { createdAt: 'desc' }
    });
}

    async update(id, data) {
        return prisma.job.update({
            where: { id },
            data
        });
    }

    async delete(id) {
        return prisma.job.delete({ where: { id } });
    }

    // Vector search using raw query
    async findByEmbedding(embedding, limit = 5) {
        // Note: This requires pgvector extension and proper casting
        // Syntax depends on how prisma handles raw queries with vector
        // This is a simplified example
        const vectorString = `[${embedding.join(',')}]`;
        return prisma.$queryRaw `
      SELECT id, title, description, budget, 1 - (embedding <=> ${vectorString}::vector) as similarity
      FROM jobs
      WHERE status = 'OPEN'
      ORDER BY embedding <=> ${vectorString}::vector
      LIMIT ${limit};
    `;
    }
}

