const gamificationService = require('../../services/gamificationService');
const imageGenerationService = require('../../services/imageGenerationService');
const userRepository = require('../../repositories/user.repository');

class UserController {
    async getById(req, res, next) {
        try {
            const user = await userRepository.findById(req.params.id);
            if (!user) {
                return res.status(404).json({ error: 'User not found' });
            }
            // Remove sensitive data
            const { password, ...userWithoutPassword } = user;
            res.json(userWithoutPassword);
        } catch (error) {
            next(error);
        }
    }

    async update(req, res, next) {
        try {
            const { id } = req.params;
            const updateData = req.body;

            // Remove sensitive fields from update
            delete updateData.password;
            delete updateData.onboardingStatus;
            delete updateData.walletBalance;
            delete updateData.trustScore;

            const user = await userRepository.update(id, updateData);
            const { password, ...userWithoutPassword } = user;

            res.json(userWithoutPassword);
        } catch (error) {
            next(error);
        }
    }

    async completeOnboarding(req, res, next) {
        try {
            const { id } = req.params;

            // Verify user exists and belongs to requester
            if (req.user && req.user.userId !== id) {
                return res.status(403).json({ error: 'Unauthorized' });
            }

            const user = await userRepository.update(id, {
                onboardingStatus: 'COMPLETED'
            });

            const { password, ...userWithoutPassword } = user;
            res.json(userWithoutPassword);
        } catch (error) {
            next(error);
        }
    }

    async getGamifiedCV(req, res, next) {
        try {
            const workerId = req.user.userId;
            const stats = await gamificationService.calculateWorkerStats(workerId);
            const imageBuffer = await imageGenerationService.generateCVImage(stats);

            res.set('Content-Type', 'image/png');
            res.send(imageBuffer);
        } catch (error) {
            next(error);
        }
    }
}

module.exports = new UserController();

const VoiceResponse = require('twilio').twiml.VoiceResponse;
