class IVRController {
    // 1. Handle Incoming Call - Check if user exists first
    async handleIncomingCall(req, res) {
        logger.info('Incoming call received');
        try {
            const callerNumber = req.body.From || req.query.From;
            const twiml = new VoiceResponse();

            // Check if user already exists
            const user = await prisma.user.findUnique({ where: { phone: callerNumber } });

            if (user) {
                // Existing user - show menu
                const gather = twiml.gather({
                    input: 'dtmf',
                    numDigits: 1,
                    action: '/api/v1/ivr/main-menu',
                    timeout: 5
                });
                gather.say(`Welcome back, ${user.name}. Press 1 for job alerts. Press 2 to check your wallet balance. Press 3 to search for jobs. Press 4 to update bank details.`);
                twiml.redirect('/api/v1/ivr/main-menu?timeout=1');
            } else {
                // New user - start registration
                const retry = parseInt(req.query.retry || '0');
                if (retry >= 3) {
                    twiml.say('We are still having trouble hearing you. Please try calling again later.');
                    twiml.hangup();
                } else {
                    const gather = twiml.gather({
                        input: 'speech',
                        action: '/api/v1/ivr/register/name',
                        timeout: 10,
                        speechTimeout: 'auto',
                        language: 'en-US',
                        speechModel: 'phone_call',
                        enhanced: true,
                        profanityFilter: false
                    });

                    if (retry === 0) {
                        gather.say({ voice: 'alice' }, 'Welcome to GigGuard. To register, please say your full name after the beep.');
                        gather.pause({ length: 1 });
                    } else {
                        gather.say({ voice: 'alice' }, 'I did not hear that clearly. Please say your full name slowly and clearly after the beep.');
                        gather.pause({ length: 1 });
                    }
                    twiml.redirect(`/api/v1/ivr/incoming?retry=${retry + 1}`);
                }
            }

            res.type('text/xml');
