        const confidence = req.body.Confidence;
        const callerNumber = req.body.From;

        logger.info(`Speech Result: "${name}", Confidence: ${confidence}`);

        if (name && confidence && parseFloat(confidence) > 0.3) {
            // Ask for skills
            const gather = twiml.gather({
                input: 'speech',
                action: `/api/v1/ivr/register/skills?name=${encodeURIComponent(name)}`,
                timeout: 10,
                speechTimeout: 'auto',
                language: 'en-US',
                speechModel: 'phone_call',
                enhanced: true,
                profanityFilter: false,
                hints: 'Carpenter, Plumber, Electrician, Driver, Painter, Mechanic, Cook, Maid, Construction, Cleaning, Mason, Welder, Gardener'
            });
            gather.say({ voice: 'alice' }, `Thank you, ${name}. Now, please tell us your skills. For example, say Carpenter, or Plumber, or Electrician. Speak after the beep.`);
            gather.pause({ length: 1 });

