            const gather = twiml.gather({
                input: 'speech',
                action: `/api/v1/ivr/register/skills?name=${encodeURIComponent(name)}`,
                timeout: 5,
                language: 'en-IN',
                hints: 'Carpenter, Plumber, Electrician, Driver, Painter, Mechanic, Cook, Maid'
            });

            gather.say('I did not hear that. Please say your skills again, like Carpenter or Plumber.');

            // Loop back if still no input
            twiml.redirect(`/api/v1/ivr/register/skills/retry?name=${encodeURIComponent(name)}&retry=${retry + 1}`);
