    async triggerOutboundCall(req, res) {
        try {
            const { userId } = req.body;
            if (!userId) {
                return res.status(400).json({
                    success: false,
                    error: 'userId is required'
                });
            }

            const user = await prisma.user.findUnique({
                where: { id: userId },
                select: {
                    id: true,
                    name: true,
                    phone: true
                }
            });

            if (!user) {
                return res.status(404).json({
                    success: false,
                    error: 'User not found'
                });
            }

            if (!user.phone) {
                return res.status(400).json({
                    success: false,
                    error: 'User has no phone number registered'
                });
            }

            const call = await twilioClient.client.calls.create({
                to: user.phone,
                from: config.twilio.phoneNumber,
                url: `${config.ngrokUrl}/api/v1/ivr/connect-caller?workerId=${userId}`,
                statusCallback: `${config.ngrokUrl}/api/v1/ivr/call-status`,
                statusCallbackEvent: ['initiated', 'ringing', 'answered', 'completed']
            });

            logger.info(`Outbound call initiated to ${user.phone} (${user.name}) - Call SID: ${call.sid}`);

            res.json({
                success: true,
                message: `Call initiated to ${user.name} at ${user.phone}`,
                callSid: call.sid,
                status: call.status
            });
        } catch (error) {
            logger.error(error, 'Error triggering outbound call');
            res.status(500).json({
                success: false,
                error: error.message || 'Failed to initiate call'
            });
        }
    }

