            const twiml = new VoiceResponse();
            twiml.say('Sorry, there was an error connecting your call.');
            twiml.hangup();
            res.type('text/xml');
            res.send(twiml.toString());
        }
    }

    // Handle browser-initiated calls (TwiML App Voice URL)
    async handleBrowserCall(req, res) {
        try {
            const twiml = new VoiceResponse();
            const workerId = req.query.workerId || req.body.workerId;

            if (workerId) {
                // Browser is calling a specific worker
                const worker = await prisma.user.findUnique({
                    where: { id: workerId },
                    select: { name: true, phone: true }
                });

                if (!worker || !worker.phone) {
                    twiml.say({ voice: 'alice' }, 'Sorry, the worker is not available.');
                    twiml.hangup();
                } else {
                    twiml.say({ voice: 'alice' }, `Connecting you to ${worker.name}. Please wait.`);

                    const dial = twiml.dial({
                        callerId: config.twilio.phoneNumber
                    });
                    dial.number(worker.phone);
                }
            } else {
                // Default: play menu or message
                twiml.say({ voice: 'alice' }, 'Welcome to GigGuard. No worker specified.');
                twiml.hangup();
            }

            res.type('text/xml');
            res.send(twiml.toString());
        } catch (error) {
            logger.error(error, 'Error in handleBrowserCall');
            const twiml = new VoiceResponse();
            twiml.say('Sorry, an error occurred.');
            twiml.hangup();
            res.type('text/xml');
            res.send(twiml.toString());
        }
    }
