const crypto = require('crypto');
const paymentRepository = require('../../repositories/payment.repository');
const logger = require('../../libs/logger');

class WebhookController {
    async handleRazorpay(req, res) {
        const secret = process.env.RAZORPAY_WEBHOOK_SECRET || 'placeholder';
        const signature = req.headers['x-razorpay-signature'];

        const generated_signature = crypto
            .createHmac('sha256', secret)
            .update(JSON.stringify(req.body))
            .digest('hex');

        if (generated_signature !== signature) {
            return res.status(400).json({ error: 'Invalid signature' });
        }

        const event = req.body.event;
        const payload = req.body.payload;

        logger.info(`Received Razorpay webhook: ${event}`);

        if (event === 'payment.captured') {
            const payment = payload.payment.entity;
            const orderId = payment.order_id;

            const transaction = await paymentRepository.findByOrderId(orderId);
            if (transaction) {
                await paymentRepository.updateStatus(transaction.id, 'CAPTURED', payment.id);
            }
        }

        res.json({ status: 'ok' });
    }
}

