class VoiceController {
    async handleWebhook(req, res, next) {
        try {
            // Simulated IVR Webhook Payload
            // {
            //   "caller_number": "+919876543210",
            //   "event": "registration" | "job_alert" | "job_accept",
            //   "transcript": "I am a carpenter...", (for registration)
            //   "input_digit": "1" (for job accept)
            // }

            const { caller_number, event, transcript, input_digit } = req.body;

            let response;

            switch (event) {
                case 'registration':
                    response = await voiceService.registerUserFromVoice(caller_number, transcript);
                    break;
                case 'job_alert':
                    response = await voiceService.getJobAlerts(caller_number);
                    break;
                case 'job_accept':
                    response = await voiceService.acceptJob(caller_number, parseInt(input_digit));
                    break;
                default:
                    response = { message: "Invalid event" };
            }

            res.json({
                success: true,
                voice_response: response.message, // Text to be spoken by TTS
                data: response
            });

        } catch (error) {
            next(error);
        }
    }
}

