const puppeteer = require('puppeteer');
const logger = require('../../libs/logger');

/**
 * Polish text using OpenAI API
 */
async function polishTextWithAI(text) {
    if (!text || text.trim().length === 0) return text;

    try {
        const { default: OpenAI } = await import('openai');
        const openai = new OpenAI({ 
            apiKey: process.env.OPENAI_API_KEY 
        });

        const response = await openai.chat.completions.create({
            model: 'gpt-4o-mini',
            messages: [
                { 
                    role: 'system', 
                    content: 'You are a professional resume writer. Rewrite the content professionally and concisely. Do not add false information. Keep it to 2-3 impactful bullet points or sentences. Focus on achievements and impact.' 
                },
                { 
                    role: 'user', 
                    content: `Rewrite this professionally:\n\n${text}` 
                }
            ],
            max_tokens: 200,
            temperature: 0.7
        });

        return response.choices[0].message.content.trim();
    } catch (error) {
        logger.error('AI polishing failed:', error);
        return text; // Fallback to original text
    }
}

