/**
 * Generate PDF from HTML
 */
async function generatePDF(html) {
    let browser;
    try {
        // Try to use system Chrome or Chromium if puppeteer's Chrome is not available
        const executablePath = process.env.PUPPETEER_EXECUTABLE_PATH || 
                              '/usr/bin/google-chrome-stable' || 
                              '/usr/bin/brave';

        browser = await puppeteer.launch({
            headless: true,
            args: ['--no-sandbox', '--disable-setuid-sandbox', '--disable-dev-shm-usage'],
            executablePath: executablePath
        });

        const page = await browser.newPage();
        await page.setContent(html, { waitUntil: 'networkidle0' });

        const pdf = await page.pdf({
            format: 'A4',
            printBackground: true,
            margin: {
                top: '20px',
                right: '20px',
                bottom: '20px',
                left: '20px'
            }
        });

        await browser.close();
        return pdf;
    } catch (error) {
        if (browser) await browser.close();
        throw error;
    }
}

/**
 * Main CV Generation Controller
 */
exports.generateCV = async (req, res) => {
    try {
        const { name, email, phone, linkedin, skills, education, projects, experience, useAI } = req.body;

        // Validation
        if (!name || !email || !phone) {
            return res.status(400).json({ 
                error: 'Name, email, and phone are required fields' 
            });
        }

        if (!skills || skills.length === 0) {
            return res.status(400).json({ 
                error: 'At least one skill is required' 
            });
        }

        // Check LinkedIn URL validity if provided
        if (linkedin && !linkedin.includes('linkedin.com')) {
            return res.status(400).json({ 
                error: 'Invalid LinkedIn URL' 
            });
        }

        let enhancedData = {};

        // Apply AI enhancement if requested
        if (useAI && process.env.OPENAI_API_KEY) {
            logger.info('Applying AI enhancement to CV content');

            // Enhance project descriptions
            if (projects && projects.length > 0) {
                enhancedData.projects = await Promise.all(
                    projects.map(async (project) => {
                        if (project.description && project.description.trim().length > 0) {
                            const enhanced = await polishTextWithAI(project.description);
                            return { ...project, description: enhanced };
                        }
                        return project;
                    })
                );
            }

            // Enhance experience descriptions
            if (experience && experience.length > 0) {
                enhancedData.experience = await Promise.all(
                    experience.map(async (exp) => {
                        if (exp.description && exp.description.trim().length > 0) {
                            const enhanced = await polishTextWithAI(exp.description);
                            return { ...exp, description: enhanced };
                        }
                        return exp;
                    })
                );
            }
        }

        // Build HTML template
        const html = buildHTMLTemplate(req.body, enhancedData);

        // Generate PDF
        logger.info('Generating PDF for:', name);
        const pdf = await generatePDF(html);

        // Send PDF as response
        res.setHeader('Content-Type', 'application/pdf');
        res.setHeader('Content-Disposition', `attachment; filename="${name.replace(/\s+/g, '_')}_CV.pdf"`);
        res.send(pdf);

        logger.info('CV generated successfully for:', name);
    } catch (error) {
        logger.error('CV generation failed:', error);
        res.status(500).json({ 
            error: 'Failed to generate CV. Please try again.',
            message: error.message 
        });
    }
};

const { z } = require('zod');

const validate = (schema) => (req, res, next) => {
    try {
        schema.parse(req.body);
        next();
    } catch (error) {
        if (error instanceof z.ZodError) {
            return res.status(400).json({
                error: 'Validation Error',
                details: error.errors,
            });
        }
        next(error);
    }
};

module.exports = validate;

const jwt = require('jsonwebtoken');
const config = require('../../config');

const authenticate = (req, res, next) => {
    const authHeader = req.headers.authorization;
    if (!authHeader) {
        return res.status(401).json({ error: 'No token provided' });
    }

    const token = authHeader.split(' ')[1];
    try {
        const decoded = jwt.verify(token, config.jwtSecret);
        req.user = decoded;
        next();
    } catch (error) {
        return res.status(401).json({ error: 'Invalid token' });
    }
};

module.exports = authenticate;
